fn normalize_mode_name(value: &str) -> String {
    value.trim().replace('-', "_").to_ascii_lowercase()
}

fn edge_collector_autopilot_mode(loaded: &LoadedConfig, options: &AutopilotRunOptions) -> bool {
    options
        .mode
        .as_deref()
        .map(normalize_mode_name)
        .unwrap_or_else(|| normalize_mode_name(&loaded.config.autopilot.mode))
        == "edge_collector"
}

