fn csv_row_count(path: &Path) -> usize {
    fs::read_to_string(path)
        .ok()
        .map(|content| {
            content
                .lines()
                .skip(1)
                .filter(|line| !line.trim().is_empty())
                .count()
        })
        .unwrap_or(0)
}

fn export_chunk_rows(loaded: &LoadedConfig) -> usize {
    loaded
        .config
        .research_worker
        .exports
        .chunk_rows
        .max(loaded.config.exports.feature_export_chunk_rows)
        .max(1)
}

fn export_max_uncompressed_bytes(loaded: &LoadedConfig) -> u64 {
    let threshold_mb = if loaded.config.storage.low_disk_mode.enabled {
        loaded
            .config
            .storage
            .low_disk_mode
            .max_local_export_mb
            .max(1)
    } else {
        loaded.config.exports.max_uncompressed_export_mb.max(1)
    };
    threshold_mb.saturating_mul(1024 * 1024).max(1)
}

fn max_local_report_bytes(loaded: &LoadedConfig) -> u64 {
    if loaded.config.reports.low_disk.enabled {
        loaded
            .config
            .reports
            .low_disk
            .max_local_report_mb
            .max(1)
            .saturating_mul(1024 * 1024)
    } else {
        u64::MAX
    }
}

fn export_compression_name(loaded: &LoadedConfig, force_compress: bool) -> Option<String> {
    if force_compress || loaded.config.exports.compress_exports {
        let trimmed = loaded.config.exports.compression.trim();
        if trimmed.is_empty() || trimmed.eq_ignore_ascii_case("none") {
            None
        } else {
            Some(trimmed.to_ascii_lowercase())
        }
    } else {
        None
    }
}

fn load_or_create_export_chunk_manifest(
    loaded: &LoadedConfig,
    run_id: &str,
) -> Result<ExportChunkManifest> {
    let report_dir = run_report_dir_for(loaded, run_id)?;
    Ok(
        load_export_chunk_manifest_if_present(&report_dir).unwrap_or_else(|| ExportChunkManifest {
            run_id: run_id.to_owned(),
            ..ExportChunkManifest::default()
        }),
    )
}

fn persist_export_chunk_entries(
    loaded: &LoadedConfig,
    run_id: &str,
    export_name: &str,
    entries: Vec<ExportChunkManifestEntry>,
    export_status: &str,
) -> Result<ExportChunkManifest> {
    let report_dir = run_report_dir_for(loaded, run_id)?;
    let mut manifest = load_or_create_export_chunk_manifest(loaded, run_id)?;
    manifest.run_id = run_id.to_owned();
    manifest.chunked_exports = manifest.chunked_exports || !entries.is_empty();
    manifest.export_status = export_status.to_owned();
    manifest
        .chunks
        .retain(|chunk| chunk.export_name != export_name);
    manifest.chunks.extend(entries);
    write_export_chunk_manifest(&report_dir, &mut manifest)?;
    Ok(manifest)
}

fn split_existing_csv_into_chunks(
    loaded: &LoadedConfig,
    run_id: &str,
    export_name: &str,
    path: &Path,
    delete_original: bool,
) -> Result<Vec<ExportChunkManifestEntry>> {
    let file = File::open(path)?;
    let reader = BufReader::new(file);
    let mut lines = reader.lines();
    let Some(header) = lines.next() else {
        return Ok(Vec::new());
    };
    let header = header?;
    let report_dir = run_report_dir_for(loaded, run_id)?;
    let compression = export_compression_name(loaded, false);
    let compress = compression.is_some();
    let rows_per_chunk = export_chunk_rows(loaded);
    let mut sequence = 0usize;
    let mut chunk_rows = 0usize;
    let mut temp_path: Option<PathBuf> = None;
    let mut chunk_file: Option<File> = None;
    let mut chunks = Vec::new();
    let open_chunk = |report_dir: &Path,
                      export_name: &str,
                      sequence: usize,
                      header: &str|
     -> Result<(PathBuf, File)> {
        let path = report_dir.join(format!("{}_tmp_{:05}.csv", export_name, sequence));
        let mut file = File::create(&path)?;
        writeln!(file, "{header}")?;
        Ok((path, file))
    };
    let finish_chunk = |temp_path: PathBuf,
                        sequence: usize,
                        chunk_rows: usize,
                        report_dir: &Path,
                        export_name: &str,
                        compress: bool,
                        compression: Option<String>|
     -> Result<ExportChunkManifestEntry> {
        let raw_bytes = fs::read(&temp_path)?;
        let (final_bytes, compression_name) = if compress {
            (
                zstd::stream::encode_all(&raw_bytes[..], 3)?,
                compression.clone().or_else(|| Some("zstd".to_owned())),
            )
        } else {
            (raw_bytes, None)
        };
        let extension = if compression_name.is_some() {
            "csv.zst"
        } else {
            "csv"
        };
        let chunk_name = format!("{}_{:05}.{}", export_name, sequence, extension);
        let final_path = report_dir.join(&chunk_name);
        atomic_write_path(&final_path, &final_bytes)?;
        let _ = fs::remove_file(&temp_path);
        Ok(ExportChunkManifestEntry {
            export_name: export_name.to_owned(),
            chunk_name,
            local_path: final_path.display().to_string(),
            row_count: chunk_rows as u64,
            size_bytes: final_bytes.len() as u64,
            checksum_sha256: checksum_hex(&final_bytes),
            remote_key: String::new(),
            uploaded: false,
            verified: false,
            pruned_local: false,
            compression: compression_name,
        })
    };
    for line in lines {
        let line = line?;
        if line.trim().is_empty() {
            continue;
        }
        if chunk_file.is_none() {
            sequence = sequence.saturating_add(1);
            let (path, file) = open_chunk(&report_dir, export_name, sequence, &header)?;
            temp_path = Some(path);
            chunk_file = Some(file);
            chunk_rows = 0;
        }
        if let Some(file) = chunk_file.as_mut() {
            writeln!(file, "{line}")?;
        }
        chunk_rows = chunk_rows.saturating_add(1);
        if chunk_rows >= rows_per_chunk {
            if let Some(mut file) = chunk_file.take() {
                file.flush()?;
                file.sync_all()?;
            }
            if let Some(path) = temp_path.take() {
                chunks.push(finish_chunk(
                    path,
                    sequence,
                    chunk_rows,
                    &report_dir,
                    export_name,
                    compress,
                    compression.clone(),
                )?);
            }
            chunk_rows = 0;
        }
    }
    if let Some(mut file) = chunk_file.take() {
        file.flush()?;
        file.sync_all()?;
    }
    if let Some(path) = temp_path.take() {
        chunks.push(finish_chunk(
            path,
            sequence,
            chunk_rows,
            &report_dir,
            export_name,
            compress,
            compression.clone(),
        )?);
    }
    if delete_original {
        let _ = fs::remove_file(path);
    }
    Ok(chunks)
}

fn chunk_existing_export_if_needed(
    loaded: &LoadedConfig,
    run_id: &str,
    export_name: &str,
    path: &Path,
) -> Result<Option<ExportChunkManifest>> {
    if !path.exists() {
        return Ok(None);
    }
    let size = fs::metadata(path)?.len();
    if !loaded.config.exports.chunked_enabled {
        return Ok(None);
    }
    if size <= export_max_uncompressed_bytes(loaded)
        && !loaded.config.research_worker.exports.compressed_only
    {
        return Ok(None);
    }
    let chunks = split_existing_csv_into_chunks(loaded, run_id, export_name, path, true)?;
    let manifest =
        persist_export_chunk_entries(loaded, run_id, export_name, chunks, "chunked_local")?;
    Ok(Some(manifest))
}

fn build_r2_upload_audit(
    manifest: &ArtifactManifest,
    stream_only_proof: StreamOnlyRunSummary,
    errors: Vec<String>,
    upload_duration_ms: u64,
) -> R2UploadAuditReport {
    R2UploadAuditReport {
        run_id: manifest.run_id.clone(),
        local_manifest_path: String::new(),
        remote_manifest_key: manifest.remote_manifest_key.clone(),
        local_size_bytes: manifest
            .artifacts
            .iter()
            .map(|artifact| artifact.size_bytes)
            .sum(),
        planned_artifacts: manifest
            .artifacts
            .iter()
            .map(|artifact| artifact.relative_path.clone())
            .collect(),
        uploaded_artifacts: manifest
            .artifacts
            .iter()
            .filter(|artifact| artifact.uploaded)
            .map(|artifact| artifact.relative_path.clone())
            .collect(),
        verified_artifacts: manifest
            .artifacts
            .iter()
            .filter(|artifact| artifact.verified)
            .map(|artifact| artifact.relative_path.clone())
            .collect(),
        failed_artifacts: if manifest.upload_summary.dry_run {
            Vec::new()
        } else {
            manifest
                .artifacts
                .iter()
                .filter(|artifact| !artifact.uploaded && !artifact.verified)
                .map(|artifact| artifact.relative_path.clone())
                .collect()
        },
        upload_duration_ms,
        retry_count: 0,
        local_prune_eligible: manifest_verified(manifest),
        rpc_ledger_path: stream_only_proof.rpc_ledger_path.clone(),
        stream_only_proof,
        errors,
    }
}

async fn upload_manifest_candidates(
    loaded: &LoadedConfig,
    client: &R2Client,
    manifest: &mut ArtifactManifest,
    candidates: &[R2ManifestArtifactCandidate],
    manifest_path: &Path,
    remote_manifest_key: &str,
    compress_override: Option<bool>,
    verify_override: Option<bool>,
) -> Result<R2UploadSummaryReport> {
    let started = std::time::Instant::now();
    let mut errors = Vec::new();
    let mut uploaded_count = 0u64;
    let mut verified_count = 0u64;
    let mut failed_count = 0u64;
    let dry_run = client.config().dry_run || !client.config().upload_enabled;
    for candidate in candidates {
        let candidate_compress_override = if candidate
            .local_path
            .file_name()
            .and_then(|value| value.to_str())
            .map(|name| name.ends_with(".jsonl.zst") || name.starts_with("segment_"))
            .unwrap_or(false)
        {
            Some(false)
        } else {
            compress_override
        };
        let prepared = client.prepare_upload(
            &candidate.local_path,
            candidate.bucket.clone(),
            candidate.remote_key.clone(),
            candidate.content_type.clone(),
            BTreeMap::new(),
            candidate_compress_override,
        )?;
        match client.upload_prepared(&prepared, verify_override).await {
            Ok(result) => {
                if let Some(entry) = manifest
                    .artifacts
                    .iter_mut()
                    .find(|entry| entry.local_path == candidate.local_path.display().to_string())
                {
                    entry.uploaded = result.uploaded;
                    entry.verified = result.verified;
                    entry.upload_time = Some(OffsetDateTime::now_utc());
                    entry.size_bytes = result.size_bytes;
                    entry.checksum_sha256 = result.checksum_sha256.clone();
                }
                if result.uploaded {
                    uploaded_count = uploaded_count.saturating_add(1);
                }
                if result.verified {
                    verified_count = verified_count.saturating_add(1);
                }
            }
            Err(error) => {
                failed_count = failed_count.saturating_add(1);
                errors.push(format!("{} -> {}", candidate.local_path.display(), error));
            }
        }
    }
    manifest.upload_summary = ArtifactManifestUploadSummary {
        attempted_count: candidates.len() as u64,
        uploaded_count,
        verified_count,
        failed_count,
        dry_run,
    };
    write_manifest(manifest_path, manifest)?;
    let manifest_bucket = client.bucket_for_reports()?;
    let manifest_prepared = client.prepare_upload(
        manifest_path,
        manifest_bucket,
        remote_manifest_key.to_owned(),
        "application/json",
        BTreeMap::new(),
        Some(false),
    )?;
    if let Err(error) = client
        .upload_prepared(&manifest_prepared, verify_override)
        .await
    {
        failed_count = failed_count.saturating_add(1);
        errors.push(format!("artifact_manifest.json -> {error}"));
    }
    let upload_completed_at = OffsetDateTime::now_utc();
    manifest.uploaded = !dry_run && failed_count == 0 && uploaded_count == candidates.len() as u64;
    manifest.verified = !dry_run && failed_count == 0 && verified_count == candidates.len() as u64;
    manifest.uploaded_at = (!dry_run).then_some(upload_completed_at);
    let summary = R2UploadSummaryReport {
        run_id: manifest.run_id.clone(),
        local_manifest_path: manifest_path.display().to_string(),
        remote_manifest_key: remote_manifest_key.to_owned(),
        upload_attempted: !dry_run,
        uploaded_count,
        verified_count,
        failed_count,
        dry_run,
        pruned_local: false,
        errors,
    };
    let _elapsed = started.elapsed();
    write_manifest(manifest_path, manifest)?;
    write_r2_upload_summary_reports(loaded, &manifest.run_id, &summary)?;
    Ok(summary)
}

async fn upload_artifacts_r2_command(
    loaded: &LoadedConfig,
    run_id: Option<&str>,
    latest_run: bool,
    latest_source_run: bool,
    latest_live_paper_run: bool,
    latest_shred_exit_run: bool,
    latest_research_cycle_run: bool,
    dry_run: bool,
    include_raw_events: bool,
    include_reports: bool,
    include_exports: bool,
    include_calibration: bool,
    include_provider_compat: bool,
    include_rpc_ledger: bool,
    compress: bool,
    no_compress: bool,
    verify: bool,
    no_verify: bool,
    require_verified_before_success: bool,
    fail_on_any_upload_error: bool,
    write_upload_audit: bool,
    min_artifacts: Option<usize>,
    max_total_upload_mb: Option<u64>,
    skip_large_raw_events: bool,
) -> Result<()> {
    let started = std::time::Instant::now();
    let selected_run_id = r2_target_run_id_from_flags(
        loaded,
        run_id,
        latest_run,
        latest_source_run,
        latest_live_paper_run,
        latest_shred_exit_run,
        latest_research_cycle_run,
    )
    .await?;
    let include_all = include_all_r2_artifact_groups(
        include_reports,
        include_exports,
        include_calibration,
        include_provider_compat,
        include_rpc_ledger,
    );
    let include_reports = include_reports || include_all;
    let include_exports = include_exports || include_all;
    let include_calibration = include_calibration || include_all;
    let include_provider_compat = include_provider_compat || include_all;
    let include_rpc_ledger = include_rpc_ledger || include_all;
    let client = r2_client_for_command(loaded, dry_run, true, false)?;
    let compress_override = if no_compress {
        Some(false)
    } else if compress {
        Some(true)
    } else {
        None
    };
    let verify_override = if no_verify {
        Some(false)
    } else if verify {
        Some(true)
    } else {
        None
    };
    let (mut manifest, candidates, manifest_path, remote_manifest_key) = build_artifact_manifest(
        loaded,
        &selected_run_id,
        &client,
        include_raw_events,
        include_reports,
        include_exports,
        include_calibration,
        include_provider_compat,
        include_rpc_ledger,
        compress_override,
    )?;
    let candidates = if skip_large_raw_events {
        let threshold_bytes = loaded.config.r2.multipart_threshold_mb * 1024 * 1024;
        candidates
            .into_iter()
            .filter(|candidate| {
                if candidate.artifact_type != "dataset" {
                    return true;
                }
                fs::metadata(&candidate.local_path)
                    .map(|metadata| metadata.len() <= threshold_bytes)
                    .unwrap_or(true)
            })
            .collect::<Vec<_>>()
    } else {
        candidates
    };
    let retained_paths = candidates
        .iter()
        .map(|candidate| candidate.local_path.display().to_string())
        .collect::<BTreeSet<_>>();
    manifest
        .artifacts
        .retain(|artifact| retained_paths.contains(&artifact.local_path));
    if let Some(min_artifacts) = min_artifacts {
        if manifest.artifacts.len() < min_artifacts {
            return Err(anyhow!(
                "planned artifact count {} is below required minimum {}",
                manifest.artifacts.len(),
                min_artifacts
            ));
        }
    }
    if let Some(max_total_upload_mb) = max_total_upload_mb {
        let total_bytes = manifest
            .artifacts
            .iter()
            .map(|artifact| artifact.size_bytes)
            .sum::<u64>();
        if total_bytes > max_total_upload_mb.saturating_mul(1024 * 1024) {
            return Err(anyhow!(
                "planned upload size {} bytes exceeds configured limit {} MB",
                total_bytes,
                max_total_upload_mb
            ));
        }
    }
    write_manifest(&manifest_path, &manifest)?;
    let summary = upload_manifest_candidates(
        loaded,
        &client,
        &mut manifest,
        &candidates,
        &manifest_path,
        &remote_manifest_key,
        compress_override,
        verify_override,
    )
    .await?;
    let manifest = load_manifest(&manifest_path)?;
    if fail_on_any_upload_error && summary.failed_count > 0 {
        return Err(anyhow!(
            "R2 upload failed for {} artifact(s)",
            summary.failed_count
        ));
    }
    if require_verified_before_success && !manifest_verified(&manifest) {
        return Err(anyhow!(
            "R2 upload did not reach fully verified state for {selected_run_id}"
        ));
    }
    if write_upload_audit {
        let mut audit = build_r2_upload_audit(
            &manifest,
            stream_only_run_summary(loaded, &selected_run_id, None)?,
            summary.errors.clone(),
            started.elapsed().as_millis() as u64,
        );
        audit.local_manifest_path = manifest_path.display().to_string();
        write_r2_upload_audit_reports(loaded, &selected_run_id, &audit)?;
    }
    if manifest_verified(&manifest) {
        let _ = apply_remote_first_verified_retention(loaded, &selected_run_id)?;
        let _ = refresh_dataset_index(loaded)?;
    } else {
        let _ = write_local_footprint_budget_report(loaded, &selected_run_id)?;
    }
    println!(
        "{}",
        serde_json::to_string_pretty(&json!({
            "command": "upload-artifacts-r2",
            "run_id": selected_run_id,
            "summary": summary,
            "artifact_count": manifest.artifacts.len(),
        }))?
    );
    Ok(())
}

async fn upload_pending_r2_command(loaded: &LoadedConfig, dry_run: bool) -> Result<()> {
    let manifests = all_r2_manifest_paths(loaded)?;
    let pending = manifests
        .into_iter()
        .filter_map(|path| {
            load_manifest(&path)
                .ok()
                .map(|manifest| (path, manifest))
                .filter(|(_, manifest)| {
                    manifest.upload_summary.attempted_count == 0
                        || manifest.upload_summary.failed_count > 0
                })
        })
        .collect::<Vec<_>>();
    let mut results = Vec::new();
    for (_, manifest) in pending {
        upload_artifacts_r2_command(
            loaded,
            Some(manifest.run_id.as_str()),
            false,
            false,
            false,
            false,
            false,
            dry_run,
            true,
            true,
            true,
            true,
            true,
            true,
            false,
            false,
            false,
            false,
            false,
            false,
            true,
            None,
            None,
            false,
        )
        .await?;
        results.push(manifest.run_id);
    }
    println!(
        "{}",
        serde_json::to_string_pretty(&json!({
            "command": "upload-pending-r2",
            "dry_run": dry_run,
            "processed_runs": results,
        }))?
    );
    Ok(())
}

async fn verify_r2_upload_command(
    loaded: &LoadedConfig,
    run_id: Option<&str>,
    latest_run: bool,
    dry_run: bool,
    check_manifest_consistency: bool,
    repair_manifest_drift: bool,
) -> Result<()> {
    let selected_run_id =
        resolve_existing_manifest_run_id(loaded, run_id, latest_run, false, false, false, false)
            .await?;
    if dry_run {
        let manifest_path = r2_manifest_path_for_run(loaded, &selected_run_id)?;
        let manifest = load_manifest(&manifest_path)?;
        println!(
            "{}",
            serde_json::to_string_pretty(&json!({
                "command": "verify-r2-upload",
                "run_id": selected_run_id,
                "dry_run": true,
                "artifact_count": manifest.artifacts.len(),
                "planned_verification_count": manifest.artifacts.len(),
            }))?
        );
        return Ok(());
    }
    let repair_report = if check_manifest_consistency && repair_manifest_drift {
        Some(ensure_manifest_consistency_for_run(loaded, &selected_run_id, true, true).await?)
    } else {
        None
    };
    let (manifest, verified_count, failures) =
        verify_r2_manifest_for_run(loaded, &selected_run_id, false, check_manifest_consistency)
            .await?;
    let consistency = if check_manifest_consistency {
        Some(manifest_consistency_report_for_run(loaded, &selected_run_id).await?)
    } else {
        None
    };
    println!(
        "{}",
        serde_json::to_string_pretty(&json!({
            "command": "verify-r2-upload",
            "run_id": selected_run_id,
            "verified_count": verified_count,
            "artifact_count": manifest.artifacts.len(),
            "failures": failures,
            "manifest_consistency": consistency,
            "repair_report": repair_report,
        }))?
    );
    Ok(())
}

async fn repair_manifest_consistency_command(
    loaded: &LoadedConfig,
    run_id: &str,
    upload_r2: bool,
    verify_r2: bool,
) -> Result<()> {
    let report = ensure_manifest_consistency_for_run(loaded, run_id, upload_r2, verify_r2).await?;
    let mut state = load_or_default_autopilot_state(loaded);
    state.last_manifest_consistency_passed = Some(!report.drift_detected);
    state.last_manifest_drift_detected = Some(report.drift_detected);
    state.last_manifest_drift_repaired = report.repaired;
    save_autopilot_state(loaded, &state)?;
    if report.repaired || report.drift_detected {
        let _ = append_autopilot_alert(
            loaded,
            if report.repaired {
                AutopilotAlertType::ManifestDriftRepaired
            } else {
                AutopilotAlertType::ManifestConsistencyDrift
            },
            if report.repaired {
                format!("manifest consistency repaired for {run_id}")
            } else {
                format!("manifest consistency drift detected for {run_id}")
            },
            None,
            Some(run_id),
            BTreeMap::from([(
                "drift_artifacts".to_owned(),
                report.drift_artifacts.join(","),
            )]),
        )?;
    }
    let verification = if verify_r2 {
        let (manifest, verified_count, failures) =
            verify_r2_manifest_for_run(loaded, run_id, false, true).await?;
        Some(json!({
            "verified_count": verified_count,
            "artifact_count": manifest.artifacts.len(),
            "failures": failures,
        }))
    } else {
        None
    };
    println!(
        "{}",
        serde_json::to_string_pretty(&json!({
            "command": "repair-manifest-consistency",
            "report": report,
            "verification": verification,
        }))?
    );
    Ok(())
}

async fn list_r2_artifacts_command(loaded: &LoadedConfig, run_id: &str) -> Result<()> {
    let manifest_path = r2_manifest_path_for_run(loaded, run_id)?;
    let manifest = load_manifest(&manifest_path)?;
    println!(
        "{}",
        serde_json::to_string_pretty(&json!({
            "command": "list-r2-artifacts",
            "run_id": run_id,
            "artifacts": manifest.artifacts,
        }))?
    );
    Ok(())
}

fn artifact_delete_allowed(
    loaded: &LoadedConfig,
    artifact: &ArtifactManifestEntry,
    delete_exports: bool,
    delete_reports: bool,
    delete_raw_events: bool,
) -> bool {
    let path = Path::new(&artifact.local_path);
    let file_name = path
        .file_name()
        .and_then(|value| value.to_str())
        .unwrap_or_default();
    if file_name.starts_with("dataset_") {
        return delete_raw_events
            || loaded
                .config
                .r2
                .retention
                .delete_local_raw_events_after_upload;
    }
    if path.extension().and_then(|value| value.to_str()) == Some("csv") {
        return delete_exports || loaded.config.r2.retention.delete_local_exports_after_upload;
    }
    delete_reports || loaded.config.r2.retention.delete_local_reports_after_upload
}

fn artifact_preserved_by_policy(
    artifact: &ArtifactManifestEntry,
    keep_rpc_ledger: bool,
    keep_calibration: bool,
) -> bool {
    let file_name = Path::new(&artifact.local_path)
        .file_name()
        .and_then(|value| value.to_str())
        .unwrap_or_default();
    file_name.starts_with("r2_upload_summary.")
        || (keep_rpc_ledger && matches!(file_name, "rpc_ledger.json" | "rpc_ledger.csv"))
        || (keep_calibration && artifact.artifact_type == "calibration")
}

fn verified_prune_report_json_path(loaded: &LoadedConfig) -> PathBuf {
    autopilot_report_root(loaded).join("verified_prune_report.json")
}

fn verified_prune_report_markdown_path(loaded: &LoadedConfig) -> PathBuf {
    autopilot_report_root(loaded).join("verified_prune_report.md")
}

fn render_verified_prune_markdown(summary: &VerifiedPruneSummary) -> String {
    format!(
        "# Verified Prune Report\n\n- dry_run: {}\n- deleted_bytes: {}\n- candidate_run_count: {}\n- skipped_run_count: {}\n- verified_run_count: {}\n- unverified_run_count: {}\n- active_run_id: {}\n- keep_last_n: {}\n- min_age_hours: {:?}\n- max_delete_mb: {:?}\n- force_prune_verified: {}\n- deleted_paths: {:?}\n- skipped_runs: {:?}\n- candidates: {:?}\n",
        summary.dry_run,
        summary.deleted_bytes,
        summary.candidate_run_count,
        summary.skipped_run_count,
        summary.verified_run_count,
        summary.unverified_run_count,
        summary.active_run_id.clone().unwrap_or_default(),
        summary.keep_last_n,
        summary.min_age_hours,
        summary.max_delete_mb,
        summary.force_prune_verified,
        summary.deleted_paths,
        summary.skipped_runs,
        summary
            .candidates
            .iter()
            .map(|candidate| (&candidate.run_id, candidate.deletable_bytes))
            .collect::<Vec<_>>(),
    )
}

fn write_verified_prune_reports(
    loaded: &LoadedConfig,
    summary: &VerifiedPruneSummary,
) -> Result<(PathBuf, PathBuf)> {
    let root = autopilot_report_root(loaded);
    fs::create_dir_all(&root)?;
    let json_path = verified_prune_report_json_path(loaded);
    let markdown_path = verified_prune_report_markdown_path(loaded);
    fs::write(&json_path, serde_json::to_vec_pretty(summary)?)?;
    write_report(&markdown_path, &render_verified_prune_markdown(summary))?;
    Ok((markdown_path, json_path))
}

fn read_json_file<T: DeserializeOwned>(path: &Path) -> Option<T> {
    fs::read(path)
        .ok()
        .and_then(|bytes| serde_json::from_slice::<T>(&bytes).ok())
}

fn atomic_write_path(path: &Path, bytes: &[u8]) -> Result<()> {
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent)?;
    }
    let temp_name = format!(
        ".{}.{}.tmp",
        path.file_name()
            .and_then(|value| value.to_str())
            .unwrap_or("artifact"),
        OffsetDateTime::now_utc().unix_timestamp_nanos()
    );
    let temp_path = path.with_file_name(temp_name);
    fs::write(&temp_path, bytes)?;
    fs::rename(&temp_path, path)?;
    Ok(())
}

fn export_chunk_manifest_path(report_dir: &Path) -> PathBuf {
    report_dir.join("export_chunks_manifest.json")
}

fn load_export_chunk_manifest_if_present(report_dir: &Path) -> Option<ExportChunkManifest> {
    read_json_file(&export_chunk_manifest_path(report_dir))
}

fn write_export_chunk_manifest(
    report_dir: &Path,
    manifest: &mut ExportChunkManifest,
) -> Result<()> {
    manifest.updated_at = OffsetDateTime::now_utc();
    atomic_write_path(
        &export_chunk_manifest_path(report_dir),
        &serde_json::to_vec_pretty(manifest)?,
    )
}

fn sync_export_chunk_manifest_with_artifact_manifest(
    report_dir: &Path,
    artifact_manifest: &ArtifactManifest,
) -> Result<Option<ExportChunkManifest>> {
    let Some(mut manifest) = load_export_chunk_manifest_if_present(report_dir) else {
        return Ok(None);
    };
    for chunk in &mut manifest.chunks {
        if let Some(artifact) = artifact_manifest
            .artifacts
            .iter()
            .find(|artifact| artifact.local_path == chunk.local_path)
        {
            chunk.remote_key = artifact.remote_key.clone();
            chunk.uploaded = artifact.uploaded;
            chunk.verified = artifact.verified;
            if artifact.verified && !Path::new(&chunk.local_path).exists() {
                chunk.pruned_local = true;
            }
        }
    }
    if manifest
        .chunks
        .iter()
        .all(|chunk| chunk.verified || chunk.pruned_local)
    {
        manifest.export_status = "chunked_remote_verified".to_owned();
    } else if manifest.chunks.iter().any(|chunk| chunk.uploaded) {
        manifest.export_status = "partial_remote".to_owned();
    }
    write_export_chunk_manifest(report_dir, &mut manifest)?;
    Ok(Some(manifest))
}

fn local_footprint_budget_path(report_dir: &Path) -> PathBuf {
    report_dir.join("local_footprint_budget.json")
}

fn write_local_footprint_budget_report(
    loaded: &LoadedConfig,
    run_id: &str,
) -> Result<LocalFootprintBudgetReport> {
    let report_dir = run_report_dir_for(loaded, run_id)?;
    fs::create_dir_all(&report_dir)?;
    let segment_manifest = load_run_segment_manifest_if_present(loaded, run_id)?;
    let export_manifest = load_export_chunk_manifest_if_present(&report_dir);
    let files = collect_run_report_files(&report_dir)?;
    let mut active_open_segment_bytes = 0u64;
    let mut export_bytes = 0u64;
    let mut report_bytes = 0u64;
    let mut restore_cache_bytes = 0u64;
    let mut temp_bytes = 0u64;
    let mut manifests_summaries_bytes = 0u64;
    for path in files {
        let size = fs::metadata(&path)
            .map(|metadata| metadata.len())
            .unwrap_or(0);
        let name = path
            .file_name()
            .and_then(|value| value.to_str())
            .unwrap_or_default();
        let relative = path
            .strip_prefix(&report_dir)
            .ok()
            .and_then(|value| value.to_str())
            .unwrap_or_default()
            .to_owned();
        if name.ends_with(".open") {
            active_open_segment_bytes = active_open_segment_bytes.saturating_add(size);
            continue;
        }
        if relative.contains("tmp_restore") {
            restore_cache_bytes = restore_cache_bytes.saturating_add(size);
            continue;
        }
        if name.ends_with(".tmp") || name.starts_with('.') {
            temp_bytes = temp_bytes.saturating_add(size);
            continue;
        }
        if name.starts_with("segment_") {
            continue;
        }
        if is_export_artifact_name(name) {
            export_bytes = export_bytes.saturating_add(size);
            continue;
        }
        if is_small_summary_artifact_name(name) {
            manifests_summaries_bytes = manifests_summaries_bytes.saturating_add(size);
            continue;
        }
        report_bytes = report_bytes.saturating_add(size);
    }
    let closed_unverified_segment_bytes = segment_manifest
        .as_ref()
        .map(|manifest| {
            manifest
                .segments
                .iter()
                .filter(|segment| !segment.verified && !segment.pruned_local)
                .map(|segment| segment.size_bytes)
                .sum::<u64>()
        })
        .unwrap_or_default();
    let closed_verified_local_segment_bytes = segment_manifest
        .as_ref()
        .map(|manifest| {
            manifest
                .segments
                .iter()
                .filter(|segment| segment.verified && !segment.pruned_local)
                .map(|segment| segment.size_bytes)
                .sum::<u64>()
        })
        .unwrap_or_default();
    let total_local_runtime_bytes = active_open_segment_bytes
        .saturating_add(closed_unverified_segment_bytes)
        .saturating_add(closed_verified_local_segment_bytes)
        .saturating_add(export_bytes)
        .saturating_add(report_bytes)
        .saturating_add(restore_cache_bytes)
        .saturating_add(temp_bytes)
        .saturating_add(manifests_summaries_bytes);
    let local_runtime_budget_bytes = if loaded.config.storage.low_disk_mode.enabled {
        loaded
            .config
            .storage
            .low_disk_mode
            .target_local_runtime_mb
            .saturating_mul(1024 * 1024)
    } else {
        0
    };
    let overage = if loaded.config.storage.low_disk_mode.enabled
        && total_local_runtime_bytes > local_runtime_budget_bytes
    {
        total_local_runtime_bytes.saturating_sub(local_runtime_budget_bytes)
    } else {
        0
    };
    let summary = LocalFootprintBudgetReport {
        run_id: run_id.to_owned(),
        updated_at: Some(OffsetDateTime::now_utc()),
        low_disk_mode_enabled: loaded.config.storage.low_disk_mode.enabled,
        active_open_segment_bytes,
        closed_unverified_segment_bytes,
        closed_verified_local_segment_bytes,
        export_bytes,
        report_bytes,
        restore_cache_bytes,
        temp_bytes,
        manifests_summaries_bytes,
        total_local_runtime_bytes,
        local_runtime_budget_bytes,
        local_runtime_budget_overage_bytes: overage,
        free_mb: filesystem_usage_summary(Path::new(&loaded.config.storage.root))?.free_bytes
            / (1024 * 1024),
        verified_segment_bytes_pruned_total: segment_manifest
            .as_ref()
            .map(|manifest| {
                manifest
                    .summary
                    .remote_bytes_verified
                    .saturating_sub(closed_verified_local_segment_bytes)
            })
            .unwrap_or_default(),
        verified_export_bytes_pruned_total: export_manifest
            .as_ref()
            .map(|manifest| {
                manifest
                    .chunks
                    .iter()
                    .filter(|chunk| chunk.verified && chunk.pruned_local)
                    .map(|chunk| chunk.size_bytes)
                    .sum()
            })
            .unwrap_or_default(),
        optional_exports_skipped_total: export_manifest
            .as_ref()
            .map(|manifest| manifest.skipped_exports.len() as u64)
            .unwrap_or_default(),
    };
    atomic_write_path(
        &local_footprint_budget_path(&report_dir),
        &serde_json::to_vec_pretty(&summary)?,
    )?;
    write_report(
        report_dir.join("local_footprint_budget.md"),
        &format!(
            "# Local Footprint Budget\n\n- run_id: {}\n- low_disk_mode_enabled: {}\n- active_open_segment_bytes: {}\n- closed_unverified_segment_bytes: {}\n- closed_verified_local_segment_bytes: {}\n- export_bytes: {}\n- report_bytes: {}\n- restore_cache_bytes: {}\n- temp_bytes: {}\n- manifests_summaries_bytes: {}\n- total_local_runtime_bytes: {}\n- local_runtime_budget_bytes: {}\n- local_runtime_budget_overage_bytes: {}\n- free_mb: {}\n- verified_segment_bytes_pruned_total: {}\n- verified_export_bytes_pruned_total: {}\n- optional_exports_skipped_total: {}\n",
            summary.run_id,
            summary.low_disk_mode_enabled,
            summary.active_open_segment_bytes,
            summary.closed_unverified_segment_bytes,
            summary.closed_verified_local_segment_bytes,
            summary.export_bytes,
            summary.report_bytes,
            summary.restore_cache_bytes,
            summary.temp_bytes,
            summary.manifests_summaries_bytes,
            summary.total_local_runtime_bytes,
            summary.local_runtime_budget_bytes,
            summary.local_runtime_budget_overage_bytes,
            summary.free_mb,
            summary.verified_segment_bytes_pruned_total,
            summary.verified_export_bytes_pruned_total,
            summary.optional_exports_skipped_total,
        ),
    )?;
    Ok(summary)
}

#[derive(Debug, Clone, Serialize, Deserialize, Default)]
struct RemoteFirstRetentionSummary {
    run_id: String,
    pruned_export_bytes: u64,
    lite_report_bytes_reduced: u64,
    removed_monolithic_export_bytes: u64,
}

#[derive(Debug, Clone, Serialize, Deserialize, Default)]
struct PostCycleCleanupSummary {
    run_id: String,
    enabled: bool,
    before_free_mb: u64,
    after_free_mb: u64,
    reclaimed_bytes: u64,
    retention_pruned_export_bytes: u64,
    retention_lite_report_bytes_reduced: u64,
    retention_removed_monolithic_export_bytes: u64,
    target_free_mb_after_cycle: u64,
    pre_cycle_min_free_mb: u64,
    reached_target_free_mb: bool,
    reached_pre_cycle_min_free_mb: bool,
}

fn apply_remote_first_verified_retention(
    loaded: &LoadedConfig,
    run_id: &str,
) -> Result<RemoteFirstRetentionSummary> {
    let report_dir = run_report_dir_for(loaded, run_id)?;
    let Some(artifact_manifest) = load_manifest_if_present(loaded, run_id)? else {
        let _ = write_local_footprint_budget_report(loaded, run_id)?;
        return Ok(RemoteFirstRetentionSummary {
            run_id: run_id.to_owned(),
            ..RemoteFirstRetentionSummary::default()
        });
    };
    if !manifest_verified(&artifact_manifest) {
        let _ = write_local_footprint_budget_report(loaded, run_id)?;
        return Ok(RemoteFirstRetentionSummary {
            run_id: run_id.to_owned(),
            ..RemoteFirstRetentionSummary::default()
        });
    }
    let mut summary = RemoteFirstRetentionSummary {
        run_id: run_id.to_owned(),
        ..RemoteFirstRetentionSummary::default()
    };
    if let Some(mut chunk_manifest) =
        sync_export_chunk_manifest_with_artifact_manifest(&report_dir, &artifact_manifest)?
    {
        if loaded
            .config
            .storage
            .low_disk_mode
            .delete_verified_exports_immediately
            || loaded.config.exports.delete_local_verified_export_chunks
        {
            for chunk in &mut chunk_manifest.chunks {
                if !chunk.verified || chunk.pruned_local {
                    continue;
                }
                let path = PathBuf::from(&chunk.local_path);
                if path.exists() {
                    let size = fs::metadata(&path)
                        .map(|metadata| metadata.len())
                        .unwrap_or(chunk.size_bytes);
                    fs::remove_file(&path)?;
                    summary.pruned_export_bytes = summary.pruned_export_bytes.saturating_add(size);
                }
                chunk.pruned_local = true;
            }
            if !chunk_manifest.chunks.is_empty()
                && chunk_manifest.chunks.iter().all(|chunk| chunk.verified)
            {
                chunk_manifest.export_status = "chunked_remote_verified".to_owned();
            }
            write_export_chunk_manifest(&report_dir, &mut chunk_manifest)?;
        }
    }
    if loaded
        .config
        .autopilot
        .post_cycle_cleanup
        .prune_verified_exports
        || loaded
            .config
            .storage
            .low_disk_mode
            .delete_verified_exports_immediately
    {
        for artifact in &artifact_manifest.artifacts {
            let path = PathBuf::from(&artifact.local_path);
            let name = path
                .file_name()
                .and_then(|value| value.to_str())
                .unwrap_or_default();
            if !artifact.verified || !path.exists() || !is_export_artifact_name(name) {
                continue;
            }
            let size = fs::metadata(&path)
                .map(|metadata| metadata.len())
                .unwrap_or(0);
            fs::remove_file(&path)?;
            summary.pruned_export_bytes = summary.pruned_export_bytes.saturating_add(size);
        }
    }
    if loaded
        .config
        .storage
        .low_disk_mode
        .forbid_monolithic_large_exports
    {
        for export_name in [
            "features.csv",
            "decisions.csv",
            "fills.csv",
            "rejection_reasons.csv",
            "data_gaps.csv",
            "run_summary.csv",
        ] {
            let path = report_dir.join(export_name);
            if !path.exists() {
                continue;
            }
            let size = fs::metadata(&path)
                .map(|metadata| metadata.len())
                .unwrap_or(0);
            if size <= export_max_uncompressed_bytes(loaded) {
                continue;
            }
            let verified_remote = artifact_manifest.artifacts.iter().any(|artifact| {
                artifact.local_path == path.display().to_string() && artifact.verified
            });
            if verified_remote {
                fs::remove_file(&path)?;
                summary.removed_monolithic_export_bytes =
                    summary.removed_monolithic_export_bytes.saturating_add(size);
            }
        }
    }
    if loaded.config.reports.low_disk.enabled
        && loaded
            .config
            .storage
            .low_disk_mode
            .lite_reports_after_upload
        && loaded.config.reports.low_disk.remote_full_reports
    {
        for artifact in &artifact_manifest.artifacts {
            let path = PathBuf::from(&artifact.local_path);
            if !artifact.verified || !path.exists() {
                continue;
            }
            let name = path
                .file_name()
                .and_then(|value| value.to_str())
                .unwrap_or_default();
            if is_small_summary_artifact_name(name) {
                continue;
            }
            if !matches!(
                path.extension().and_then(|value| value.to_str()),
                Some("md") | Some("json")
            ) {
                continue;
            }
            let size = fs::metadata(&path)
                .map(|metadata| metadata.len())
                .unwrap_or(0);
            if size <= max_local_report_bytes(loaded) {
                continue;
            }
            let reduced = match path.extension().and_then(|value| value.to_str()) {
                Some("md") => {
                    let body = format!(
                        "# Remote-First Lite Report\n\n- run_id: {}\n- original_local_path: {}\n- remote_key: {}\n- note: full report uploaded and verified to R2; local copy reduced in low-disk mode.\n",
                        run_id, artifact.local_path, artifact.remote_key,
                    );
                    write_report(&path, &body)?;
                    body.len() as u64
                }
                Some("json") => {
                    let lite = json!({
                        "run_id": run_id,
                        "remote_key": artifact.remote_key,
                        "status": "remote_first_lite_report",
                        "note": "full report uploaded and verified to R2; local copy reduced in low-disk mode"
                    });
                    let bytes = serde_json::to_vec_pretty(&lite)?;
                    fs::write(&path, &bytes)?;
                    bytes.len() as u64
                }
                _ => continue,
            };
            summary.lite_report_bytes_reduced = summary
                .lite_report_bytes_reduced
                .saturating_add(size.saturating_sub(reduced));
        }
    }
    let _ = write_local_footprint_budget_report(loaded, run_id)?;
    Ok(summary)
}

fn run_post_cycle_cleanup(loaded: &LoadedConfig, run_id: &str) -> Result<PostCycleCleanupSummary> {
    let config = &loaded.config.autopilot.post_cycle_cleanup;
    let before = collect_disk_preflight_summary(loaded)?;
    let mut summary = PostCycleCleanupSummary {
        run_id: run_id.to_owned(),
        enabled: config.enabled,
        before_free_mb: before.free_mb,
        after_free_mb: before.free_mb,
        target_free_mb_after_cycle: config.target_free_mb_after_cycle,
        pre_cycle_min_free_mb: loaded.config.autopilot.disk.pre_cycle_min_free_mb,
        ..PostCycleCleanupSummary::default()
    };
    if !config.enabled {
        return Ok(summary);
    }
    if config.run_clean_build_artifacts {
        let _ = clean_build_artifacts_command(loaded, false, true);
    }
    let retention = apply_remote_first_verified_retention(loaded, run_id)?;
    let after = collect_disk_preflight_summary(loaded)?;
    summary.after_free_mb = after.free_mb;
    summary.retention_pruned_export_bytes = retention.pruned_export_bytes;
    summary.retention_lite_report_bytes_reduced = retention.lite_report_bytes_reduced;
    summary.retention_removed_monolithic_export_bytes = retention.removed_monolithic_export_bytes;
    summary.reclaimed_bytes = after
        .root_filesystem
        .free_bytes
        .saturating_sub(before.root_filesystem.free_bytes);
    summary.reached_target_free_mb = after.free_mb >= config.target_free_mb_after_cycle;
    summary.reached_pre_cycle_min_free_mb =
        after.free_mb >= loaded.config.autopilot.disk.pre_cycle_min_free_mb;
    Ok(summary)
}

fn chunk_manifest_summary(
    manifest: Option<&ExportChunkManifest>,
) -> (bool, usize, usize, usize, u64, u64, String) {
    let Some(manifest) = manifest else {
        return (false, 0, 0, 0, 0, 0, "not_generated".to_owned());
    };
    let feature_chunks = manifest
        .chunks
        .iter()
        .filter(|chunk| chunk.export_name == "features")
        .count();
    let decision_chunks = manifest
        .chunks
        .iter()
        .filter(|chunk| chunk.export_name == "decisions")
        .count();
    let total_chunks = manifest.chunks.len();
    let local_remaining = manifest
        .chunks
        .iter()
        .filter(|chunk| !chunk.pruned_local)
        .map(|chunk| chunk.size_bytes)
        .sum();
    let remote_verified = manifest
        .chunks
        .iter()
        .filter(|chunk| chunk.verified)
        .map(|chunk| chunk.size_bytes)
        .sum();
    (
        manifest.chunked_exports,
        feature_chunks,
        decision_chunks,
        total_chunks,
        local_remaining,
        remote_verified,
        manifest.export_status.clone(),
    )
}

fn collect_run_report_files(report_dir: &Path) -> Result<Vec<PathBuf>> {
    let mut files = Vec::new();
    if !report_dir.exists() {
        return Ok(files);
    }
    let mut stack = vec![report_dir.to_path_buf()];
    while let Some(path) = stack.pop() {
        for entry in fs::read_dir(path)? {
            let entry = entry?;
            let entry_path = entry.path();
            if entry_path.is_dir() {
                stack.push(entry_path);
            } else if entry_path.is_file() {
                files.push(entry_path);
            }
        }
    }
    files.sort();
    Ok(files)
}

fn is_export_artifact_name(name: &str) -> bool {
    name.ends_with(".csv")
        || name.ends_with(".csv.zst")
        || name.starts_with("features_")
        || name.starts_with("decisions_")
        || name.starts_with("fills_")
        || name.starts_with("data_gaps_")
        || name.starts_with("rejection_reasons_")
        || name.starts_with("run_summary_")
}

fn is_small_summary_artifact_name(name: &str) -> bool {
    matches!(
        name,
        "artifact_manifest.json"
            | "segment_manifest.json"
            | "export_chunks_manifest.json"
            | "segment_status.json"
            | "segment_status.md"
            | "disk_actions.json"
            | "disk_actions.md"
            | "local_footprint_budget.json"
            | "local_footprint_budget.md"
            | "r2_upload_summary.json"
            | "r2_upload_summary.md"
            | "r2_upload_audit.json"
            | "r2_upload_audit.md"
            | "rpc_ledger.csv"
            | "rpc_ledger.json"
            | "stream_only_audit.md"
            | "stream_only_audit.json"
            | "live_collection_quality.md"
            | "live_collection_quality.json"
            | "backtest_readiness.md"
            | "backtest_readiness.json"
            | "metadata_backfill.md"
            | "metadata_backfill.json"
            | "finalize_run_recovery.md"
            | "finalize_run_recovery.json"
            | "run_summary.md"
            | "run_summary.json"
    )
}

fn chunked_export_paths_for(report_dir: &Path, export_name: &str) -> Vec<PathBuf> {
    let Some(manifest) = load_export_chunk_manifest_if_present(report_dir) else {
        return Vec::new();
    };
    let mut paths = manifest
        .chunks
        .into_iter()
        .filter(|chunk| chunk.export_name == export_name)
        .map(|chunk| PathBuf::from(chunk.local_path))
        .collect::<Vec<_>>();
    paths.sort();
    paths
}

fn preferred_export_schema_path(
    report_dir: &Path,
    export_name: &str,
    fallback: PathBuf,
) -> PathBuf {
    chunked_export_paths_for(report_dir, export_name)
        .into_iter()
        .next()
        .unwrap_or(fallback)
}

fn read_text_artifact(path: &Path) -> Result<String> {
    let bytes = fs::read(path)?;
    if path
        .file_name()
        .and_then(|value| value.to_str())
        .unwrap_or_default()
        .ends_with(".zst")
    {
        let decoded = zstd::stream::decode_all(&bytes[..])?;
        Ok(String::from_utf8(decoded)?)
    } else {
        Ok(String::from_utf8(bytes)?)
    }
}

fn register_skipped_export(
    loaded: &LoadedConfig,
    run_id: &str,
    export_name: &str,
    status: &str,
) -> Result<()> {
    let report_dir = run_report_dir_for(loaded, run_id)?;
    let mut manifest =
        load_export_chunk_manifest_if_present(&report_dir).unwrap_or_else(|| ExportChunkManifest {
            run_id: run_id.to_owned(),
            ..ExportChunkManifest::default()
        });
    manifest.run_id = run_id.to_owned();
    manifest.chunked_exports |= false;
    manifest.export_status = status.to_owned();
    if !manifest
        .skipped_exports
        .iter()
        .any(|value| value == export_name)
    {
        manifest.skipped_exports.push(export_name.to_owned());
    }
    write_export_chunk_manifest(&report_dir, &mut manifest)
}

fn checksum_hex(bytes: &[u8]) -> String {
    format!("{:x}", Sha256::digest(bytes))
}

fn csv_escape_cell(value: &str) -> String {
    let escaped = value.replace('"', "\"\"");
    if escaped.contains(',') || escaped.contains('\n') || escaped.contains('"') {
        format!("\"{escaped}\"")
    } else {
        escaped
    }
}

fn csv_line(row: &[String]) -> String {
    let mut line = row
        .iter()
        .map(|value| csv_escape_cell(value))
        .collect::<Vec<_>>()
        .join(",");
    line.push('\n');
    line
}

struct CsvChunkWriter {
    report_dir: PathBuf,
    export_name: String,
    header: String,
    rows_per_chunk: usize,
    compress: bool,
    compression: Option<String>,
    current_rows: usize,
    sequence: usize,
    temp_path: Option<PathBuf>,
    file: Option<BufWriter<File>>,
    chunks: Vec<ExportChunkManifestEntry>,
}

impl CsvChunkWriter {
    fn new(
        report_dir: PathBuf,
        export_name: &str,
        header: Vec<String>,
        rows_per_chunk: usize,
        compress: bool,
        compression: Option<String>,
    ) -> Result<Self> {
        fs::create_dir_all(&report_dir)?;
        Ok(Self {
            report_dir,
            export_name: export_name.to_owned(),
            header: csv_line(&header),
            rows_per_chunk: rows_per_chunk.max(1),
            compress,
            compression,
            current_rows: 0,
            sequence: 0,
            temp_path: None,
            file: None,
            chunks: Vec::new(),
        })
    }

    fn write_row(&mut self, row: &[String]) -> Result<()> {
        self.ensure_open_chunk()?;
        if let Some(file) = self.file.as_mut() {
            file.write_all(csv_line(row).as_bytes())?;
            self.current_rows = self.current_rows.saturating_add(1);
        }
        if self.current_rows >= self.rows_per_chunk {
            self.finish_current_chunk()?;
        }
        Ok(())
    }

    fn finish(mut self) -> Result<Vec<ExportChunkManifestEntry>> {
        self.finish_current_chunk()?;
        Ok(self.chunks)
    }

    fn ensure_open_chunk(&mut self) -> Result<()> {
        if self.file.is_some() {
            return Ok(());
        }
        self.sequence = self.sequence.saturating_add(1);
        self.current_rows = 0;
        let temp_path = self
            .report_dir
            .join(format!("{}_tmp_{:05}.csv", self.export_name, self.sequence));
        let mut file = BufWriter::new(File::create(&temp_path)?);
        file.write_all(self.header.as_bytes())?;
        self.temp_path = Some(temp_path);
        self.file = Some(file);
        Ok(())
    }

    fn finish_current_chunk(&mut self) -> Result<()> {
        let Some(temp_path) = self.temp_path.take() else {
            return Ok(());
        };
        if let Some(mut file) = self.file.take() {
            file.flush()?;
            file.get_ref().sync_all()?;
        }
        if self.current_rows == 0 {
            let _ = fs::remove_file(temp_path);
            return Ok(());
        }
        let raw_bytes = fs::read(&temp_path)?;
        let (final_bytes, compression) = if self.compress {
            (
                zstd::stream::encode_all(&raw_bytes[..], 3)?,
                self.compression.clone().or_else(|| Some("zstd".to_owned())),
            )
        } else {
            (raw_bytes, None)
        };
        let extension = if compression.is_some() {
            "csv.zst"
        } else {
            "csv"
        };
        let chunk_name = format!("{}_{:05}.{}", self.export_name, self.sequence, extension);
        let final_path = self.report_dir.join(&chunk_name);
        atomic_write_path(&final_path, &final_bytes)?;
        let _ = fs::remove_file(temp_path);
        self.chunks.push(ExportChunkManifestEntry {
            export_name: self.export_name.clone(),
            chunk_name,
            local_path: final_path.display().to_string(),
            row_count: self.current_rows as u64,
            size_bytes: final_bytes.len() as u64,
            checksum_sha256: checksum_hex(&final_bytes),
            remote_key: String::new(),
            uploaded: false,
            verified: false,
            pruned_local: false,
            compression,
        });
        self.current_rows = 0;
        Ok(())
    }
}

