async fn r2_empty_managed_prefix_command(
    loaded: &LoadedConfig,
    bucket: &str,
    prefix: &str,
    dry_run: bool,
    confirmation: bool,
) -> Result<()> {
    destructive_r2_operation_allowed(loaded, confirmation, Some(bucket), Some(prefix))?;
    let mut config = loaded.config.r2.clone();
    config.delete_enabled = true;
    let client = R2Client::new(&config)?;
    let objects = client.list_objects(bucket, prefix, None).await?;
    if !dry_run {
        for object in &objects {
            client.delete_object(bucket, &object.key).await?;
        }
    }
    println!(
        "{}",
        serde_json::to_string_pretty(&json!({
            "command": "r2-empty-managed-prefix",
            "dry_run": dry_run,
            "bucket": bucket,
            "prefix": prefix,
            "object_count": objects.len(),
            "bytes": objects.iter().map(|object| object.size_bytes).sum::<u64>(),
        }))?
    );
    Ok(())
}

