async fn r2_reset_managed_storage_command(
    loaded: &LoadedConfig,
    dry_run: bool,
    confirmation: bool,
    cloudflare_confirmation: bool,
) -> Result<()> {
    if !dry_run && !cloudflare_confirmation {
        return Err(anyhow!(
            "destructive R2 reset also requires --i-understand-this-deletes-cloudflare-r2-data"
        ));
    }
    let mut config = loaded.config.r2.clone();
    config.delete_enabled = true;
    let client = R2Client::new(&config)?;
    let buckets = configured_managed_buckets(&client);
    let mut plans = Vec::new();
    for bucket in &buckets {
        let objects = client
            .list_objects(bucket, &loaded.config.r2.managed_prefix, None)
            .await?;
        plans.push(json!({
            "bucket": bucket,
            "prefix": loaded.config.r2.managed_prefix,
            "object_count": objects.len(),
            "bytes": objects.iter().map(|object| object.size_bytes).sum::<u64>(),
        }));
        if !dry_run {
            destructive_r2_operation_allowed(
                loaded,
                confirmation,
                Some(bucket),
                Some(&loaded.config.r2.managed_prefix),
            )?;
            for object in &objects {
                client.delete_object(bucket, &object.key).await?;
            }
        }
    }
    println!(
        "{}",
        serde_json::to_string_pretty(&json!({
            "command": "r2-reset-managed-storage",
            "dry_run": dry_run,
            "plans": plans,
        }))?
    );
    Ok(())
}

fn collect_disk_preflight_summary(loaded: &LoadedConfig) -> Result<DiskPreflightSummary> {
    let store = storage_engine(loaded)?;
    let state = load_or_default_autopilot_state(loaded);
    let report_root = Path::new(&loaded.config.storage.root)
        .parent()
        .unwrap_or_else(|| Path::new("."))
        .join("data")
        .join("reports");
    let manifests = all_r2_manifest_paths(loaded)?
        .into_iter()
        .filter_map(|path| load_manifest(&path).ok())
        .collect::<Vec<_>>();
    let prune_summary = build_verified_prune_summary(
        loaded,
        true,
        loaded.config.autopilot.disk.allow_prune_verified_exports,
        loaded.config.autopilot.disk.allow_prune_verified_reports,
        loaded.config.autopilot.disk.allow_prune_verified_raw_events,
        loaded.config.autopilot.disk.keep_minimal_manifest,
        loaded.config.autopilot.disk.keep_rpc_ledger,
        loaded.config.autopilot.disk.keep_calibration,
        loaded.config.r2.retention.keep_last_n_local_runs,
        Some(loaded.config.r2.retention.keep_local_after_upload_hours),
        None,
        false,
        active_autopilot_run_id_from_state(&state),
        false,
    )?;
    let workspace_root = workspace_root_from_config(loaded);
    let target_dir = workspace_root.join("target");
    let var_log_path = PathBuf::from("/var/log");
    let root_filesystem = filesystem_usage_summary(Path::new(&loaded.config.storage.root))?;
    let free_mb = root_filesystem.free_bytes / (1024 * 1024);
    let var_log_size_bytes = path_size_bytes(&var_log_path);
    let journald_log_hint = (var_log_size_bytes > 512 * 1024 * 1024).then(|| {
        format!(
            "/var/log is {} bytes; consider checking journald or rotated logs",
            var_log_size_bytes
        )
    });
    let warning_free_mb = loaded.config.autopilot.disk.warning_free_mb;
    let pre_cycle_min_free_mb = loaded.config.autopilot.disk.pre_cycle_min_free_mb;
    let critical_free_mb = loaded.config.autopilot.disk.critical_free_mb;
    let emergency_free_mb = loaded.config.autopilot.disk.emergency_free_mb;
    Ok(DiskPreflightSummary {
        root_filesystem,
        data_directory_size_bytes: path_size_bytes(Path::new(&loaded.config.storage.root)),
        reports_directory_size_bytes: path_size_bytes(&report_root),
        exports_size_bytes: path_size_bytes(&report_root),
        event_logs_size_bytes: path_size_bytes(&store.layout().raw_event_log)
            + path_size_bytes(&store.layout().normalized_event_log)
            + path_size_bytes(&store.layout().decision_log)
            + path_size_bytes(&store.layout().fill_log),
        target_build_directory_size_bytes: path_size_bytes(&target_dir),
        var_log_size_bytes,
        journald_log_hint,
        active_run_id: active_autopilot_run_id_from_state(&state).map(ToOwned::to_owned),
        verified_uploaded_runs_count: manifests
            .iter()
            .filter(|manifest| manifest_verified(manifest))
            .count(),
        unverified_runs_count: manifests
            .iter()
            .filter(|manifest| !manifest_verified(manifest))
            .count(),
        prune_candidates_count: prune_summary.candidate_run_count,
        warning_active: free_mb < warning_free_mb && free_mb >= pre_cycle_min_free_mb,
        pre_cycle_blocked: free_mb < pre_cycle_min_free_mb,
        critical: free_mb < critical_free_mb,
        emergency: free_mb < emergency_free_mb,
        warning_free_mb,
        pre_cycle_min_free_mb,
        critical_free_mb,
        emergency_free_mb,
        min_free_mb_before_cycle: loaded.config.autopilot.disk.min_free_mb_before_cycle,
        min_free_mb_during_cycle: loaded.config.autopilot.disk.min_free_mb_during_cycle,
        free_mb,
    })
}

fn evaluate_pre_cycle_disk_policy(
    loaded: &LoadedConfig,
    state: &AutopilotPersistedState,
    preflight: &DiskPreflightSummary,
    stream_only_passed: bool,
) -> PreCycleDiskAssessment {
    let disk = &loaded.config.autopilot.disk;
    let mut details = BTreeMap::new();
    details.insert("free_mb".to_owned(), preflight.free_mb.to_string());
    details.insert(
        "warning_free_mb".to_owned(),
        disk.warning_free_mb.to_string(),
    );
    details.insert(
        "pre_cycle_min_free_mb".to_owned(),
        disk.pre_cycle_min_free_mb.to_string(),
    );
    details.insert(
        "critical_free_mb".to_owned(),
        disk.critical_free_mb.to_string(),
    );
    details.insert(
        "emergency_free_mb".to_owned(),
        disk.emergency_free_mb.to_string(),
    );
    details.insert(
        "unuploaded_run_count".to_owned(),
        preflight.unverified_runs_count.to_string(),
    );
    details.insert(
        "low_disk_mode_enabled".to_owned(),
        loaded.config.storage.low_disk_mode.enabled.to_string(),
    );

    if preflight.free_mb < disk.emergency_free_mb {
        return PreCycleDiskAssessment {
            decision: PreCycleDiskDecision::BlockEmergency,
            message: format!(
                "pre-cycle free_mb={} below emergency_free_mb={}",
                preflight.free_mb, disk.emergency_free_mb
            ),
            details,
        };
    }

    if preflight.free_mb < disk.critical_free_mb {
        return PreCycleDiskAssessment {
            decision: PreCycleDiskDecision::BlockCritical,
            message: format!(
                "pre-cycle free_mb={} below critical_free_mb={}",
                preflight.free_mb, disk.critical_free_mb
            ),
            details,
        };
    }

    if preflight.free_mb < disk.pre_cycle_min_free_mb {
        let decision = if disk.block_new_cycle_below_pre_cycle_min {
            PreCycleDiskDecision::BlockBelowPreCycleMinimum
        } else {
            PreCycleDiskDecision::StartAggressiveLowDisk
        };
        return PreCycleDiskAssessment {
            decision,
            message: format!(
                "pre-cycle free_mb={} below pre_cycle_min_free_mb={}",
                preflight.free_mb, disk.pre_cycle_min_free_mb
            ),
            details,
        };
    }

    if preflight.free_mb < disk.warning_free_mb {
        let r2_healthy = loaded.config.r2.enabled
            && loaded.config.r2.upload_enabled
            && !loaded.config.r2.dry_run;
        let no_unuploaded_runs = preflight.unverified_runs_count == 0;
        let no_active_recovery = state.needs_recovery_run_id.is_none()
            && !matches!(state.current_state, AutopilotPhase::NeedsRecovery);
        let stream_only_clean = stream_only_passed
            && state.last_rpc_network_calls_total == 0
            && state.last_rpc_credits_used_total == 0;
        details.insert("r2_healthy".to_owned(), r2_healthy.to_string());
        details.insert(
            "no_unuploaded_runs".to_owned(),
            no_unuploaded_runs.to_string(),
        );
        details.insert(
            "no_active_recovery".to_owned(),
            no_active_recovery.to_string(),
        );
        details.insert(
            "stream_only_clean".to_owned(),
            stream_only_clean.to_string(),
        );
        details.insert(
            "aggressive_low_disk_mode".to_owned(),
            disk.aggressive_low_disk_mode_below_warning.to_string(),
        );

        let low_disk_allowed = (!disk.block_new_cycle_below_warning)
            && (!loaded.config.storage.low_disk_mode.enabled
                || (disk.allow_cycle_below_warning_if_r2_healthy
                    && (!disk.require_no_unuploaded_runs_below_warning || no_unuploaded_runs)
                    && r2_healthy
                    && stream_only_clean
                    && no_active_recovery));

        return if low_disk_allowed {
            PreCycleDiskAssessment {
                decision: PreCycleDiskDecision::StartAggressiveLowDisk,
                message: format!(
                    "pre-cycle free_mb={} below warning_floor_mb={} but above pre_cycle_min_free_mb={}; starting in aggressive low-disk mode",
                    preflight.free_mb, disk.warning_free_mb, disk.pre_cycle_min_free_mb
                ),
                details,
            }
        } else {
            let mut reasons = Vec::new();
            if disk.block_new_cycle_below_warning {
                reasons.push("block_new_cycle_below_warning=true".to_owned());
            }
            if loaded.config.storage.low_disk_mode.enabled
                && !disk.allow_cycle_below_warning_if_r2_healthy
            {
                reasons.push("allow_cycle_below_warning_if_r2_healthy=false".to_owned());
            }
            if loaded.config.storage.low_disk_mode.enabled && !r2_healthy {
                reasons.push("r2_not_healthy".to_owned());
            }
            if loaded.config.storage.low_disk_mode.enabled
                && disk.require_no_unuploaded_runs_below_warning
                && !no_unuploaded_runs
            {
                reasons.push("unuploaded_runs_present".to_owned());
            }
            if loaded.config.storage.low_disk_mode.enabled && !no_active_recovery {
                reasons.push("active_recovery_required".to_owned());
            }
            if !stream_only_clean {
                reasons.push("stream_only_proof_not_clean".to_owned());
            }
            if reasons.is_empty() {
                reasons.push("below_warning_policy_blocked".to_owned());
            }
            PreCycleDiskAssessment {
                decision: PreCycleDiskDecision::BlockBelowWarningPolicy,
                message: format!(
                    "pre-cycle free_mb={} below warning_floor_mb={} and warning-mode start requirements were not met: {}",
                    preflight.free_mb,
                    disk.warning_free_mb,
                    reasons.join(",")
                ),
                details,
            }
        };
    }

    PreCycleDiskAssessment {
        decision: PreCycleDiskDecision::StartNormal,
        message: format!(
            "pre-cycle free_mb={} meets warning_free_mb={}",
            preflight.free_mb, disk.warning_free_mb
        ),
        details,
    }
}

