async fn populate_edge_dataset_fields_from_remote_manifest(
    loaded: &LoadedConfig,
    entry: &mut DatasetIndexRunEntry,
) -> Result<()> {
    if !entry.edge_mode {
        return Ok(());
    }
    let manifest = load_run_segment_manifest_local_or_r2(loaded, &entry.run_id, true).await?;
    let relevant = manifest
        .segments
        .iter()
        .filter(|segment| {
            segment.artifact_type.starts_with("edge_")
                || matches!(
                    segment.artifact_type.as_str(),
                    "normalized_events" | "source_events"
                )
        })
        .collect::<Vec<_>>();
    entry.edge_segments_count = relevant.len();
    entry.edge_segments_verified = relevant.iter().filter(|segment| segment.verified).count();
    entry.edge_segments_remote_bytes = relevant
        .iter()
        .filter(|segment| segment.verified)
        .map(|segment| segment.size_bytes)
        .sum();
    entry.edge_segments_local_bytes = relevant
        .iter()
        .filter(|segment| !segment.pruned_local)
        .map(|segment| segment.size_bytes)
        .sum();
    let (normalized_events_segments_count, normalized_events_segments_verified) =
        segment_counts_by_artifact_type(Some(&manifest), "normalized_events");
    let (source_events_segments_count, source_events_segments_verified) =
        segment_counts_by_artifact_type(Some(&manifest), "source_events");
    let (edge_events_segments_count, _) =
        segment_counts_by_artifact_type(Some(&manifest), "edge_events");
    let (edge_transactions_segments_count, _) =
        segment_counts_by_artifact_type(Some(&manifest), "edge_transactions");
    let (edge_accounts_segments_count, _) =
        segment_counts_by_artifact_type(Some(&manifest), "edge_accounts");
    let (edge_slots_segments_count, _) =
        segment_counts_by_artifact_type(Some(&manifest), "edge_slots");
    let (edge_data_gaps_segments_count, _) =
        segment_counts_by_artifact_type(Some(&manifest), "edge_data_gaps");
    entry.normalized_events_segments_count = normalized_events_segments_count;
    entry.normalized_events_segments_verified = normalized_events_segments_verified;
    entry.source_events_segments_count = source_events_segments_count;
    entry.source_events_segments_verified = source_events_segments_verified;
    entry.edge_events_segments_count = edge_events_segments_count;
    entry.edge_transactions_segments_count = edge_transactions_segments_count;
    entry.edge_accounts_segments_count = edge_accounts_segments_count;
    entry.edge_slots_segments_count = edge_slots_segments_count;
    entry.edge_data_gaps_segments_count = edge_data_gaps_segments_count;
    entry.normalized_events_missing = normalized_events_segments_count == 0;
    entry.edge_dataset_complete = normalized_events_segments_count > 0
        && normalized_events_segments_count == normalized_events_segments_verified
        && manifest.summary.failed_segments == 0
        && manifest
            .segments
            .iter()
            .filter(|segment| !segment.verified)
            .count()
            == 0;
    entry.edge_source_ready = entry.stream_only_passed
        && entry.r2_verified
        && entry.edge_segments_count > 0
        && entry.edge_segments_count == entry.edge_segments_verified;
    entry.edge_source_complete = entry.edge_source_ready && entry.edge_dataset_complete;
    Ok(())
}

fn json_u64_field(value: &serde_json::Value, object: &str, field: &str) -> u64 {
    value
        .get(object)
        .and_then(|node| node.get(field))
        .and_then(|node| {
            node.as_u64().or_else(|| {
                node.as_str()
                    .and_then(|text| text.trim().parse::<u64>().ok())
            })
        })
        .unwrap_or_default()
}

fn json_string_field(value: &serde_json::Value, field: &str) -> Option<String> {
    value
        .get(field)
        .and_then(|node| node.as_str())
        .filter(|text| !text.trim().is_empty())
        .map(|text| text.to_owned())
}

fn json_decimal_nested(value: &serde_json::Value, object: &str, field: &str) -> Option<Decimal> {
    value
        .get(object)
        .and_then(|node| node.get(field))
        .and_then(|node| match node {
            serde_json::Value::Number(number) => number.to_string().parse::<Decimal>().ok(),
            serde_json::Value::String(text) => text.parse::<Decimal>().ok(),
            _ => None,
        })
}

fn parity_status(value: &serde_json::Value, object: &str) -> Option<String> {
    let passed = json_u64_field(value, object, "passed");
    let failed = json_u64_field(value, object, "failed");
    let unavailable = json_u64_field(value, object, "unavailable");
    if failed > 0 {
        Some("failed".to_owned())
    } else if unavailable > 0 && passed > 0 {
        Some("partial_pass_with_unavailable".to_owned())
    } else if unavailable > 0 {
        Some("unavailable".to_owned())
    } else if passed > 0 {
        Some("passed".to_owned())
    } else {
        None
    }
}

fn candidate_phase_math_report_dirs(output_dir: &Path) -> Vec<PathBuf> {
    let mut dirs = Vec::new();
    dirs.push(output_dir.to_path_buf());
    let mut cursor = output_dir;
    for _ in 0..3 {
        let Some(parent) = cursor.parent() else {
            break;
        };
        dirs.push(parent.to_path_buf());
        cursor = parent;
    }
    dirs
}

fn apply_phase_math_metadata_from_local_reports(
    entry: &mut DatasetIndexRunEntry,
    output_dir: &str,
) {
    let output_dir = PathBuf::from(output_dir);
    let dirs = candidate_phase_math_report_dirs(&output_dir);
    let math_summary = dirs
        .iter()
        .map(|dir| dir.join("math_correctness_summary.json"))
        .find(|path| path.exists())
        .and_then(|path| read_json_file::<serde_json::Value>(&path));
    let Some(math_summary) = math_summary else {
        return;
    };

    entry.math_version = Some("phase76_owner_summed".to_owned());
    entry.holder_math_version = Some("phase76_owner_summed".to_owned());
    entry.math_correctness_status = json_string_field(&math_summary, "math_correctness_status");
    entry.holder_parity_status = parity_status(&math_summary, "holder_parity");
    entry.top_holder_parity_status = parity_status(&math_summary, "top_holder_parity");
    entry.dev_holding_parity_status = parity_status(&math_summary, "dev_holding_parity");
    entry.holder_invariant_status = json_string_field(&math_summary, "holder_invariant_status");
    entry.holder_parity_passed = json_u64_field(&math_summary, "holder_parity", "passed");
    entry.holder_parity_failed = json_u64_field(&math_summary, "holder_parity", "failed");
    entry.holder_parity_unavailable = json_u64_field(&math_summary, "holder_parity", "unavailable");
    entry.top_holder_parity_passed = json_u64_field(&math_summary, "top_holder_parity", "passed");
    entry.top_holder_parity_failed = json_u64_field(&math_summary, "top_holder_parity", "failed");
    entry.top_holder_parity_unavailable =
        json_u64_field(&math_summary, "top_holder_parity", "unavailable");
    entry.dev_holding_parity_passed = json_u64_field(&math_summary, "dev_holding_parity", "passed");
    entry.dev_holding_parity_failed = json_u64_field(&math_summary, "dev_holding_parity", "failed");
    entry.threshold_tuning_allowed = false;

    let replay_comparison = dirs
        .iter()
        .map(|dir| dir.join("replay_outcome_comparison.json"))
        .find(|path| path.exists())
        .and_then(|path| read_json_file::<serde_json::Value>(&path));
    if let Some(replay_comparison) = replay_comparison {
        let pnl = json_decimal_nested(&replay_comparison, "new_replay", "paper_pnl");
        entry.executable_pnl_total = pnl;
        entry.raw_pnl_total = pnl;
        entry.artifact_excluded_pnl_total = Some(Decimal::ZERO);
    }
}

async fn apply_research_outputs_to_dataset_index(
    loaded: &LoadedConfig,
    index: &mut DatasetIndex,
    source_run_id: &str,
    run_summary: &ResearchWorkerRunSummary,
    summary: &ResearchResultsUploadSummary,
) -> Result<()> {
    let Some(entry) = index
        .runs
        .iter_mut()
        .find(|entry| entry.run_id == source_run_id)
    else {
        return Err(anyhow!(
            "source run {source_run_id} not present in authoritative dataset index"
        ));
    };
    entry.research_outputs_available = summary.research_outputs_available;
    entry.research_worker_processed = summary.research_outputs_available;
    entry.research_latest_derived_run_id = summary.replay_run_id.clone();
    entry.research_outputs_remote_prefix = summary.research_outputs_remote_prefix.clone();
    entry.feature_outputs_remote_key = summary.feature_outputs_remote_key.clone();
    entry.backtest_outputs_remote_key = summary.backtest_outputs_remote_key.clone();
    entry.calibration_outputs_remote_key = summary.calibration_outputs_remote_key.clone();
    entry.decision_outputs_remote_key = summary.decision_outputs_remote_key.clone();
    entry.fill_outputs_remote_key = summary.fill_outputs_remote_key.clone();
    entry.research_manifest_remote_key = summary.research_manifest_remote_key.clone();
    entry.research_r2_verified = summary.research_r2_verified;
    entry.research_r2_verified_count = summary.research_r2_verified_count;
    entry.research_r2_failed_count = summary.research_r2_failed_count;
    entry.research_derived_ready = run_summary.research_derived_ready;
    entry.research_derived_readiness_level = run_summary.research_derived_readiness_level.clone();
    entry.normalized_events_missing = run_summary.normalized_events_missing;
    entry.fallback_used = run_summary.fallback_used;
    entry.fallback_reason = run_summary.fallback_reason.clone();
    entry.fallback_source = run_summary.fallback_source.clone();
    entry.research_replay_confidence = run_summary.research_replay_confidence;
    entry.segment_warning_count = run_summary.warnings.len();
    entry.invalid_segment_count = run_summary.invalid_segment_count;
    entry.invalid_segments = run_summary.invalid_segments.clone();
    entry.unresolved_segment_warnings = run_summary.unresolved_segment_warnings.clone();
    entry.fallback_replay_affected = run_summary.fallback_replay_affected;
    entry.normalized_replay_warning = run_summary.normalized_replay_warning;
    entry.normalized_replay_affected = run_summary.normalized_replay_affected;
    entry.normalized_invalid_segment_count = run_summary.normalized_invalid_segment_count;
    entry.source_fallback_warning = run_summary.source_fallback_warning;
    entry.source_fallback_affected = run_summary.source_fallback_affected;
    entry.edge_dataset_complete = run_summary.edge_dataset_complete;
    apply_phase_math_metadata_from_local_reports(entry, &summary.output_dir);
    let _ = populate_edge_dataset_fields_from_remote_manifest(loaded, entry).await;
    entry.normalized_events_missing =
        entry.edge_mode && entry.normalized_events_segments_count == 0;
    index.generated_at = OffsetDateTime::now_utc();
    Ok(())
}

async fn upload_dataset_index_value_r2(
    loaded: &LoadedConfig,
    index: &DatasetIndex,
    dry_run: bool,
    verify: bool,
) -> Result<DatasetIndexUploadSummary> {
    let path = dataset_index_path(loaded);
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent)?;
    }
    fs::write(&path, serde_json::to_vec_pretty(index)?)?;
    let client = r2_client_for_command(loaded, dry_run, true, false)?;
    let bucket = client.bucket_for_reports()?;
    let key = client.managed_key(
        &client.config().paths.manifests_prefix,
        "dataset_index.json",
    );
    let prepared = client.prepare_upload(
        &path,
        bucket.clone(),
        key.clone(),
        "application/json",
        BTreeMap::new(),
        Some(false),
    )?;
    let result = client
        .upload_prepared(&prepared, verify.then_some(true))
        .await?;
    if verify && !dry_run && !result.verified {
        return Err(anyhow!("dataset index upload did not verify"));
    }
    Ok(DatasetIndexUploadSummary {
        path: path.display().to_string(),
        bucket,
        remote_key: key,
        uploaded: result.uploaded,
        verified: result.verified,
        run_count: index.runs.len(),
        dry_run,
        authoritative_run_count_before: 0,
        merged_run_count_after: index.runs.len(),
        changed_run_ids: Vec::new(),
        dry_run_diff: false,
    })
}

async fn resolve_backfill_run_ids(
    loaded: &LoadedConfig,
    run_id: Option<&str>,
    latest_live_paper_run: bool,
    latest_recovered_run: bool,
    all_recovered: bool,
) -> Result<Vec<String>> {
    if let Some(run_id) = run_id {
        return Ok(vec![run_id.to_owned()]);
    }
    if all_recovered {
        let run_ids = latest_recovered_run_ids(loaded)?;
        if run_ids.is_empty() {
            return Err(anyhow!("no recovered runs found"));
        }
        return Ok(run_ids);
    }
    if latest_recovered_run {
        return latest_recovered_run_ids(loaded)?
            .into_iter()
            .last()
            .map(|run_id| vec![run_id])
            .ok_or_else(|| anyhow!("no recovered runs found"));
    }
    Ok(vec![
        select_live_collection_run_id(loaded, None, latest_live_paper_run, false, false, false)
            .await?,
    ])
}

async fn backfill_run_metadata_command(
    loaded: &LoadedConfig,
    run_id: Option<&str>,
    latest_live_paper_run: bool,
    latest_recovered_run: bool,
    all_recovered: bool,
    dry_run: bool,
    write: bool,
    refresh_dataset_index_flag: bool,
    upload_dataset_index: bool,
    verify_r2: bool,
) -> Result<()> {
    let run_ids = resolve_backfill_run_ids(
        loaded,
        run_id,
        latest_live_paper_run,
        latest_recovered_run,
        all_recovered,
    )
    .await?;
    let mut summaries = Vec::new();
    let mut report_paths = Vec::new();
    for run_id in &run_ids {
        let summary =
            collect_run_metadata_backfill_summary(loaded, run_id, verify_r2 && !dry_run).await?;
        if write && !dry_run {
            persist_backfilled_run_metadata(loaded, &summary)?;
            let (markdown_path, json_path) = write_metadata_backfill_reports(loaded, &summary)?;
            let _ = write_canonical_run_summary_reports(loaded, run_id, &summary)?;
            let _ = refresh_backtest_readiness_reports_from_backfill(loaded, run_id, &summary)?;
            report_paths.push(json!({
                "run_id": run_id,
                "markdown_path": markdown_path.display().to_string(),
                "json_path": json_path.display().to_string(),
            }));
        }
        summaries.push(summary);
    }

    let mut dataset_index_run_count = None;
    let mut dataset_index_uploaded = None;
    if !dry_run && (refresh_dataset_index_flag || upload_dataset_index) {
        let index = refresh_dataset_index(loaded)?;
        dataset_index_run_count = Some(index.runs.len());
        if upload_dataset_index {
            let summary = upload_dataset_index_r2_internal(
                loaded,
                loaded.config.r2.dry_run,
                true,
                true,
                false,
            )
            .await?;
            dataset_index_uploaded =
                Some(summary.verified || (summary.uploaded && summary.dry_run));
            dataset_index_run_count = Some(summary.run_count);
        }
    }

    if write && !dry_run {
        let uploaded = dataset_index_uploaded.unwrap_or(false);
        let run_count = dataset_index_run_count.unwrap_or_default();
        for summary in &summaries {
            update_autopilot_state_from_backfill(loaded, summary, uploaded, run_count)?;
        }
    }

    println!(
        "{}",
        serde_json::to_string_pretty(&json!({
            "command": "backfill-run-metadata",
            "dry_run": dry_run,
            "write": write,
            "refresh_dataset_index": refresh_dataset_index_flag,
            "upload_dataset_index": upload_dataset_index,
            "verify_r2": verify_r2,
            "run_ids": run_ids,
            "summaries": summaries,
            "report_paths": report_paths,
            "dataset_index_run_count": dataset_index_run_count,
            "dataset_index_uploaded": dataset_index_uploaded,
        }))?
    );
    Ok(())
}

async fn upload_dataset_index_r2_internal(
    loaded: &LoadedConfig,
    dry_run: bool,
    verify: bool,
    merge_authoritative: bool,
    dry_run_diff: bool,
) -> Result<DatasetIndexUploadSummary> {
    let guard = acquire_dataset_index_lock(loaded, "upload-dataset-index-r2")?;
    refresh_dataset_index_lock(&guard, "upload-dataset-index-r2")?;
    let local_index = refresh_dataset_index(loaded)?;
    let authoritative_index = if merge_authoritative {
        match download_dataset_index_from_r2(loaded).await {
            Ok(index) => index,
            Err(_) => local_index.clone(),
        }
    } else {
        local_index.clone()
    };
    let authoritative_run_count_before = authoritative_index.runs.len();
    let mut merged_index = authoritative_index.clone();
    if merge_authoritative {
        for entry in local_index.runs.clone() {
            upsert_dataset_index_entry(&mut merged_index, entry);
        }
        merged_index.calibration = local_index.calibration.clone();
        merged_index.provider_compat = local_index.provider_compat.clone();
        merged_index.generated_at = OffsetDateTime::now_utc();
    }
    let changed_run_ids = dataset_index_changed_run_ids(&authoritative_index, &merged_index)?;
    if dry_run_diff {
        let client = r2_client_for_command(loaded, true, true, false)?;
        let bucket = client.bucket_for_reports()?;
        let remote_key = client.managed_key(
            &client.config().paths.manifests_prefix,
            "dataset_index.json",
        );
        return Ok(DatasetIndexUploadSummary {
            path: dataset_index_path(loaded).display().to_string(),
            bucket,
            remote_key,
            uploaded: false,
            verified: false,
            run_count: merged_index.runs.len(),
            dry_run: true,
            authoritative_run_count_before,
            merged_run_count_after: merged_index.runs.len(),
            changed_run_ids,
            dry_run_diff: true,
        });
    }
    refresh_dataset_index_lock(&guard, "upload-dataset-index-r2")?;
    let mut summary = upload_dataset_index_value_r2(loaded, &merged_index, dry_run, verify).await?;
    summary.authoritative_run_count_before = authoritative_run_count_before;
    summary.merged_run_count_after = merged_index.runs.len();
    summary.changed_run_ids = changed_run_ids;
    summary.dry_run_diff = false;
    Ok(summary)
}

async fn upload_dataset_index_r2_command(
    loaded: &LoadedConfig,
    dry_run: bool,
    verify: bool,
    merge_authoritative: bool,
    dry_run_diff: bool,
) -> Result<()> {
    let summary = upload_dataset_index_r2_internal(
        loaded,
        dry_run,
        verify,
        merge_authoritative,
        dry_run_diff,
    )
    .await?;
    println!(
        "{}",
        serde_json::to_string_pretty(&json!({
            "command": "upload-dataset-index-r2",
            "dry_run": summary.dry_run,
            "verify": verify,
            "merge_authoritative": merge_authoritative,
            "dry_run_diff": dry_run_diff,
            "path": summary.path,
            "bucket": summary.bucket,
            "remote_key": summary.remote_key,
            "uploaded": summary.uploaded,
            "verified": summary.verified,
            "run_count": summary.run_count,
            "authoritative_run_count_before": summary.authoritative_run_count_before,
            "merged_run_count_after": summary.merged_run_count_after,
            "changed_run_ids": summary.changed_run_ids,
        }))?
    );
    Ok(())
}

fn collect_regular_files(root: &Path) -> Result<Vec<PathBuf>> {
    let mut files = Vec::new();
    if !root.exists() {
        return Ok(files);
    }
    let mut stack = vec![root.to_path_buf()];
    while let Some(path) = stack.pop() {
        for entry in fs::read_dir(&path)? {
            let entry = entry?;
            let path = entry.path();
            let name = path
                .file_name()
                .and_then(|value| value.to_str())
                .unwrap_or_default();
            if name == ".DS_Store" || name == "Thumbs.db" || name.starts_with(".") {
                continue;
            }
            let metadata = entry.metadata()?;
            if metadata.is_dir() {
                stack.push(path);
            } else if metadata.is_file() {
                files.push(path);
            }
        }
    }
    files.sort();
    Ok(files)
}

async fn publish_phase82_results_command(
    loaded: &LoadedConfig,
    phase82_dir: &str,
    pinned_run_set: &str,
    verify: bool,
) -> Result<()> {
    let phase82_dir = PathBuf::from(phase82_dir);
    let phase_dir_lower = phase82_dir.to_string_lossy().to_ascii_lowercase();
    let phase_label = if phase_dir_lower.contains("phase85") {
        "phase85_diagnostic_lab"
    } else if phase_dir_lower.contains("phase84") {
        "phase84_labels"
    } else if phase_dir_lower.contains("phase83") {
        "phase83_labels"
    } else {
        "phase82_labels"
    };
    let command_name = match phase_label {
        "phase85_diagnostic_lab" => "publish-phase85-diagnostic-lab",
        "phase84_labels" => "publish-phase84-results",
        "phase83_labels" => "publish-phase83-results",
        _ => "publish-phase82-results",
    };
    let pinned_run_set_path = PathBuf::from(pinned_run_set);
    let pinned = read_json_file::<serde_json::Value>(&pinned_run_set_path).ok_or_else(|| {
        anyhow!(
            "pinned run set missing or invalid: {}",
            pinned_run_set_path.display()
        )
    })?;
    let runs = pinned
        .get("runs")
        .and_then(|value| value.as_array())
        .ok_or_else(|| anyhow!("pinned run set must contain runs array"))?;
    let readiness =
        read_json_file::<serde_json::Value>(&phase82_dir.join("backtest_readiness_v2_batch.json"))
            .unwrap_or_else(|| json!({}));
    let metric_batch =
        read_json_file::<serde_json::Value>(&phase82_dir.join("metric_parity_batch.json"))
            .unwrap_or_else(|| json!({}));

    let client = r2_client_for_command(loaded, false, true, false)?;
    let bucket = client.bucket_for_reports()?;
    let mut uploaded_files = Vec::new();
    let mut verified_files = Vec::new();
    let mut failed_files = Vec::new();
    for path in collect_regular_files(&phase82_dir)? {
        let relative = path
            .strip_prefix(&phase82_dir)
            .unwrap_or(path.as_path())
            .to_string_lossy()
            .replace('\\', "/");
        let remote_key = client.managed_key(
            &research_remote_base_prefix(&client),
            &format!("{phase_label}/{relative}"),
        );
        let prepared = client.prepare_upload(
            &path,
            bucket.clone(),
            remote_key.clone(),
            &artifact_content_type(&path),
            BTreeMap::new(),
            Some(false),
        )?;
        let result = client
            .upload_prepared(&prepared, verify.then_some(true))
            .await?;
        if result.uploaded {
            uploaded_files.push(remote_key.clone());
        }
        if verify && result.verified {
            verified_files.push(remote_key.clone());
        }
        if verify && !result.verified {
            failed_files.push(remote_key.clone());
        }
    }

    let mut index = match download_dataset_index_from_r2(loaded).await {
        Ok(index) => index,
        Err(_) => load_dataset_index_local_or_r2(loaded, false).await?,
    };
    let mut updated_run_ids = Vec::new();
    for run in runs {
        let Some(source_run_id) = run.get("source_run_id").and_then(|value| value.as_str()) else {
            continue;
        };
        let derived_run_id = run
            .get("derived_run_id")
            .and_then(|value| value.as_str())
            .map(ToOwned::to_owned);
        let entry = index
            .runs
            .iter_mut()
            .find(|entry| entry.run_id == source_run_id)
            .ok_or_else(|| anyhow!("source run {source_run_id} not found in dataset index"))?;
        entry.threshold_tuning_allowed = false;
        if phase_label == "phase85_diagnostic_lab" {
            entry.diagnostic_backtest_phase = Some("phase85".to_owned());
            entry.diagnostic_backtest_status = Some("generated".to_owned());
            entry.hypothesis_shortlist_available = true;
            updated_run_ids.push(source_run_id.to_owned());
            continue;
        }
        let summary_path = phase82_dir
            .join("runs")
            .join(source_run_id)
            .join("metric_parity_summary.json");
        let summary = read_json_file::<serde_json::Value>(&summary_path)
            .ok_or_else(|| anyhow!("metric parity summary missing: {}", summary_path.display()))?;
        let metric_parity_v2 = json!({
            "schema_version": match phase_label {
                "phase84_labels" => "metric_parity_v2.phase84",
                "phase83_labels" => "metric_parity_v2.phase83",
                _ => "metric_parity_v2.phase82",
            },
            "metric_engine_version": "phase80_metric_engine_v2",
            "generated_at": OffsetDateTime::now_utc(),
            "source_run_id": source_run_id,
            "derived_run_id": derived_run_id,
            "families": summary.get("families").cloned().unwrap_or_else(|| json!({})),
            "overall_status": summary.get("metric_parity_overall_status").cloned().unwrap_or_else(|| json!("unknown")),
            "diagnostics_allowed": metric_batch.get("diagnostic_backtesting_allowed").cloned().unwrap_or_else(|| json!(false)),
            "backtest_allowed": readiness.pointer("/use_cases/single_run_backtest/allowed").cloned().unwrap_or_else(|| json!(false)),
            "threshold_tuning_allowed": false,
        });
        let readiness_v2 = json!({
            "schema_version": match phase_label {
                "phase84_labels" => "readiness_v2.phase84",
                "phase83_labels" => "readiness_v2.phase83",
                _ => "readiness_v2.phase82",
            },
            "generated_at": OffsetDateTime::now_utc(),
            "source_run_id": source_run_id,
            "derived_run_id": derived_run_id,
            "diagnostics": readiness.pointer("/use_cases/diagnostics").cloned().unwrap_or_else(|| json!({"allowed": false})),
            "single_run_backtest": readiness.pointer("/use_cases/single_run_backtest").cloned().unwrap_or_else(|| json!({"allowed": false})),
            "multi_run_backtest": readiness.pointer("/use_cases/multi_run_backtest").cloned().unwrap_or_else(|| json!({"allowed": false})),
            "threshold_tuning": readiness.pointer("/use_cases/threshold_tuning").cloned().unwrap_or_else(|| json!({"allowed": false})),
            "walk_forward": readiness.pointer("/use_cases/walk_forward").cloned().unwrap_or_else(|| json!({"allowed": false})),
        });
        entry.metric_parity_v2 = Some(metric_parity_v2);
        entry.readiness_v2 = Some(readiness_v2);
        if phase_label == "phase83_labels" || phase_label == "phase84_labels" {
            let family_status = |family: &str| -> Option<String> {
                summary
                    .pointer(&format!("/families/{family}/status"))
                    .and_then(|value| value.as_str())
                    .map(ToOwned::to_owned)
            };
            entry.label_generator_version = Some(if phase_label == "phase84_labels" {
                "phase84_cli_v2".to_owned()
            } else {
                "phase83_cli".to_owned()
            });
            entry.canonical_label_status = Some(
                family_status("mfe_mae")
                    .unwrap_or_else(|| "partial_pass_with_unavailable".to_owned()),
            );
            entry.price_coverage_status = family_status("price");
            entry.market_cap_coverage_status = family_status("market_cap");
            entry.curve_progress_coverage_status = family_status("curve_progress");
            entry.mfe_mae_label_status = family_status("mfe_mae");
            entry.diagnostic_backtest_pack_status = Some("generated".to_owned());
            entry.diagnostic_backtesting_allowed = metric_batch
                .get("diagnostic_backtesting_allowed")
                .and_then(|value| value.as_bool())
                .unwrap_or(false);
            if phase_label == "phase84_labels" {
                entry.canonical_price_path_version = Some("phase84_v2".to_owned());
                entry.curve_coverage_status = family_status("curve_progress");
                entry.label_coverage_status = family_status("mfe_mae");
                entry.diagnostic_backtest_interpretation_status = Some("generated".to_owned());
            }
        }
        updated_run_ids.push(source_run_id.to_owned());
    }
    index.generated_at = OffsetDateTime::now_utc();
    let local_path = dataset_index_path(loaded);
    if let Some(parent) = local_path.parent() {
        fs::create_dir_all(parent)?;
    }
    fs::write(&local_path, serde_json::to_vec_pretty(&index)?)?;
    let upload_summary = upload_dataset_index_value_r2(loaded, &index, false, verify).await?;
    let result = json!({
        "command": command_name,
        "phase_label": phase_label,
        "phase82_dir": phase82_dir.display().to_string(),
        "pinned_run_set": pinned_run_set_path.display().to_string(),
        "uploaded_label_report_files": uploaded_files.len(),
        "verified_label_report_files": verified_files.len(),
        "failed_label_report_files": failed_files,
        "updated_run_ids": updated_run_ids,
        "dataset_index_uploaded": upload_summary.uploaded,
        "dataset_index_verified": upload_summary.verified,
        "dataset_index_remote_key": upload_summary.remote_key,
        "dataset_index_bucket": upload_summary.bucket,
        "no_secrets": true,
    });
    fs::write(
        phase82_dir.join("dataset_index_upload_result.json"),
        serde_json::to_vec_pretty(&result)?,
    )?;
    write_report(
        phase82_dir.join("dataset_index_upload_result.md"),
        &format!(
            "# {} Dataset Index Upload\n\n- uploaded_label_report_files: {}\n- verified_label_report_files: {}\n- updated_run_ids: `{}`\n- dataset_index_uploaded: {}\n- dataset_index_verified: {}\n- dataset_index_remote_key: `{}`\n- no_secrets: true\n",
            phase_label,
            result["uploaded_label_report_files"]
                .as_u64()
                .unwrap_or_default(),
            result["verified_label_report_files"]
                .as_u64()
                .unwrap_or_default(),
            updated_run_ids.join(", "),
            upload_summary.uploaded,
            upload_summary.verified,
            upload_summary.remote_key,
        ),
    )?;
    println!("{}", serde_json::to_string_pretty(&result)?);
    Ok(())
}

async fn inspect_dataset_index_command(
    loaded: &LoadedConfig,
    dataset_index_r2: bool,
) -> Result<()> {
    let path = dataset_index_path(loaded);
    let index = load_dataset_index_local_or_r2(loaded, dataset_index_r2).await?;
    println!(
        "{}",
        serde_json::to_string_pretty(&json!({
            "command": "inspect-dataset-index",
            "path": if dataset_index_r2 { None::<String> } else { Some(path.display().to_string()) },
            "source": if dataset_index_r2 { "r2" } else { "local_or_built" },
            "schema_version": index.schema_version,
            "run_count": index.runs.len(),
            "runs": index.runs,
            "calibration": index.calibration,
            "provider_compat": index.provider_compat,
        }))?
    );
    Ok(())
}

fn normalized_complete_run_records(
    index: &DatasetIndex,
    latest_n: Option<usize>,
) -> Vec<NormalizedCompleteRunRecord> {
    let mut runs = index
        .runs
        .iter()
        .filter(|entry| run_is_normalized_complete(entry))
        .map(|entry| NormalizedCompleteRunRecord {
            run_id: entry.run_id.clone(),
            created_at: entry.created_at.or(entry.completed_at),
            normalized_events_segments_count: entry.normalized_events_segments_count,
            normalized_events_segments_verified: entry.normalized_events_segments_verified,
            source_events_segments_count: entry.source_events_segments_count,
            edge_segments_count: entry.edge_segments_count,
            fallback_used: entry.fallback_used,
            edge_dataset_complete: entry.edge_dataset_complete,
            r2_full_verification_status: entry.r2_full_verification_status.clone(),
            r2_full_consistency_status: entry.r2_full_consistency_status.clone(),
            research_worker_processed: entry.research_worker_processed,
            research_latest_derived_run_id: entry.research_latest_derived_run_id.clone(),
        })
        .collect::<Vec<_>>();
    runs.sort_by(|left, right| {
        right
            .created_at
            .unwrap_or(OffsetDateTime::UNIX_EPOCH)
            .cmp(&left.created_at.unwrap_or(OffsetDateTime::UNIX_EPOCH))
            .then_with(|| right.run_id.cmp(&left.run_id))
    });
    if let Some(limit) = latest_n {
        runs.truncate(limit);
    }
    runs
}

async fn list_normalized_complete_runs_command(
    loaded: &LoadedConfig,
    dataset_index_r2: bool,
    latest_n: Option<usize>,
) -> Result<()> {
    let index = load_dataset_index_local_or_r2(loaded, dataset_index_r2).await?;
    let runs = normalized_complete_run_records(&index, latest_n);
    let report_root = resolve_user_path(loaded, &loaded.config.research_worker.local_output_dir);
    fs::create_dir_all(&report_root)?;
    let markdown_path = report_root.join("normalized_events_complete_runs.md");
    let json_path = report_root.join("normalized_events_complete_runs.json");
    let markdown = format!(
        "# Normalized-Complete Edge Runs\n\n- count: {}\n- runs: {:?}\n",
        runs.len(),
        runs.iter().map(|run| &run.run_id).collect::<Vec<_>>()
    );
    write_report(&markdown_path, &markdown)?;
    let summary = NormalizedCompleteRunsSummary {
        command: "list-normalized-complete-runs".to_owned(),
        count: runs.len(),
        runs,
        markdown_path: markdown_path.display().to_string(),
        json_path: json_path.display().to_string(),
    };
    fs::write(&json_path, serde_json::to_vec_pretty(&summary)?)?;
    println!("{}", serde_json::to_string_pretty(&summary)?);
    Ok(())
}

fn enrichment_required_env_missing() -> Vec<String> {
    [
        "HELIUS_API_KEY",
        "BIRDEYE_API_KEY",
        "SHYFT_API_KEY",
        "TWITTER_BEARER_TOKEN",
        "X_API_KEY",
        "DISCORD_TOKEN",
    ]
    .into_iter()
    .filter(|name| {
        std::env::var(name)
            .map(|value| value.trim().is_empty())
            .unwrap_or(true)
    })
    .map(ToOwned::to_owned)
    .collect::<Vec<_>>()
}

fn enrichment_readiness_check_command(loaded: &LoadedConfig) -> Result<()> {
    let report_root = resolve_user_path(loaded, &loaded.config.research_worker.local_output_dir);
    fs::create_dir_all(&report_root)?;
    let cache_dir = resolve_user_path(loaded, &loaded.config.enrichment.cache_dir);
    fs::create_dir_all(&cache_dir)?;
    let ledger_path = resolve_user_path(loaded, &loaded.config.enrichment.ledger_path);
    if !ledger_path.exists() {
        if let Some(parent) = ledger_path.parent() {
            fs::create_dir_all(parent)?;
        }
        fs::write(&ledger_path, b"")?;
    }
    let required_env_missing = enrichment_required_env_missing();
    let cache_dir_exists = cache_dir.exists();
    let ledger_exists = ledger_path.exists();
    let rpc_budget_config_present = loaded.config.enrichment.max_daily_rpc_calls > 0
        && loaded.config.enrichment.max_daily_rpc_credits > 0;
    let metadata_fetch_budget_config_present =
        loaded.config.enrichment.max_daily_http_metadata_fetches > 0;
    let metadata_social_canary_possible_without_rpc =
        loaded.config.enrichment.metadata.allow_uri_fetch
            && loaded.config.enrichment.metadata.allow_social_detection;
    let ready_for_metadata_social_canary = metadata_social_canary_possible_without_rpc
        && cache_dir_exists
        && ledger_exists
        && required_env_missing.is_empty();
    let ready_for_funding_bundle_canary = cache_dir_exists
        && ledger_exists
        && rpc_budget_config_present
        && required_env_missing.is_empty()
        && loaded.config.enrichment.rpc.allow_funding_graph_rpc
        && loaded.config.enrichment.rpc.allow_bundle_evidence_rpc;
    let ready_for_any_enrichment =
        ready_for_metadata_social_canary || ready_for_funding_bundle_canary;
    let mut canary_limits = BTreeMap::new();
    canary_limits.insert(
        "max_daily_rpc_calls".to_owned(),
        loaded.config.enrichment.max_daily_rpc_calls.to_string(),
    );
    canary_limits.insert(
        "max_daily_rpc_credits".to_owned(),
        loaded.config.enrichment.max_daily_rpc_credits.to_string(),
    );
    canary_limits.insert(
        "max_daily_http_metadata_fetches".to_owned(),
        loaded
            .config
            .enrichment
            .max_daily_http_metadata_fetches
            .to_string(),
    );
    canary_limits.insert(
        "max_wallets_per_run".to_owned(),
        loaded.config.enrichment.max_wallets_per_run.to_string(),
    );
    canary_limits.insert(
        "max_tokens_per_run".to_owned(),
        loaded.config.enrichment.max_tokens_per_run.to_string(),
    );
    canary_limits.insert(
        "max_signatures_per_wallet".to_owned(),
        loaded
            .config
            .enrichment
            .max_signatures_per_wallet
            .to_string(),
    );
    let markdown_path = report_root.join("enrichment_readiness_check.md");
    let json_path = report_root.join("enrichment_readiness_check.json");
    let summary = EnrichmentReadinessSummary {
        command: "enrichment-readiness-check".to_owned(),
        ready_for_metadata_social_canary,
        ready_for_funding_bundle_canary,
        ready_for_any_enrichment,
        metadata_social_canary_possible_without_rpc,
        cache_dir_exists,
        ledger_exists,
        rpc_budget_config_present,
        metadata_fetch_budget_config_present,
        required_env_missing,
        canary_limits,
        vps_enrichment_disabled: !loaded.config.enrichment.run_on_vps
            && !loaded.config.edge_collector.allow_rpc_enrichment
            && !loaded.config.edge_collector.allow_metadata_fetch
            && !loaded.config.edge_collector.allow_social_fetch
            && !loaded.config.edge_collector.allow_wallet_history_rpc
            && !loaded.config.edge_collector.allow_bundle_enrichment_rpc,
        cache_dir: cache_dir.display().to_string(),
        ledger_path: ledger_path.display().to_string(),
        markdown_path: markdown_path.display().to_string(),
        json_path: json_path.display().to_string(),
    };
    let markdown = format!(
        "# Enrichment Readiness Check\n\n- ready_for_metadata_social_canary: {}\n- ready_for_funding_bundle_canary: {}\n- ready_for_any_enrichment: {}\n- metadata_social_canary_possible_without_rpc: {}\n- cache_dir_exists: {}\n- ledger_exists: {}\n- required_env_missing: {:?}\n- canary_limits: {:?}\n- vps_enrichment_disabled: {}\n",
        summary.ready_for_metadata_social_canary,
        summary.ready_for_funding_bundle_canary,
        summary.ready_for_any_enrichment,
        summary.metadata_social_canary_possible_without_rpc,
        summary.cache_dir_exists,
        summary.ledger_exists,
        summary.required_env_missing,
        summary.canary_limits,
        summary.vps_enrichment_disabled,
    );
    write_report(&markdown_path, &markdown)?;
    fs::write(&json_path, serde_json::to_vec_pretty(&summary)?)?;
    println!("{}", serde_json::to_string_pretty(&summary)?);
    Ok(())
}

fn write_r2_manifests_csv(loaded: &LoadedConfig) -> Result<(PathBuf, usize)> {
    let manifests = all_r2_manifest_paths(loaded)?;
    let mut rows = manifests
        .into_iter()
        .filter_map(|path| load_manifest(&path).ok().map(|manifest| (path, manifest)))
        .map(|(path, manifest)| R2ManifestExportRow {
            run_id: manifest.run_id.clone(),
            source_run_id: manifest.source_run_id.clone(),
            run_kind: manifest.run_kind.clone(),
            run_role: manifest.run_role.clone(),
            local_manifest_path: path.display().to_string(),
            remote_manifest_key: format!(
                "{}/{}/{}/artifact_manifest.json",
                loaded.config.r2.managed_prefix,
                loaded.config.r2.paths.manifests_prefix,
                manifest.run_id
            ),
            upload_attempted: manifest.upload_summary.attempted_count > 0,
            uploaded_count: manifest.upload_summary.uploaded_count,
            verified_count: manifest.upload_summary.verified_count,
            failed_count: manifest.upload_summary.failed_count,
            dry_run: manifest.upload_summary.dry_run,
            uploaded_at: manifest
                .artifacts
                .iter()
                .filter_map(|artifact| artifact.upload_time)
                .max(),
            pruned_local: manifest
                .pruning_summary
                .as_ref()
                .map(|summary| summary.local_prune_succeeded)
                .unwrap_or(false),
            errors: if manifest.upload_summary.failed_count > 0 {
                "upload_failed".to_owned()
            } else {
                String::new()
            },
        })
        .collect::<Vec<_>>();
    rows.sort_by(|left, right| left.run_id.cmp(&right.run_id));
    let path = export_r2_manifests_path(loaded);
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent)?;
    }
    let mut csv = String::from(
        "run_id,source_run_id,run_kind,run_role,local_manifest_path,remote_manifest_key,upload_attempted,uploaded_count,verified_count,failed_count,dry_run,uploaded_at,pruned_local,errors\n",
    );
    for row in &rows {
        csv.push_str(&format!(
            "{},{},{},{},{},{},{},{},{},{},{},{},{},{}\n",
            row.run_id,
            row.source_run_id.clone().unwrap_or_default(),
            row.run_kind,
            row.run_role,
            row.local_manifest_path,
            row.remote_manifest_key,
            row.upload_attempted,
            row.uploaded_count,
            row.verified_count,
            row.failed_count,
            row.dry_run,
            row.uploaded_at
                .map(|value| value.unix_timestamp_nanos().to_string())
                .unwrap_or_default(),
            row.pruned_local,
            row.errors
        ));
    }
    fs::write(&path, csv)?;
    Ok((path, rows.len()))
}

async fn export_r2_manifests_command(loaded: &LoadedConfig) -> Result<()> {
    let (path, row_count) = write_r2_manifests_csv(loaded)?;
    println!(
        "{}",
        serde_json::to_string_pretty(&json!({
            "command": "export-r2-manifests",
            "path": path.display().to_string(),
            "row_count": row_count,
        }))?
    );
    Ok(())
}

