fn env_value_present(name: &str) -> bool {
    std::env::var(name)
        .ok()
        .map(|value| !value.trim().is_empty())
        .unwrap_or(false)
}

fn parsed_env_file_value(path_values: &BTreeMap<String, String>, name: &str) -> Option<String> {
    path_values
        .get(name)
        .map(|value| value.trim().to_owned())
        .filter(|value| !value.is_empty())
        .filter(|value| !is_placeholder_env_value(value))
}

fn env_value_from_sources(name: &str, path_values: &BTreeMap<String, String>) -> Option<String> {
    std::env::var(name)
        .ok()
        .map(|value| value.trim().to_owned())
        .filter(|value| !value.is_empty())
        .or_else(|| parsed_env_file_value(path_values, name))
}

fn env_value_present_in_sources(name: &str, path_values: &BTreeMap<String, String>) -> bool {
    env_value_from_sources(name, path_values).is_some()
}

fn is_placeholder_env_value(value: &str) -> bool {
    let trimmed = value.trim();
    trimmed.is_empty()
        || trimmed == "<placeholder>"
        || trimmed == "<redacted>"
        || trimmed.contains("your-")
        || trimmed.contains("example")
        || trimmed.contains("replace-me")
}

fn parse_env_file(path: &Path) -> Result<BTreeMap<String, String>> {
    let raw = fs::read_to_string(path)
        .map_err(|error| anyhow!("failed to read env file {}: {error}", path.display()))?;
    let mut values = BTreeMap::new();
    for line in raw.lines() {
        let trimmed = line.trim();
        if trimmed.is_empty() || trimmed.starts_with('#') {
            continue;
        }
        let Some((key, value)) = trimmed.split_once('=') else {
            continue;
        };
        let clean_key = key.trim();
        if clean_key.is_empty() {
            continue;
        }
        let clean_value = value.trim().trim_matches('"').trim_matches('\'').to_owned();
        values.insert(clean_key.to_owned(), clean_value);
    }
    Ok(values)
}

struct EnvFileOverlayGuard {
    previous_values: Vec<(String, Option<String>)>,
}

impl Drop for EnvFileOverlayGuard {
    fn drop(&mut self) {
        for (key, previous) in self.previous_values.iter().rev() {
            match previous {
                Some(value) => {
                    // CLI commands are single-process/single-command invocations here; restore the
                    // process environment so tests and follow-on code do not inherit the overlay.
                    unsafe { std::env::set_var(key, value) };
                }
                None => {
                    // See the set_var note above. The guard only touches keys it set itself.
                    unsafe { std::env::remove_var(key) };
                }
            }
        }
    }
}

fn apply_env_file_overlay(
    loaded: &LoadedConfig,
    env_file: Option<&str>,
) -> Result<Option<EnvFileOverlayGuard>> {
    let Some(path) = env_file else {
        return Ok(None);
    };
    let values = parse_env_file(&resolve_user_path(loaded, path))?;
    let mut previous_values = Vec::new();
    for (key, value) in values {
        let clean_value = value.trim();
        if clean_value.is_empty() || is_placeholder_env_value(clean_value) {
            continue;
        }
        if std::env::var(&key)
            .ok()
            .map(|existing| !existing.trim().is_empty())
            .unwrap_or(false)
        {
            continue;
        }
        previous_values.push((key.clone(), std::env::var(&key).ok()));
        // This command-line tool runs one selected operation per process. We apply the env-file
        // overlay before constructing clients so code that reads std::env sees the same values that
        // bootstrap validation already accepted.
        unsafe { std::env::set_var(key, clean_value) };
    }
    Ok(Some(EnvFileOverlayGuard { previous_values }))
}

fn valid_endpoint_scheme(value: &str) -> bool {
    value.starts_with("http://") || value.starts_with("https://")
}

fn resolve_report_root(
    loaded: &LoadedConfig,
    default_subdir: &str,
    run_id: &str,
    override_dir: Option<&str>,
) -> PathBuf {
    if let Some(path) = override_dir {
        return resolve_user_path(loaded, path).join(run_id);
    }
    storage_engine(loaded)
        .map(|store| store.layout().report_dir.join(default_subdir).join(run_id))
        .unwrap_or_else(|_| {
            Path::new(&loaded.config.storage.root)
                .join("reports")
                .join(default_subdir)
                .join(run_id)
        })
}

fn redacted_deshred_config(
    loaded: &LoadedConfig,
    provider_name_override: Option<&str>,
) -> serde_json::Value {
    let deshred = loaded.config.ingest.deshred.clone().unwrap_or_default();
    let endpoint_env = if deshred.endpoint_env.trim().is_empty() {
        "GEYSER_ENDPOINT".to_owned()
    } else {
        deshred.endpoint_env
    };
    let auth_token_env = if deshred.auth_token_env.trim().is_empty() {
        "GEYSER_AUTH_TOKEN".to_owned()
    } else {
        deshred.auth_token_env
    };
    json!({
        "provider_name": provider_name_override
            .filter(|value| !value.trim().is_empty())
            .map(ToOwned::to_owned)
            .or_else(|| (!loaded.config.provider.name.trim().is_empty()).then(|| loaded.config.provider.name.clone())),
        "enabled": deshred.enabled,
        "required": deshred.required,
        "endpoint_configured": deshred_endpoint_value(loaded).is_some(),
        "endpoint_env": endpoint_env,
        "auth_required": deshred.auth_required,
        "auth_token_env": auth_token_env.clone(),
        "auth_token_present": env_value_present(&auth_token_env),
        "auth_metadata_key_configured": !deshred.auth_metadata_key.trim().is_empty(),
        "auth_metadata_key": if deshred.auth_metadata_key.trim().is_empty() { "x-token".to_owned() } else { deshred.auth_metadata_key },
        "subscribe_transactions": deshred.subscribe_transactions,
        "program_filters_from_pump_ids": deshred.program_filters_from_pump_ids,
        "connect_timeout_ms": deshred.connect_timeout_ms,
        "request_timeout_ms": deshred.request_timeout_ms,
        "keepalive_interval_ms": deshred.keepalive_interval_ms,
        "reconnect_backoff_ms": deshred.reconnect_backoff_ms,
        "max_reconnect_backoff_ms": deshred.max_reconnect_backoff_ms,
        "max_reconnect_attempts": deshred.max_reconnect_attempts,
        "fail_if_unsupported": deshred.fail_if_unsupported,
        "max_decoded_message_size": deshred.max_decoded_message_size,
    })
}

fn load_provider_compatibility_records(
    loaded: &LoadedConfig,
) -> Result<Vec<ProviderCompatibilityRecord>> {
    let path = provider_compatibility_path(loaded);
    if !path.exists() {
        return Ok(Vec::new());
    }
    Ok(serde_json::from_slice(&fs::read(path)?)?)
}

fn write_provider_compatibility_records(
    loaded: &LoadedConfig,
    records: &[ProviderCompatibilityRecord],
) -> Result<()> {
    let path = provider_compatibility_path(loaded);
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent)?;
    }
    fs::write(path, serde_json::to_vec_pretty(records)?)?;
    Ok(())
}

fn append_provider_compatibility_record(
    loaded: &LoadedConfig,
    mut record: ProviderCompatibilityRecord,
) -> Result<()> {
    if !loaded.config.provider.record_compatibility {
        return Ok(());
    }
    let mut records = load_provider_compatibility_records(loaded)?;
    let existing_same_provider = records
        .iter()
        .filter(|existing| {
            existing.endpoint_host_hash == record.endpoint_host_hash
                && existing.provider_name == record.provider_name
        })
        .cloned()
        .collect::<Vec<_>>();
    let mut history = existing_same_provider
        .iter()
        .flat_map(|existing| existing.provider_status_history.clone())
        .collect::<Vec<_>>();
    history.push(record.subscribe_deshred_result.clone());
    record.provider_status_history = history;
    record.total_smoke_attempts = existing_same_provider
        .iter()
        .map(|existing| existing.total_smoke_attempts)
        .max()
        .unwrap_or(0)
        .saturating_add(1);
    let stream_success = matches!(
        record.subscribe_deshred_result.as_str(),
        "updates_received" | "zero_updates" | "connected"
    );
    record.successful_stream_attempts = existing_same_provider
        .iter()
        .map(|existing| existing.successful_stream_attempts)
        .max()
        .unwrap_or(0)
        .saturating_add(u64::from(stream_success));
    record.failed_stream_attempts = existing_same_provider
        .iter()
        .map(|existing| existing.failed_stream_attempts)
        .max()
        .unwrap_or(0)
        .saturating_add(u64::from(!stream_success));
    record.max_updates_observed = existing_same_provider
        .iter()
        .map(|existing| existing.max_updates_observed)
        .max()
        .unwrap_or(0)
        .max(record.max_updates_observed);
    record.max_duration_connected_ms = existing_same_provider
        .iter()
        .map(|existing| existing.max_duration_connected_ms)
        .max()
        .unwrap_or(0)
        .max(record.max_duration_connected_ms);
    record.last_successful_deshred_stream_at = if stream_success {
        Some(record.tested_at)
    } else {
        existing_same_provider
            .iter()
            .filter_map(|existing| existing.last_successful_deshred_stream_at)
            .max()
    };
    record.last_unimplemented_at = if record.subscribe_deshred_result == "unimplemented" {
        Some(record.tested_at)
    } else {
        existing_same_provider
            .iter()
            .filter_map(|existing| existing.last_unimplemented_at)
            .max()
    };
    record.last_auth_rejected_at = if record.subscribe_deshred_result == "auth_rejected" {
        Some(record.tested_at)
    } else {
        existing_same_provider
            .iter()
            .filter_map(|existing| existing.last_auth_rejected_at)
            .max()
    };
    record.last_zero_update_at = if record.subscribe_deshred_result == "zero_updates" {
        Some(record.tested_at)
    } else {
        existing_same_provider
            .iter()
            .filter_map(|existing| existing.last_zero_update_at)
            .max()
    };
    record.last_stream_error_at = if matches!(
        record.subscribe_deshred_result.as_str(),
        "stream_error" | "connection_failed"
    ) {
        Some(record.tested_at)
    } else {
        existing_same_provider
            .iter()
            .filter_map(|existing| existing.last_stream_error_at)
            .max()
    };
    record.supports_deshred_confidence = if stream_success {
        "yes".to_owned()
    } else if record.subscribe_deshred_result == "unimplemented" {
        "likely_no".to_owned()
    } else if !record.proto_support || !record.client_support {
        "no".to_owned()
    } else if record.subscribe_deshred_result == "not_attempted_missing_endpoint" {
        existing_same_provider
            .iter()
            .rev()
            .find_map(|existing| {
                (!existing.supports_deshred_confidence.is_empty())
                    .then(|| existing.supports_deshred_confidence.clone())
            })
            .unwrap_or_else(|| "unknown".to_owned())
    } else {
        "maybe".to_owned()
    };
    records.push(record);
    records.sort_by(|left, right| {
        left.tested_at
            .cmp(&right.tested_at)
            .then_with(|| left.endpoint_host_hash.cmp(&right.endpoint_host_hash))
            .then_with(|| {
                left.subscribe_deshred_result
                    .cmp(&right.subscribe_deshred_result)
            })
    });
    write_provider_compatibility_records(loaded, &records)
}

fn provider_compatibility_record_from_smoke(
    loaded: &LoadedConfig,
    capability: &runtime::DeshredCapability,
    summary: &runtime::DeshredProviderSmokeSummary,
    smoke_run_id: Option<&str>,
    dry_run_id: Option<&str>,
    provider_name_override: Option<&str>,
) -> ProviderCompatibilityRecord {
    let provider_name = provider_name_override
        .filter(|value| !value.trim().is_empty())
        .map(ToOwned::to_owned)
        .or_else(|| {
            (!loaded.config.provider.name.trim().is_empty())
                .then(|| loaded.config.provider.name.clone())
        });
    let tested_at = OffsetDateTime::now_utc();
    let stream_success = matches!(
        summary.provider_status.as_str(),
        "updates_received" | "zero_updates" | "connected"
    );
    ProviderCompatibilityRecord {
        provider_name,
        endpoint_host_hash: endpoint_host_hash(deshred_endpoint_value(loaded).as_deref()),
        tested_at,
        smoke_run_id: smoke_run_id.map(ToOwned::to_owned),
        dry_run_id: dry_run_id.map(ToOwned::to_owned),
        provider_status_history: vec![summary.provider_status.clone()],
        last_successful_deshred_stream_at: stream_success.then_some(tested_at),
        last_unimplemented_at: (summary.provider_status == "unimplemented").then_some(tested_at),
        last_auth_rejected_at: (summary.provider_status == "auth_rejected").then_some(tested_at),
        last_zero_update_at: (summary.provider_status == "zero_updates").then_some(tested_at),
        last_stream_error_at: matches!(
            summary.provider_status.as_str(),
            "stream_error" | "connection_failed"
        )
        .then_some(tested_at),
        total_smoke_attempts: 1,
        successful_stream_attempts: u64::from(stream_success),
        failed_stream_attempts: u64::from(!stream_success),
        max_updates_observed: summary.updates_received,
        max_duration_connected_ms: summary.duration_seconds.saturating_mul(1000),
        supports_deshred_confidence: if stream_success {
            "yes".to_owned()
        } else if summary.provider_status == "unimplemented" {
            "likely_no".to_owned()
        } else if !capability.supported_by_proto || !capability.supported_by_client {
            "no".to_owned()
        } else if summary.provider_status == "not_attempted_missing_endpoint" {
            "unknown".to_owned()
        } else {
            "maybe".to_owned()
        },
        proto_support: capability.supported_by_proto,
        client_support: capability.supported_by_client,
        subscribe_deshred_attempted: capability.can_enable && summary.endpoint_configured,
        subscribe_deshred_result: summary.provider_status.clone(),
        auth_metadata_key_used: loaded
            .config
            .ingest
            .deshred
            .clone()
            .unwrap_or_default()
            .auth_metadata_key,
        supports_program_filters: capability.supports_program_filters,
        supports_loaded_addresses: capability.exposes_loaded_addresses,
        supports_signature: capability.exposes_signature,
        supports_slot: capability.exposes_slot,
        supports_raw_transaction: capability.exposes_raw_transaction,
        supports_instruction_data: capability.exposes_instruction_data,
        supports_ping: loaded
            .config
            .ingest
            .deshred
            .clone()
            .unwrap_or_default()
            .keepalive_interval_ms
            > 0,
        observed_updates: summary.updates_received,
        observed_errors: summary.errors.clone(),
        notes: summary.limitations.clone(),
        schema_version: common::SCHEMA_VERSION,
    }
}

fn write_provider_compatibility_csv(
    loaded: &LoadedConfig,
    path: &Path,
    records: &[ProviderCompatibilityRecord],
) -> Result<()> {
    let mut file = create_csv_file(path)?;
    writeln!(
        file,
        "provider_name,endpoint_host_hash,tested_at,smoke_run_id,dry_run_id,provider_status_history,last_successful_deshred_stream_at,last_unimplemented_at,last_auth_rejected_at,last_zero_update_at,last_stream_error_at,total_smoke_attempts,successful_stream_attempts,failed_stream_attempts,max_updates_observed,max_duration_connected_ms,supports_deshred_confidence,proto_support,client_support,subscribe_deshred_attempted,subscribe_deshred_result,auth_metadata_key_used,supports_program_filters,supports_loaded_addresses,supports_signature,supports_slot,supports_raw_transaction,supports_instruction_data,supports_ping,observed_updates,observed_errors,notes,schema_version"
    )?;
    let mut sorted = records.to_vec();
    sorted.sort_by(|left, right| {
        left.tested_at
            .cmp(&right.tested_at)
            .then_with(|| left.endpoint_host_hash.cmp(&right.endpoint_host_hash))
            .then_with(|| {
                left.subscribe_deshred_result
                    .cmp(&right.subscribe_deshred_result)
            })
    });
    for record in sorted {
        let row = vec![
            csv_field(record.provider_name.as_deref().unwrap_or("")),
            csv_field(&record.endpoint_host_hash),
            record.tested_at.unix_timestamp_nanos().to_string(),
            csv_field(record.smoke_run_id.as_deref().unwrap_or("")),
            csv_field(record.dry_run_id.as_deref().unwrap_or("")),
            csv_field(&record.provider_status_history.join("|")),
            csv_field(
                &record
                    .last_successful_deshred_stream_at
                    .map(|value| value.unix_timestamp_nanos().to_string())
                    .unwrap_or_default(),
            ),
            csv_field(
                &record
                    .last_unimplemented_at
                    .map(|value| value.unix_timestamp_nanos().to_string())
                    .unwrap_or_default(),
            ),
            csv_field(
                &record
                    .last_auth_rejected_at
                    .map(|value| value.unix_timestamp_nanos().to_string())
                    .unwrap_or_default(),
            ),
            csv_field(
                &record
                    .last_zero_update_at
                    .map(|value| value.unix_timestamp_nanos().to_string())
                    .unwrap_or_default(),
            ),
            csv_field(
                &record
                    .last_stream_error_at
                    .map(|value| value.unix_timestamp_nanos().to_string())
                    .unwrap_or_default(),
            ),
            record.total_smoke_attempts.to_string(),
            record.successful_stream_attempts.to_string(),
            record.failed_stream_attempts.to_string(),
            record.max_updates_observed.to_string(),
            record.max_duration_connected_ms.to_string(),
            csv_field(&record.supports_deshred_confidence),
            record.proto_support.to_string(),
            record.client_support.to_string(),
            record.subscribe_deshred_attempted.to_string(),
            csv_field(&record.subscribe_deshred_result),
            csv_field(&record.auth_metadata_key_used),
            record.supports_program_filters.to_string(),
            record.supports_loaded_addresses.to_string(),
            record.supports_signature.to_string(),
            record.supports_slot.to_string(),
            record.supports_raw_transaction.to_string(),
            record.supports_instruction_data.to_string(),
            record.supports_ping.to_string(),
            record.observed_updates.to_string(),
            csv_field(&record.observed_errors.join("|")),
            csv_field(&record.notes.join("|")),
            record.schema_version.to_string(),
        ];
        writeln!(file, "{}", row.join(","))?;
    }
    let _ = loaded;
    Ok(())
}

fn render_operator_runbook(
    command: &str,
    endpoint_env: &str,
    endpoint_present: bool,
    auth_env: &str,
    auth_present: bool,
    summary: &runtime::DeshredProviderSmokeSummary,
) -> String {
    let next_step = match summary.provider_status.as_str() {
        "not_attempted_missing_endpoint" => {
            "Set the endpoint env var, then rerun smoke-deshred-provider in strict mode."
        }
        "unimplemented" => {
            "Treat SubscribeDeshred as unsupported for this provider until they expose it."
        }
        "auth_rejected" => "Fix auth metadata or token configuration, then rerun smoke.",
        "zero_updates" => {
            "Retry with a longer duration or a busier market window to confirm zero-update behavior."
        }
        "updates_received" => {
            "Run provider-dry-run or a short live-data paper collection to validate reconciliation."
        }
        "stream_error" | "connection_failed" => {
            "Check provider reachability and retry the smoke harness."
        }
        _ => "Inspect the smoke JSON and provider compatibility report before the next attempt.",
    };
    format!(
        "# Operator Next Steps\n\n- sanitized_command: `{}`\n- expected_env_vars: {} {}\n- endpoint_env_present: {}\n- auth_env_present: {}\n- provider_status: {}\n- next_recommended_action: {}\n",
        command,
        endpoint_env,
        auth_env,
        endpoint_present,
        auth_present,
        summary.provider_status,
        next_step,
    )
}

fn raw_shred_capability_payload(loaded: &LoadedConfig) -> serde_json::Value {
    let feature_flag_compiled = cfg!(feature = "production-shred-decoder");
    let production_mode_allowed = loaded.config.early_intent.allow_production_raw_shred;
    let production_supported = feature_flag_compiled && production_mode_allowed;
    let reason_if_unsupported = if production_supported {
        None
    } else {
        Some(
            "production raw shred decoder is not compiled; enable feature production-shred-decoder with a supported backend"
                .to_owned(),
        )
    };
    json!({
        "feature_flag_compiled": feature_flag_compiled,
        "backend_available": feature_flag_compiled,
        "fixture_decoder_available": true,
        "production_mode_allowed": production_mode_allowed,
        "production_supported": production_supported,
        "reason_if_unsupported": reason_if_unsupported,
    })
}

fn write_empty_rpc_ledger_files(report_root: &Path) -> Result<String> {
    fs::create_dir_all(report_root)?;
    let json_path = report_root.join("rpc_ledger.json");
    let csv_path = report_root.join("rpc_ledger.csv");
    fs::write(&json_path, b"[]")?;
    write_rpc_ledger_csv(&csv_path, &[])?;
    Ok(json_path.display().to_string())
}

