fn disk_preflight_markdown_path(loaded: &LoadedConfig) -> PathBuf {
    autopilot_report_root(loaded).join("disk_preflight.md")
}

fn run_metadata_sorted(loaded: &LoadedConfig) -> Result<Vec<StoredRecord<storage::RunMetadata>>> {
    let mut records = storage_engine(loaded)?.list_runs()?;
    records.sort_by(|left, right| {
        left.record
            .created_at_wall_time
            .cmp(&right.record.created_at_wall_time)
            .then_with(|| left.record.run_id.cmp(&right.record.run_id))
    });
    Ok(records)
}

