fn derive_associated_token_account(
    owner: &str,
    mint: &str,
    token_program_id: &'static str,
) -> Option<String> {
    let owner = Pubkey::from_str(owner).ok()?;
    let mint = Pubkey::from_str(mint).ok()?;
    let token_program = Pubkey::from_str(token_program_id).ok()?;
    let associated_token_program = Pubkey::from_str(ASSOCIATED_TOKEN_PROGRAM_ID).ok()?;
    let (address, _) = Pubkey::find_program_address(
        &[owner.as_ref(), token_program.as_ref(), mint.as_ref()],
        &associated_token_program,
    );
    Some(address.to_string())
}

fn associated_curve_analysis(events: &[NormalizedEvent]) -> AssociatedCurveAnalysis {
    let Some(payload) = events.iter().find_map(|event| match &event.payload {
        EventPayload::TokenCreated(payload) => Some(payload),
        _ => None,
    }) else {
        return AssociatedCurveAnalysis {
            observed: None,
            derived: None,
            token_program_id: None,
            source: "unavailable_provider_or_idl",
            confidence: "unavailable",
            matches_observed_account_list: None,
            observed_matches_derived: None,
            unavailable_reason: "missing_due_to_token_not_initialized",
        };
    };
    let mint = payload.mint.to_string();
    let curve = payload.bonding_curve_account.to_string();
    let observed = payload
        .associated_bonding_curve_account
        .as_ref()
        .map(ToString::to_string);
    if mint.is_empty() || curve.is_empty() {
        return AssociatedCurveAnalysis {
            observed,
            derived: None,
            token_program_id: None,
            source: "unavailable_provider_or_idl",
            confidence: "unavailable",
            matches_observed_account_list: None,
            observed_matches_derived: None,
            unavailable_reason: "missing_mint_or_bonding_curve_account",
        };
    }
    let raw_accounts = payload
        .raw_account_list
        .iter()
        .map(ToString::to_string)
        .collect::<BTreeSet<_>>();
    let candidates = [
        (
            SPL_TOKEN_PROGRAM_ID,
            derive_associated_token_account(&curve, &mint, SPL_TOKEN_PROGRAM_ID),
        ),
        (
            TOKEN_2022_PROGRAM_ID,
            derive_associated_token_account(&curve, &mint, TOKEN_2022_PROGRAM_ID),
        ),
    ];
    let matched = candidates
        .iter()
        .find_map(|(program, candidate)| {
            candidate
                .as_ref()
                .filter(|value| raw_accounts.contains(*value))
                .map(|value| (*program, value.clone(), true))
        })
        .or_else(|| {
            candidates.iter().find_map(|(program, candidate)| {
                candidate.clone().map(|value| (*program, value, false))
            })
        });
    let (token_program_id, derived, matches_observed_account_list) =
        if let Some((program, derived, matches)) = matched {
            (Some(program), Some(derived), Some(matches))
        } else {
            (None, None, None)
        };
    let observed_matches_derived = observed
        .as_ref()
        .zip(derived.as_ref())
        .map(|(observed, derived)| observed == derived);
    let source = if observed.is_some() {
        "official_idl_account"
    } else if derived.is_some() {
        "official_idl_pda_derivation"
    } else {
        "unavailable_missing_required_seed"
    };
    let confidence = if observed.is_some() {
        "observed"
    } else if derived.is_some() {
        "deterministic"
    } else {
        "unavailable"
    };
    AssociatedCurveAnalysis {
        observed,
        derived,
        token_program_id,
        source,
        confidence,
        matches_observed_account_list,
        observed_matches_derived,
        unavailable_reason: if confidence == "unavailable" {
            "missing_mint_or_bonding_curve_account"
        } else {
            ""
        },
    }
}

fn token_supply_analysis(events: &[NormalizedEvent]) -> TokenSupplyAnalysis {
    let has_create = events
        .iter()
        .any(|event| matches!(event.payload, EventPayload::TokenCreated(_)));
    let decimals = events
        .iter()
        .find_map(|event| match &event.payload {
            EventPayload::BondingCurveUpdate(payload) => payload.token_decimals,
            EventPayload::HolderBalanceUpdate(payload) => payload.token_decimals,
            _ => None,
        })
        .unwrap_or(common::DEFAULT_PUMP_TOKEN_DECIMALS);
    let stream_observed_raw = events.iter().find_map(|event| match &event.payload {
        EventPayload::TokenCreated(payload) => payload.initial_supply,
        _ => None,
    });
    let bonding_curve_observed_raw = events.iter().find_map(|event| match &event.payload {
        EventPayload::BondingCurveUpdate(payload) => payload.token_total_supply_raw,
        _ => None,
    });
    let protocol_constant_ui = Decimal::from(common::PUMP_TOTAL_SUPPLY_UI);
    let protocol_constant_raw = common::ui_tokens_to_raw(protocol_constant_ui, decimals);
    let selected_raw = bonding_curve_observed_raw
        .or(stream_observed_raw)
        .or_else(|| has_create.then_some(protocol_constant_raw));
    let selected_ui = selected_raw.map(|raw| common::raw_tokens_to_ui(raw, decimals));
    let (source, confidence) = if bonding_curve_observed_raw.is_some() {
        ("bonding_curve_observed", "observed")
    } else if stream_observed_raw.is_some() {
        ("stream_observed", "observed")
    } else if has_create {
        ("protocol_constant", "protocol_constant")
    } else {
        ("unavailable", "unavailable")
    };
    TokenSupplyAnalysis {
        stream_observed_raw,
        bonding_curve_observed_raw,
        protocol_constant_raw: has_create.then_some(protocol_constant_raw),
        protocol_constant_ui: has_create.then_some(protocol_constant_ui),
        rpc_verified_raw: None,
        selected_raw,
        selected_ui,
        decimals,
        source,
        confidence,
        rpc_unavailable_reason: "unavailable_blocked_by_rpc_budget",
    }
}

fn sol_balance_analysis(
    events: &[NormalizedEvent],
    related_signatures: &BTreeSet<String>,
) -> SolBalanceAnalysis {
    let related_observed = events
        .iter()
        .filter_map(|event| {
            if let EventPayload::ObservedTransaction(payload) = &event.payload {
                let related = payload
                    .signature_hint
                    .as_ref()
                    .map(|sig| related_signatures.contains(sig))
                    .unwrap_or(true);
                related.then_some(payload)
            } else {
                None
            }
        })
        .collect::<Vec<_>>();
    let sample = related_observed.first();
    let pre_observed = related_observed
        .iter()
        .any(|payload| !payload.pre_sol_balances_lamports.is_empty());
    let post_observed = related_observed
        .iter()
        .any(|payload| !payload.post_sol_balances_lamports.is_empty());
    let quote_amount_lamports_from_delta = events.iter().find_map(|event| match &event.payload {
        EventPayload::PumpBuy(payload)
            if payload.status != common::TransactionStatus::Failed
                && payload.quote_in > Decimal::ZERO =>
        {
            Some(payload.quote_in)
        }
        EventPayload::PumpSell(payload)
            if payload.status != common::TransactionStatus::Failed
                && payload.quote_out > Decimal::ZERO =>
        {
            Some(payload.quote_out)
        }
        _ => None,
    });
    let quote_amount_sol_from_delta = quote_amount_lamports_from_delta.map(common::lamports_to_sol);
    let tx_fee_lamports =
        sample.and_then(|payload| payload.tx_fee_lamports.as_ref().map(|fee| fee.0));
    let priority_fee_lamports = sample.and_then(|payload| {
        payload
            .estimated_priority_fee_lamports
            .as_ref()
            .map(|fee| fee.0)
    });
    let trade_quote_source = if pre_observed && post_observed {
        "transaction_meta_pre_post_balance"
    } else if quote_amount_lamports_from_delta.is_some() {
        "wallet_lamport_delta"
    } else {
        "unavailable_provider_meta"
    };
    let trade_quote_source_confidence = if pre_observed && post_observed {
        "observed"
    } else if quote_amount_lamports_from_delta.is_some() {
        "fallback"
    } else {
        "unavailable"
    };
    SolBalanceAnalysis {
        pre_observed,
        post_observed,
        pre_balance_count: sample
            .map(|payload| payload.pre_sol_balances_lamports.len())
            .unwrap_or(0),
        post_balance_count: sample
            .map(|payload| payload.post_sol_balances_lamports.len())
            .unwrap_or(0),
        sample_pre_lamports: sample.and_then(|payload| {
            payload
                .pre_sol_balances_lamports
                .first()
                .map(|lamports| lamports.0)
        }),
        sample_post_lamports: sample.and_then(|payload| {
            payload
                .post_sol_balances_lamports
                .first()
                .map(|lamports| lamports.0)
        }),
        quote_amount_lamports_from_delta,
        quote_amount_sol_from_delta,
        tx_fee_lamports,
        priority_fee_lamports,
        trade_quote_source,
        trade_quote_source_confidence,
        unavailable_reason: if trade_quote_source == "unavailable_provider_meta" {
            "unavailable_provider_meta"
        } else {
            ""
        },
    }
}

fn event_mint_string(event: &NormalizedEvent) -> Option<String> {
    event.mint().map(|mint| mint.to_string())
}

fn event_signature_string(event: &NormalizedEvent) -> Option<String> {
    event.signature().map(ToOwned::to_owned)
}

fn event_received_ts(event: &NormalizedEvent) -> String {
    event
        .meta
        .block_time
        .or(Some(event.meta.received_at_wall_time))
        .map(|value| value.to_string())
        .unwrap_or_default()
}

fn is_successful_launch_create(event: &NormalizedEvent) -> bool {
    matches!(
        &event.payload,
        EventPayload::TokenCreated(payload) if payload.status != common::TransactionStatus::Failed
    )
}

fn is_successful_trade(event: &NormalizedEvent) -> bool {
    matches!(
        &event.payload,
        EventPayload::PumpBuy(payload) if payload.status != common::TransactionStatus::Failed
    ) || matches!(
        &event.payload,
        EventPayload::PumpSell(payload) if payload.status != common::TransactionStatus::Failed
    )
}

fn fresh_field_present(
    field: &str,
    events: &[NormalizedEvent],
    related_signatures: &BTreeSet<String>,
) -> bool {
    match field {
        "launch_create_signature" => events.iter().any(|e| matches!(e.payload, EventPayload::TokenCreated(_)) && event_signature_string(e).is_some()),
        "launch_create_slot" => events.iter().any(|e| matches!(e.payload, EventPayload::TokenCreated(_)) && e.meta.slot > 0),
        "launch_create_timestamp" => events.iter().any(|e| matches!(e.payload, EventPayload::TokenCreated(_)) && (e.meta.block_time.is_some() || e.meta.received_at_wall_time != OffsetDateTime::UNIX_EPOCH)),
        "mint" => events.iter().any(|e| matches!(e.payload, EventPayload::TokenCreated(_)) && event_mint_string(e).is_some()),
        "creator_dev_wallet" => events.iter().any(|e| matches!(&e.payload, EventPayload::TokenCreated(p) if !p.creator_wallet.to_string().is_empty())),
        "bonding_curve_account" => events.iter().any(|e| matches!(&e.payload, EventPayload::TokenCreated(p) if !p.bonding_curve_account.to_string().is_empty())),
        "associated_bonding_curve_account_observed" => events.iter().any(|e| matches!(&e.payload, EventPayload::TokenCreated(p) if p.associated_bonding_curve_account.is_some())),
        "associated_bonding_curve_account_derived" => {
            let analysis = associated_curve_analysis(events);
            analysis.derived.is_some() && analysis.observed_matches_derived != Some(false)
        }
        "token_decimals" => events.iter().any(|e| matches!(&e.payload, EventPayload::BondingCurveUpdate(p) if p.token_decimals.is_some()) || matches!(&e.payload, EventPayload::HolderBalanceUpdate(p) if p.token_decimals.is_some())),
        "token_total_supply_stream_observed" => events.iter().any(|e| matches!(&e.payload, EventPayload::TokenCreated(p) if p.initial_supply.is_some())),
        "token_total_supply_bonding_curve_observed" => events.iter().any(|e| matches!(&e.payload, EventPayload::BondingCurveUpdate(p) if p.token_total_supply_raw.is_some())),
        "token_total_supply_protocol_constant" => events.iter().any(|e| matches!(e.payload, EventPayload::TokenCreated(_))),
        "token_total_supply_rpc_verified" => false,
        "token_total_supply_selected" => token_supply_analysis(events).selected_raw.is_some(),
        "virtual_sol_reserves" => events.iter().any(|e| matches!(&e.payload, EventPayload::BondingCurveUpdate(p) if p.virtual_quote_reserves > Decimal::ZERO) || matches!(&e.payload, EventPayload::TokenCreated(p) if p.initial_virtual_quote_reserves.is_some())),
        "virtual_token_reserves" => events.iter().any(|e| matches!(&e.payload, EventPayload::BondingCurveUpdate(p) if p.virtual_token_reserves > Decimal::ZERO) || matches!(&e.payload, EventPayload::TokenCreated(p) if p.initial_virtual_token_reserves.is_some())),
        "real_sol_reserves" => events.iter().any(|e| matches!(&e.payload, EventPayload::BondingCurveUpdate(p) if p.real_quote_reserves >= Decimal::ZERO) || matches!(&e.payload, EventPayload::TokenCreated(p) if p.initial_real_quote_reserves.is_some())),
        "real_token_reserves" => events.iter().any(|e| matches!(&e.payload, EventPayload::BondingCurveUpdate(p) if p.real_token_reserves >= Decimal::ZERO) || matches!(&e.payload, EventPayload::TokenCreated(p) if p.initial_real_token_reserves.is_some())),
        "curve_complete_flag" => events.iter().any(|e| matches!(&e.payload, EventPayload::BondingCurveUpdate(p) if p.curve_complete_flag.is_some())),
        "curve_progress_pct" => events.iter().any(|e| matches!(&e.payload, EventPayload::BondingCurveUpdate(p) if p.curve_progress_pct.is_some())),
        "buy_sell_direction" => events.iter().any(is_successful_trade),
        "token_amount_raw_or_ui" => events.iter().any(|e| matches!(&e.payload, EventPayload::PumpBuy(p) if p.status != common::TransactionStatus::Failed && p.token_out > Decimal::ZERO) || matches!(&e.payload, EventPayload::PumpSell(p) if p.status != common::TransactionStatus::Failed && p.token_in > Decimal::ZERO)),
        "quote_amount_lamports_or_sol" => events.iter().any(|e| matches!(&e.payload, EventPayload::PumpBuy(p) if p.status != common::TransactionStatus::Failed && p.quote_in > Decimal::ZERO) || matches!(&e.payload, EventPayload::PumpSell(p) if p.status != common::TransactionStatus::Failed && p.quote_out > Decimal::ZERO)),
        "signer_or_owner_wallet" => events.iter().any(|e| matches!(&e.payload, EventPayload::PumpBuy(p) if !p.buyer.to_string().is_empty()) || matches!(&e.payload, EventPayload::PumpSell(p) if !p.seller.to_string().is_empty()) || matches!(&e.payload, EventPayload::HolderBalanceUpdate(p) if !p.owner_wallet.to_string().is_empty()) || matches!(&e.payload, EventPayload::ObservedTransaction(p) if p.signer.is_some())),
        "token_account" => events.iter().any(|e| matches!(&e.payload, EventPayload::HolderBalanceUpdate(p) if !p.token_account.to_string().is_empty())),
        "pre_post_token_balance" => events.iter().any(|e| matches!(&e.payload, EventPayload::HolderBalanceUpdate(p) if p.old_balance.is_some() || p.new_balance >= Decimal::ZERO)),
        "pre_sol_balance_stream_observed" => events.iter().any(|e| matches!(&e.payload, EventPayload::ObservedTransaction(p) if !p.pre_sol_balances_lamports.is_empty() && p.signature_hint.as_ref().map(|sig| related_signatures.contains(sig)).unwrap_or(true))),
        "post_sol_balance_stream_observed" => events.iter().any(|e| matches!(&e.payload, EventPayload::ObservedTransaction(p) if !p.post_sol_balances_lamports.is_empty() && p.signature_hint.as_ref().map(|sig| related_signatures.contains(sig)).unwrap_or(true))),
        "quote_amount_lamports_from_delta" => events.iter().any(|e| matches!(&e.payload, EventPayload::PumpBuy(p) if p.status != common::TransactionStatus::Failed && p.quote_in > Decimal::ZERO) || matches!(&e.payload, EventPayload::PumpSell(p) if p.status != common::TransactionStatus::Failed && p.quote_out > Decimal::ZERO)),
        "transaction_signature" => events.iter().any(|e| event_signature_string(e).is_some()),
        "instruction_type" => events.iter().any(|e| matches!(event_kind(e), "token_created" | "pump_buy" | "pump_sell" | "bonding_curve_update" | "holder_balance_update")),
        "instruction_shape_hash" => events.iter().any(|e| matches!(&e.payload, EventPayload::ObservedTransaction(p) if p.instruction_shape_hash.is_some() && p.signature_hint.as_ref().map(|sig| related_signatures.contains(sig)).unwrap_or(true))),
        "account_list_hash" => events.iter().any(|e| matches!(&e.payload, EventPayload::ObservedTransaction(p) if p.account_list_hash.is_some() && p.signature_hint.as_ref().map(|sig| related_signatures.contains(sig)).unwrap_or(true))),
        "compute_unit_limit" => events.iter().any(|e| matches!(&e.payload, EventPayload::PumpBuy(p) if p.compute_unit_limit.is_some()) || matches!(&e.payload, EventPayload::PumpSell(p) if p.compute_unit_limit.is_some()) || matches!(&e.payload, EventPayload::ObservedTransaction(p) if p.compute_unit_limit.is_some())),
        "compute_unit_price" => events.iter().any(|e| matches!(&e.payload, EventPayload::PumpBuy(p) if p.compute_unit_price.is_some()) || matches!(&e.payload, EventPayload::PumpSell(p) if p.compute_unit_price.is_some()) || matches!(&e.payload, EventPayload::ObservedTransaction(p) if p.compute_unit_price.is_some())),
        "priority_fee" => events.iter().any(|e| matches!(&e.payload, EventPayload::PumpBuy(p) if p.estimated_priority_fee_lamports.is_some()) || matches!(&e.payload, EventPayload::PumpSell(p) if p.estimated_priority_fee_lamports.is_some()) || matches!(&e.payload, EventPayload::ObservedTransaction(p) if p.estimated_priority_fee_lamports.is_some())),
        "tx_fee" => events.iter().any(|e| matches!(&e.payload, EventPayload::PumpBuy(p) if p.estimated_base_fee_lamports.is_some()) || matches!(&e.payload, EventPayload::PumpSell(p) if p.estimated_base_fee_lamports.is_some()) || matches!(&e.payload, EventPayload::ObservedTransaction(p) if p.tx_fee_lamports.is_some())),
        "failed_transaction_flag" => events.iter().any(|e| matches!(&e.payload, EventPayload::PumpBuy(_) | EventPayload::PumpSell(_) | EventPayload::ObservedTransaction(_))),
        "error_code_if_failed" => events.iter().any(|e| matches!(&e.payload, EventPayload::ObservedTransaction(p) if !p.failed_transaction || p.error_code.is_some())),
        "source_sequence_slot_timestamp_confidence" => events.iter().any(|e| e.meta.slot > 0 && e.meta.decode_confidence >= Decimal::ZERO),
        _ => false,
    }
}

fn fresh_field_unavailable_reason(
    field: &str,
    present: bool,
    token_events: &[NormalizedEvent],
    all_events: &[NormalizedEvent],
) -> (&'static str, bool) {
    if present {
        return ("", false);
    }
    let has_trade = token_events.iter().any(|event| {
        matches!(
            event.payload,
            EventPayload::PumpBuy(_) | EventPayload::PumpSell(_)
        )
    });
    let has_holder = token_events
        .iter()
        .any(|event| matches!(event.payload, EventPayload::HolderBalanceUpdate(_)));
    let has_curve = token_events
        .iter()
        .any(|event| matches!(event.payload, EventPayload::BondingCurveUpdate(_)));
    let observed_tx_count = all_events
        .iter()
        .filter(|event| matches!(event.payload, EventPayload::ObservedTransaction(_)))
        .count();
    match field {
        "buy_sell_direction"
        | "token_amount_raw_or_ui"
        | "quote_amount_lamports_or_sol"
        | "quote_amount_lamports_from_delta"
            if !has_trade =>
        {
            ("not_applicable_no_trade_observed_for_tracked_launch", false)
        }
        "token_account" | "pre_post_token_balance" if !has_holder => (
            "not_applicable_no_holder_update_observed_for_tracked_launch",
            false,
        ),
        "curve_complete_flag" | "curve_progress_pct" if !has_curve => (
            "missing_due_to_token_not_initialized_or_no_curve_update_observed",
            true,
        ),
        "instruction_shape_hash" | "account_list_hash" | "error_code_if_failed"
            if observed_tx_count == 0 =>
        {
            ("not_emitted_by_provider_observed_transaction_absent", false)
        }
        "compute_unit_limit" | "compute_unit_price" | "priority_fee" | "tx_fee"
            if !has_trade && observed_tx_count == 0 =>
        {
            ("not_applicable_no_trade_or_observed_transaction", false)
        }
        "associated_bonding_curve_account_observed" => (
            "official_idl_account_not_present_in_decoded_instruction; official_idl_pda_derivation_used_when_possible",
            false,
        ),
        "associated_bonding_curve_account_derived" => {
            let analysis = associated_curve_analysis(token_events);
            if analysis.observed_matches_derived == Some(false) {
                ("associated_bonding_curve_derivation_mismatch", true)
            } else {
                (analysis.unavailable_reason, true)
            }
        }
        "token_total_supply_stream_observed" => (
            "provider_did_not_emit_supply_for_create_or_curve_account",
            false,
        ),
        "token_total_supply_bonding_curve_observed" => (
            "bonding_curve_account_update_not_in_stream_or_decoder_missing_field",
            false,
        ),
        "token_total_supply_protocol_constant" => {
            ("not_a_pumpfun_create_or_missing_mint_context", true)
        }
        "token_total_supply_rpc_verified" => ("unavailable_blocked_by_rpc_budget", false),
        "token_total_supply_selected" => (
            "no_stream_supply_and_no_protocol_constant_context_available",
            true,
        ),
        "token_decimals" => (
            "decoded_but_not_serialized_or_provider_did_not_emit_decimals",
            true,
        ),
        "pre_sol_balance_stream_observed" | "post_sol_balance_stream_observed" => (
            "provider_meta_unavailable_or_old_schema_without_serialized_pre_post_balances",
            false,
        ),
        "quote_amount_lamports_from_delta" if has_trade => (
            "wallet_lamport_delta_or_instruction_amount_unavailable",
            true,
        ),
        _ => ("decoded_but_not_serialized", true),
    }
}

fn decimal_to_json(value: Option<Decimal>) -> serde_json::Value {
    value
        .map(|decimal| json!(decimal.to_string()))
        .unwrap_or(serde_json::Value::Null)
}

fn build_stream_metric_values(
    run_id: &str,
    mint: &str,
    events: &[NormalizedEvent],
) -> Vec<serde_json::Value> {
    let mut rows = Vec::new();
    let mut latest_curve_price = None;
    let mut latest_market_cap = None;
    let mut latest_curve_progress = None;
    let mut buy_count = 0_u64;
    let mut sell_count = 0_u64;
    let mut buy_volume = Decimal::ZERO;
    let mut sell_volume = Decimal::ZERO;
    let mut buyers = BTreeSet::<String>::new();
    let mut sellers = BTreeSet::<String>::new();
    let mut owner_balances = BTreeMap::<String, Decimal>::new();
    let mut dev_wallet = None::<String>;
    let mut price_path = Vec::<Decimal>::new();
    let mut tx_fingerprints = 0_u64;
    for event in events {
        match &event.payload {
            EventPayload::TokenCreated(payload) => {
                dev_wallet = Some(payload.creator_wallet.to_string());
            }
            EventPayload::BondingCurveUpdate(payload) => {
                let decimals = payload
                    .token_decimals
                    .unwrap_or(common::DEFAULT_PUMP_TOKEN_DECIMALS);
                if let Some(price) = payload.price_sol_per_token.or_else(|| {
                    common::pump_virtual_reserve_price_sol_per_token(
                        payload.virtual_quote_reserves,
                        payload.virtual_token_reserves,
                        decimals,
                    )
                }) {
                    latest_curve_price = Some(price);
                    latest_market_cap = Some(common::pump_market_cap_quote_1b(price));
                    price_path.push(price);
                }
                latest_curve_progress = payload.curve_progress_pct.or_else(|| {
                    let ui = common::raw_tokens_to_ui(payload.real_token_reserves, decimals);
                    common::pump_curve_progress_pct_from_real_token_reserves_ui(ui)
                });
            }
            EventPayload::PumpBuy(payload)
                if payload.status != common::TransactionStatus::Failed =>
            {
                buy_count += 1;
                buy_volume += payload.quote_in;
                buyers.insert(payload.buyer.to_string());
            }
            EventPayload::PumpSell(payload)
                if payload.status != common::TransactionStatus::Failed =>
            {
                sell_count += 1;
                sell_volume += payload.quote_out;
                sellers.insert(payload.seller.to_string());
            }
            EventPayload::HolderBalanceUpdate(payload) => {
                owner_balances.insert(payload.owner_wallet.to_string(), payload.new_balance);
            }
            EventPayload::ObservedTransaction(payload) => {
                if payload.account_list_hash.is_some() || payload.instruction_shape_hash.is_some() {
                    tx_fingerprints += 1;
                }
            }
            _ => {}
        }
    }
    let holder_count = owner_balances
        .values()
        .filter(|balance| **balance > Decimal::ZERO)
        .count();
    let observed_supply = owner_balances.values().copied().sum::<Decimal>();
    let top_holder = owner_balances
        .values()
        .copied()
        .max()
        .unwrap_or(Decimal::ZERO);
    let top_holder_pct = if observed_supply > Decimal::ZERO {
        Some(top_holder / observed_supply)
    } else {
        None
    };
    let dev_holding = dev_wallet
        .as_ref()
        .and_then(|wallet| owner_balances.get(wallet))
        .copied();
    let mfe_mae = if let Some(first) = price_path.first().copied() {
        let high = price_path.iter().copied().max().unwrap_or(first);
        let low = price_path.iter().copied().min().unwrap_or(first);
        (Some((high - first) / first), Some((low - first) / first))
    } else {
        (None, None)
    };
    for (metric, family, value, unavailable) in [
        (
            "reserve_price_sol_per_token",
            "reserve-implied price",
            decimal_to_json(latest_curve_price),
            latest_curve_price
                .is_none()
                .then_some("missing_curve_state_snapshot"),
        ),
        (
            "market_cap_1b_sol",
            "market cap",
            decimal_to_json(latest_market_cap),
            latest_market_cap
                .is_none()
                .then_some("missing_price_or_market_cap"),
        ),
        (
            "curve_progress_pct",
            "curve progress",
            decimal_to_json(latest_curve_progress),
            latest_curve_progress
                .is_none()
                .then_some("missing_real_token_reserves_or_progress"),
        ),
        ("buy_count", "buy/sell flow", json!(buy_count), None),
        ("sell_count", "buy/sell flow", json!(sell_count), None),
        (
            "buy_volume_quote",
            "buy/sell flow",
            json!(buy_volume.to_string()),
            None,
        ),
        (
            "sell_volume_quote",
            "buy/sell flow",
            json!(sell_volume.to_string()),
            None,
        ),
        (
            "unique_buyers",
            "unique buyers / sellers",
            json!(buyers.len()),
            None,
        ),
        (
            "unique_sellers",
            "unique buyers / sellers",
            json!(sellers.len()),
            None,
        ),
        (
            "holder_count",
            "holder count",
            json!(holder_count),
            owner_balances
                .is_empty()
                .then_some("missing_holder_snapshot"),
        ),
        (
            "top_holder_pct_observed",
            "top-holder concentration",
            decimal_to_json(top_holder_pct),
            top_holder_pct
                .is_none()
                .then_some("missing_holder_denominator"),
        ),
        (
            "dev_holding_balance",
            "dev holdings",
            decimal_to_json(dev_holding),
            dev_holding
                .is_none()
                .then_some("dev_wallet_balance_not_observed"),
        ),
        (
            "transaction_fingerprint_rows",
            "transaction fingerprints",
            json!(tx_fingerprints),
            None,
        ),
        (
            "fake_momentum_stream_proxy",
            "fake momentum",
            json!((buy_count > 0 && sellers.is_empty()).to_string()),
            None,
        ),
        (
            "sell_absorption_stream_proxy",
            "sell absorption",
            json!((sell_count > 0 && buy_count > sell_count).to_string()),
            None,
        ),
        (
            "mfe_pct",
            "MFE / MAE",
            decimal_to_json(mfe_mae.0),
            mfe_mae.0.is_none().then_some("insufficient_price_path"),
        ),
        (
            "mae_pct",
            "MFE / MAE",
            decimal_to_json(mfe_mae.1),
            mfe_mae.1.is_none().then_some("insufficient_price_path"),
        ),
    ] {
        rows.push(json!({
            "source_run_id": run_id,
            "mint": mint,
            "metric_name": metric,
            "metric_family": family,
            "value": value,
            "source": "stream_normalized_events",
            "confidence": if unavailable.is_some() { 0.0 } else { 1.0 },
            "unavailable_reason": unavailable.unwrap_or(""),
            "holder_count_source": if metric == "holder_count" { "stream_owner_summed_token_accounts" } else { "" },
            "top_holder_source": if metric == "top_holder_pct_observed" { "stream_owner_summed_token_accounts" } else { "" },
            "dev_holding_source": if metric == "dev_holding_balance" { "stream_owner_summed_token_accounts" } else { "" },
            "holder_rpc_used": false,
            "holder_rpc_required": false,
            "holder_rpc_audit_status": "not_run_not_required",
        }));
    }
    rows
}

#[allow(clippy::too_many_arguments)]
async fn launch_metric_canary_command(
    loaded: &LoadedConfig,
    duration_seconds: u64,
    max_launches: usize,
    stop_on_first_contract_failure: bool,
    require_stream_metrics: bool,
    no_live_trading: bool,
    no_rpc: bool,
    upload_r2: bool,
    verify_r2: bool,
    output_dir: &str,
    require_metadata_social: bool,
    allow_rpc_enrichment: bool,
    dry_run: bool,
    local_only: bool,
    latest_canary_run: bool,
    replay_canary_run: Option<&str>,
) -> Result<()> {
    let output_dir = PathBuf::from(output_dir);
    ensure_fresh_launch_metric_contract_files(&output_dir)?;
    let budget = json!({
        "schema_version": "phase89.enrichment_budget_status.v1",
        "rpc_credits_available": false,
        "no_rpc_mode": no_rpc,
        "funding_graph": "blocked_by_rpc_budget",
        "common_funder": "blocked_by_rpc_budget",
        "wallet_age_history": "blocked_by_rpc_budget",
        "bundle_confirmation": "blocked_by_rpc_budget_unless_stream_observable",
        "holder_denominator_repair_via_rpc": "not_required_for_holder_metrics",
        "metadata_social": if require_metadata_social { "blocked_by_http_api_key_or_budget" } else { "not_required_for_stream_canary" },
        "raw_deshred": "blocked_by_provider_unless_configured",
    });
    write_quant_json_md(
        &output_dir,
        "enrichment_budget_status",
        &budget,
        "# Phase 89 Enrichment/RPC Budget Status\n\nRPC enrichment was not run. RPC-dependent metrics are budget blockers, not stream canary failures.\n".to_owned(),
    )?;
    if dry_run {
        let result = json!({
            "command": "launch-metric-canary",
            "dry_run": true,
            "duration_seconds": duration_seconds,
            "max_launches": max_launches,
            "stop_on_first_contract_failure": stop_on_first_contract_failure,
            "require_stream_metrics": require_stream_metrics,
            "no_live_trading": no_live_trading,
            "no_rpc": no_rpc,
            "upload_r2": upload_r2,
            "verify_r2": verify_r2,
            "local_only": local_only,
            "latest_canary_run": latest_canary_run,
            "replay_canary_run": replay_canary_run,
        });
        println!("{}", serde_json::to_string_pretty(&result)?);
        return Ok(());
    }
    if !no_live_trading {
        bail!("launch-metric-canary refuses to run unless --no-live-trading is set");
    }
    if allow_rpc_enrichment && no_rpc {
        bail!("--allow-rpc-enrichment=true conflicts with --no-rpc");
    }
    let (run_id, all_events, live_summary) = if let Some(run_id) = replay_canary_run {
        let hydration = hydrate_normalized_event_segments_for_run(loaded, run_id, true).await?;
        if hydration.fallback_used {
            bail!("launch canary requires normalized_events; fallback was used for {run_id}");
        }
        let store = storage_engine(loaded)?;
        let events = store
            .read_normalized_events_filtered(Some(run_id), None)?
            .into_iter()
            .map(|record| record.record)
            .collect::<Vec<_>>();
        (run_id.to_owned(), events, None)
    } else if latest_canary_run {
        let index = load_dataset_index_local_or_r2(loaded, true).await?;
        let run_id = normalized_complete_run_records(&index, Some(1))
            .into_iter()
            .next()
            .map(|entry| entry.run_id)
            .ok_or_else(|| anyhow!("no normalized-complete run found for --latest-canary-run"))?;
        let hydration = hydrate_normalized_event_segments_for_run(loaded, &run_id, true).await?;
        if hydration.fallback_used {
            bail!("launch canary requires normalized_events; fallback was used for {run_id}");
        }
        let store = storage_engine(loaded)?;
        let events = store
            .read_normalized_events_filtered(Some(&run_id), None)?
            .into_iter()
            .map(|record| record.record)
            .collect::<Vec<_>>();
        (run_id, events, None)
    } else {
        let live_run_id = format!(
            "live-launch-canary-{}",
            OffsetDateTime::now_utc().unix_timestamp_nanos()
        );
        let (summary, events) = collect_fresh_launch_canary_events(
            loaded,
            FreshLaunchCanaryLiveOptions {
                duration_seconds,
                max_launches: max_launches.max(1),
                stop_when_max_launches_seen: false,
                retain_only_tracked_mints: false,
            },
        )
        .await?;
        if summary.tracked_mint.is_none() {
            bail!(
                "no fresh Pump.fun launch detected during live canary window; provider_status={}",
                summary.provider_status
            );
        }
        (live_run_id, events, Some(summary))
    };
    let creates = all_events
        .iter()
        .filter(|event| is_successful_launch_create(event))
        .take(max_launches.max(1))
        .collect::<Vec<_>>();
    let Some(create) = creates.first() else {
        bail!(
            "no successful Pump.fun create/launch event found in canary run {run_id}; failed create instructions are skipped"
        );
    };
    let mint = event_mint_string(create).ok_or_else(|| anyhow!("create event missing mint"))?;
    let token_events = all_events
        .iter()
        .filter(|event| event_mint_string(event).as_deref() == Some(mint.as_str()))
        .cloned()
        .collect::<Vec<_>>();
    let related_signatures = token_events
        .iter()
        .filter_map(event_signature_string)
        .collect::<BTreeSet<_>>();
    let observed_transactions = all_events
        .iter()
        .filter(|event| {
            matches!(&event.payload, EventPayload::ObservedTransaction(payload)
                if payload.signature_hint.as_ref().map(|sig| related_signatures.contains(sig)).unwrap_or(false))
        })
        .cloned()
        .collect::<Vec<_>>();
    let mut scoped_events = token_events.clone();
    scoped_events.extend(observed_transactions);
    let run_dir = output_dir.join("runs").join(&run_id);
    fs::create_dir_all(&run_dir)?;
    if let Some(summary) = &live_summary {
        fs::write(
            run_dir.join("live_canary_stream_summary.json"),
            serde_json::to_vec_pretty(summary)?,
        )?;
    }
    let mut normalized_jsonl = String::new();
    for event in &scoped_events {
        normalized_jsonl.push_str(&serde_json::to_string(event)?);
        normalized_jsonl.push('\n');
    }
    fs::write(run_dir.join("normalized_events.jsonl"), normalized_jsonl)?;
    let create_payload = serde_json::to_value(create)?;
    let launch_context = json!({
        "schema_version": "phase89.launch_context.v1",
        "source_run_id": run_id,
        "mint": mint,
        "launch_event_id": create.meta.event_id.0.to_string(),
        "launch_signature": event_signature_string(create),
        "launch_slot": create.meta.slot,
        "launch_timestamp": event_received_ts(create),
        "tracked_token_event_count": token_events.len(),
        "related_observed_transaction_count": scoped_events.iter().filter(|event| matches!(event.payload, EventPayload::ObservedTransaction(_))).count(),
        "launch_event": create_payload,
        "track_fresh_launch_only": true,
    });
    fs::write(
        run_dir.join("launch_context.json"),
        serde_json::to_vec_pretty(&launch_context)?,
    )?;
    let mut coverage_rows = Vec::<serde_json::Value>::new();
    let mut missing_rows = Vec::<serde_json::Value>::new();
    let mut blocking_failures = Vec::<serde_json::Value>::new();
    let associated_curve = associated_curve_analysis(&scoped_events);
    let token_supply = token_supply_analysis(&scoped_events);
    let sol_balance = sol_balance_analysis(&scoped_events, &related_signatures);
    for spec in fresh_launch_stream_field_contract() {
        let present = fresh_field_present(spec.field_id, &scoped_events, &related_signatures);
        let (reason, blocking_failure) =
            fresh_field_unavailable_reason(spec.field_id, present, &token_events, &all_events);
        let matching_events = scoped_events
            .iter()
            .filter(|event| spec.event_kinds.contains(&event_kind(event)))
            .collect::<Vec<_>>();
        let first = matching_events.first();
        let last = matching_events.last();
        let event_types_seen = matching_events
            .iter()
            .map(|event| event_kind(event))
            .collect::<BTreeSet<_>>()
            .into_iter()
            .collect::<Vec<_>>();
        let row = json!({
            "source_run_id": run_id,
            "mint": mint,
            "metric_family": spec.metric_family,
            "field_id": spec.field_id,
            "bucket": spec.bucket,
            "expected": spec.required,
            "observed": present,
            "observed_count": if present { matching_events.len().max(1) } else { 0 },
            "first_seen_slot": first.map(|event| event.meta.slot),
            "first_seen_timestamp": first.map(|event| event_received_ts(event)),
            "last_seen_slot": last.map(|event| event.meta.slot),
            "last_seen_timestamp": last.map(|event| event_received_ts(event)),
            "event_types_seen": event_types_seen.join("|"),
            "source_artifacts": "normalized_events",
            "confidence": if present { 1.0 } else { 0.0 },
            "unavailable_reason": reason,
            "blocking_for_research": spec.blocking_for_research && blocking_failure,
            "blocking_for_backtest": spec.blocking_for_backtest && blocking_failure,
            "blocking_for_tuning": spec.blocking_for_tuning || blocking_failure,
            "missing_path_classification": if present { "" } else { reason },
            "associated_bonding_curve_account_observed": associated_curve.observed.clone(),
            "associated_bonding_curve_account_derived": associated_curve.derived.clone(),
            "associated_bonding_curve_account_source": associated_curve.source,
            "associated_bonding_curve_account_confidence": associated_curve.confidence,
            "associated_bonding_curve_token_program_id": associated_curve.token_program_id,
            "associated_bonding_curve_derivation_matches_observed_account_list": associated_curve.matches_observed_account_list,
            "associated_bonding_curve_observed_matches_derived": associated_curve.observed_matches_derived,
            "token_total_supply_stream_observed_raw": decimal_to_json(token_supply.stream_observed_raw),
            "token_total_supply_bonding_curve_observed_raw": decimal_to_json(token_supply.bonding_curve_observed_raw),
            "token_total_supply_protocol_constant_raw": decimal_to_json(token_supply.protocol_constant_raw),
            "token_total_supply_protocol_constant_ui": decimal_to_json(token_supply.protocol_constant_ui),
            "token_total_supply_rpc_verified_raw": decimal_to_json(token_supply.rpc_verified_raw),
            "token_total_supply_rpc_verified_reason": token_supply.rpc_unavailable_reason,
            "token_total_supply_selected_raw": decimal_to_json(token_supply.selected_raw),
            "token_total_supply_selected_ui": decimal_to_json(token_supply.selected_ui),
            "token_total_supply_source": token_supply.source,
            "token_total_supply_confidence": token_supply.confidence,
            "token_supply_curve_economic_raw": decimal_to_json(token_supply.bonding_curve_observed_raw),
            "token_supply_curve_economic_ui": decimal_to_json(token_supply.bonding_curve_observed_raw.map(|raw| common::raw_tokens_to_ui(raw, token_supply.decimals))),
            "token_supply_protocol_constant_raw": decimal_to_json(token_supply.protocol_constant_raw),
            "token_supply_protocol_constant_ui": decimal_to_json(token_supply.protocol_constant_ui),
            "token_supply_rpc_mint_raw": decimal_to_json(token_supply.rpc_verified_raw),
            "token_supply_rpc_mint_ui": serde_json::Value::Null,
            "token_supply_selected_for_market_cap": "token_supply_curve_economic_or_protocol_constant",
            "token_supply_selected_for_curve_progress": "bonding_curve_real_reserves_and_curve_economic_supply",
            "token_supply_selected_for_holder_pct": "token_supply_curve_economic_or_protocol_constant",
            "token_supply_selected_reason": token_supply.source,
            "token_supply_semantics_status": "stream_policy_no_rpc_mint_supply",
            "token_supply_mismatch_flag": false,
            "rpc_supply_diagnostic_only": true,
            "supply_denominator_policy_version": "phase102.supply_denominator.v1",
            "token_decimals_selected": token_supply.decimals,
            "pre_sol_balance_stream_observed": sol_balance.pre_observed,
            "post_sol_balance_stream_observed": sol_balance.post_observed,
            "pre_sol_balance_count": sol_balance.pre_balance_count,
            "post_sol_balance_count": sol_balance.post_balance_count,
            "pre_sol_balance_lamports": sol_balance.sample_pre_lamports,
            "post_sol_balance_lamports": sol_balance.sample_post_lamports,
            "quote_amount_lamports_from_delta_value": decimal_to_json(sol_balance.quote_amount_lamports_from_delta),
            "quote_amount_sol_from_delta": decimal_to_json(sol_balance.quote_amount_sol_from_delta),
            "tx_fee_lamports": sol_balance.tx_fee_lamports,
            "priority_fee_lamports": sol_balance.priority_fee_lamports,
            "trade_quote_source": sol_balance.trade_quote_source,
            "trade_quote_source_confidence": sol_balance.trade_quote_source_confidence,
            "sol_balance_unavailable_reason": sol_balance.unavailable_reason,
        });
        if !present {
            missing_rows.push(row.clone());
            if spec.required && blocking_failure && require_stream_metrics {
                blocking_failures.push(row.clone());
            }
        }
        coverage_rows.push(row);
    }
    write_json_rows_csv(
        &run_dir.join("source_field_coverage.csv"),
        &[
            "source_run_id",
            "mint",
            "metric_family",
            "field_id",
            "bucket",
            "expected",
            "observed",
            "observed_count",
            "first_seen_slot",
            "first_seen_timestamp",
            "last_seen_slot",
            "last_seen_timestamp",
            "event_types_seen",
            "source_artifacts",
            "confidence",
            "unavailable_reason",
            "blocking_for_research",
            "blocking_for_backtest",
            "blocking_for_tuning",
            "missing_path_classification",
            "associated_bonding_curve_account_observed",
            "associated_bonding_curve_account_derived",
            "associated_bonding_curve_account_source",
            "associated_bonding_curve_account_confidence",
            "associated_bonding_curve_token_program_id",
            "associated_bonding_curve_derivation_matches_observed_account_list",
            "associated_bonding_curve_observed_matches_derived",
            "token_total_supply_stream_observed_raw",
            "token_total_supply_bonding_curve_observed_raw",
            "token_total_supply_protocol_constant_raw",
            "token_total_supply_protocol_constant_ui",
            "token_total_supply_rpc_verified_raw",
            "token_total_supply_rpc_verified_reason",
            "token_total_supply_selected_raw",
            "token_total_supply_selected_ui",
            "token_total_supply_source",
            "token_total_supply_confidence",
            "token_supply_curve_economic_raw",
            "token_supply_curve_economic_ui",
            "token_supply_protocol_constant_raw",
            "token_supply_protocol_constant_ui",
            "token_supply_rpc_mint_raw",
            "token_supply_rpc_mint_ui",
            "token_supply_selected_for_market_cap",
            "token_supply_selected_for_curve_progress",
            "token_supply_selected_for_holder_pct",
            "token_supply_selected_reason",
            "token_supply_semantics_status",
            "token_supply_mismatch_flag",
            "rpc_supply_diagnostic_only",
            "supply_denominator_policy_version",
            "token_decimals_selected",
            "pre_sol_balance_stream_observed",
            "post_sol_balance_stream_observed",
            "pre_sol_balance_count",
            "post_sol_balance_count",
            "pre_sol_balance_lamports",
            "post_sol_balance_lamports",
            "quote_amount_lamports_from_delta_value",
            "quote_amount_sol_from_delta",
            "tx_fee_lamports",
            "priority_fee_lamports",
            "trade_quote_source",
            "trade_quote_source_confidence",
            "sol_balance_unavailable_reason",
        ],
        &coverage_rows,
    )?;
    write_json_rows_csv(
        &run_dir.join("missing_stream_fields.csv"),
        &[
            "source_run_id",
            "mint",
            "metric_family",
            "field_id",
            "unavailable_reason",
            "blocking_for_research",
            "blocking_for_backtest",
            "blocking_for_tuning",
        ],
        &missing_rows,
    )?;
    let coverage = json!({
        "schema_version": "phase103.source_field_coverage.v3",
        "source_run_id": run_id,
        "mint": mint,
        "stream_required_fields": fresh_launch_stream_field_contract().len(),
        "observed_fields": coverage_rows.iter().filter(|row| row["observed"].as_bool().unwrap_or(false)).count(),
        "missing_fields": missing_rows.len(),
        "blocking_failures": blocking_failures,
        "associated_bonding_curve": {
            "observed": associated_curve.observed,
            "derived": associated_curve.derived,
            "source": associated_curve.source,
            "confidence": associated_curve.confidence,
            "token_program_id": associated_curve.token_program_id,
            "derivation_matches_observed_account_list": associated_curve.matches_observed_account_list,
            "observed_matches_derived": associated_curve.observed_matches_derived
        },
        "token_total_supply": {
            "stream_observed_raw": decimal_to_json(token_supply.stream_observed_raw),
            "bonding_curve_observed_raw": decimal_to_json(token_supply.bonding_curve_observed_raw),
            "protocol_constant_raw": decimal_to_json(token_supply.protocol_constant_raw),
            "protocol_constant_ui": decimal_to_json(token_supply.protocol_constant_ui),
            "rpc_verified_raw": decimal_to_json(token_supply.rpc_verified_raw),
            "rpc_verified_reason": token_supply.rpc_unavailable_reason,
            "selected_raw": decimal_to_json(token_supply.selected_raw),
            "selected_ui": decimal_to_json(token_supply.selected_ui),
            "source": token_supply.source,
            "confidence": token_supply.confidence,
            "decimals": token_supply.decimals
        },
        "token_supply_denominator_policy": {
            "token_supply_curve_economic_raw": decimal_to_json(token_supply.bonding_curve_observed_raw),
            "token_supply_curve_economic_ui": decimal_to_json(token_supply.bonding_curve_observed_raw.map(|raw| common::raw_tokens_to_ui(raw, token_supply.decimals))),
            "token_supply_protocol_constant_raw": decimal_to_json(token_supply.protocol_constant_raw),
            "token_supply_protocol_constant_ui": decimal_to_json(token_supply.protocol_constant_ui),
            "token_supply_rpc_mint_raw": decimal_to_json(token_supply.rpc_verified_raw),
            "token_supply_rpc_mint_ui": null,
            "token_supply_selected_for_market_cap": "token_supply_curve_economic_or_protocol_constant",
            "token_supply_selected_for_curve_progress": "bonding_curve_real_reserves_and_curve_economic_supply",
            "token_supply_selected_for_holder_pct": "token_supply_curve_economic_or_protocol_constant",
            "token_supply_selected_reason": token_supply.source,
            "token_supply_semantics_status": "stream_policy_no_rpc_mint_supply",
            "token_supply_mismatch_flag": false,
            "rpc_supply_diagnostic_only": true,
            "supply_denominator_policy_version": "phase102.supply_denominator.v1"
        },
        "sol_balance": {
            "pre_sol_balance_stream_observed": sol_balance.pre_observed,
            "post_sol_balance_stream_observed": sol_balance.post_observed,
            "quote_amount_lamports_from_delta": decimal_to_json(sol_balance.quote_amount_lamports_from_delta),
            "quote_amount_sol_from_delta": decimal_to_json(sol_balance.quote_amount_sol_from_delta),
            "tx_fee_lamports": sol_balance.tx_fee_lamports,
            "priority_fee_lamports": sol_balance.priority_fee_lamports,
            "trade_quote_source": sol_balance.trade_quote_source,
            "trade_quote_source_confidence": sol_balance.trade_quote_source_confidence,
            "unavailable_reason": sol_balance.unavailable_reason
        },
        "rows": coverage_rows,
    });
    fs::write(
        run_dir.join("source_field_coverage.json"),
        serde_json::to_vec_pretty(&coverage)?,
    )?;
    write_report(
        run_dir.join("source_field_coverage.md"),
        &format!(
            "# Source Field Coverage\n\n- source run: `{}`\n- mint: `{}`\n- observed fields: `{}` / `{}`\n- missing fields: `{}`\n- blocking stream failures: `{}`\n",
            run_id,
            mint,
            coverage["observed_fields"],
            coverage["stream_required_fields"],
            missing_rows.len(),
            coverage["blocking_failures"]
                .as_array()
                .map(|rows| rows.len())
                .unwrap_or(0)
        ),
    )?;
    let metric_rows = build_stream_metric_values(&run_id, &mint, &scoped_events);
    write_json_rows_csv(
        &run_dir.join("stream_metric_values.csv"),
        &[
            "source_run_id",
            "mint",
            "metric_name",
            "metric_family",
            "value",
            "source",
            "confidence",
            "unavailable_reason",
            "holder_count_source",
            "top_holder_source",
            "dev_holding_source",
            "holder_rpc_used",
            "holder_rpc_required",
            "holder_rpc_audit_status",
        ],
        &metric_rows,
    )?;
    let stream_proof = json!({
        "schema_version": "phase89.stream_metric_proof.v1",
        "source_run_id": run_id,
        "mint": mint,
        "metrics_computed": metric_rows.iter().filter(|row| row["unavailable_reason"].as_str().unwrap_or("").is_empty()).count(),
        "metrics_unavailable": metric_rows.iter().filter(|row| !row["unavailable_reason"].as_str().unwrap_or("").is_empty()).count(),
        "rows": metric_rows,
        "no_rpc_used": no_rpc,
        "holder_count_source": "stream_owner_summed_token_accounts",
        "top_holder_source": "stream_owner_summed_token_accounts",
        "dev_holding_source": "stream_owner_summed_token_accounts",
        "holder_rpc_used": false,
        "holder_rpc_required": false,
        "holder_rpc_audit_status": "not_run_not_required",
        "no_live_trading": no_live_trading,
    });
    write_quant_json_md(
        &run_dir,
        "stream_metric_proof",
        &stream_proof,
        format!(
            "# Stream Metric Proof\n\n- source run: `{run_id}`\n- mint: `{mint}`\n- no RPC used: `{no_rpc}`\n- no live trading: `{no_live_trading}`\n"
        ),
    )?;
    let contract_result = json!({
        "schema_version": "phase89.metric_contract_result.v1",
        "source_run_id": run_id,
        "mint": mint,
        "status": if blocking_failures.is_empty() { "passed" } else { "failed" },
        "stream_required_passed": blocking_failures.is_empty(),
        "blocking_failures": blocking_failures,
        "enrichment_required_metrics": "blocked_by_rpc_budget_or_http_provider_not_stream_failure",
        "holder_rpc_used": false,
        "holder_rpc_required": false,
        "holder_rpc_audit_status": "not_run_not_required",
        "holder_denominator_repair_via_rpc": "not_required_for_holder_metrics",
        "raw_shred_required_metrics": "blocked_by_provider",
        "deshred_required_metrics": "blocked_by_provider",
        "threshold_tuning_allowed": false,
    });
    write_quant_json_md(
        &run_dir,
        "metric_contract_result",
        &contract_result,
        format!(
            "# Metric Contract Result\n\nStatus: `{}`\n\nThreshold tuning allowed: `false`\n",
            contract_result["status"].as_str().unwrap_or("unknown")
        ),
    )?;
    write_json_rows_csv(
        &run_dir.join("metric_unavailable_reasons.csv"),
        &["metric_family", "field_id", "unavailable_reason", "bucket"],
        &missing_rows,
    )?;
    let mut canary_uploaded_files = Vec::<String>::new();
    let mut canary_verified_files = Vec::<String>::new();
    let mut canary_failed_files = Vec::<String>::new();
    if upload_r2 {
        fn collect_canary_files(path: &Path, out: &mut Vec<PathBuf>) -> Result<()> {
            if path.is_file() {
                out.push(path.to_path_buf());
                return Ok(());
            }
            for entry in fs::read_dir(path)? {
                let entry = entry?;
                collect_canary_files(&entry.path(), out)?;
            }
            Ok(())
        }
        let client = r2_client_for_command(loaded, false, true, false)?;
        let bucket = client.bucket_for_reports()?;
        let mut paths = Vec::<PathBuf>::new();
        collect_canary_files(&output_dir, &mut paths)?;
        paths.sort();
        let remote_base = format!("phase90_field_gap_fix/{run_id}");
        for path in paths {
            if path.is_dir() {
                continue;
            }
            let relative = path
                .strip_prefix(&output_dir)
                .unwrap_or(path.as_path())
                .to_string_lossy()
                .replace('\\', "/");
            let remote_key = client.managed_key(
                &research_remote_base_prefix(&client),
                &format!("{remote_base}/{relative}"),
            );
            let prepared = client.prepare_upload(
                &path,
                bucket.clone(),
                remote_key.clone(),
                &artifact_content_type(&path),
                BTreeMap::new(),
                Some(false),
            )?;
            let result = client
                .upload_prepared(&prepared, verify_r2.then_some(true))
                .await?;
            if result.uploaded {
                canary_uploaded_files.push(remote_key.clone());
            }
            if verify_r2 && result.verified {
                canary_verified_files.push(remote_key.clone());
            }
            if verify_r2 && !result.verified {
                canary_failed_files.push(remote_key);
            }
        }
        let upload_summary = json!({
        "schema_version": "phase90.canary_r2_upload.v1",
            "source_run_id": run_id,
            "mint": mint,
            "uploaded_files": canary_uploaded_files.clone(),
            "verified_files": canary_verified_files.clone(),
            "failed_files": canary_failed_files.clone(),
            "verified": verify_r2 && !canary_verified_files.is_empty() && canary_failed_files.is_empty(),
        });
        write_quant_json_md(
            &output_dir,
            "canary_r2_upload_summary",
            &upload_summary,
            format!(
                "# Phase 90 Canary R2 Upload\n\n- source run: `{run_id}`\n- uploaded files: `{}`\n- verified files: `{}`\n- failed files: `{}`\n",
                upload_summary["uploaded_files"]
                    .as_array()
                    .map(|v| v.len())
                    .unwrap_or(0),
                upload_summary["verified_files"]
                    .as_array()
                    .map(|v| v.len())
                    .unwrap_or(0),
                upload_summary["failed_files"]
                    .as_array()
                    .map(|v| v.len())
                    .unwrap_or(0),
            ),
        )?;
    }
    let canary_r2_verified = if upload_r2 {
        verify_r2 && !canary_verified_files.is_empty() && canary_failed_files.is_empty()
    } else {
        false
    };
    let success = json!({
        "schema_version": "phase90.fresh_launch_canary_success.v1",
        "source_run_id": run_id,
        "mint": mint,
        "launch_detected": true,
        "stream_required_passed": contract_result["stream_required_passed"],
        "r2_upload_verified": canary_r2_verified,
        "r2_uploaded_files": canary_uploaded_files.len(),
        "r2_verified_files": canary_verified_files.len(),
        "r2_failed_files": canary_failed_files.len(),
        "upload_r2_requested": upload_r2,
        "local_only": local_only,
        "no_live_rpc_used": no_rpc,
        "no_live_orders": no_live_trading,
        "threshold_tuning_allowed": false,
    });
    write_quant_json_md(
        &output_dir,
        "fresh_launch_canary_success",
        &success,
        format!(
            "# Fresh Launch Canary Success\n\n- source run: `{run_id}`\n- mint: `{mint}`\n- stream required passed: `{}`\n- threshold tuning allowed: `false`\n",
            success["stream_required_passed"]
        ),
    )?;
    let readiness = json!({
        "schema_version": "phase90.final_metric_readiness.v1",
        "source_run_id": run_id,
        "mint": mint,
        "stream_required_metrics_working": contract_result["stream_required_passed"],
        "research_derived_metrics_working": stream_proof["metrics_computed"].as_u64().unwrap_or(0) > 0,
        "blocked_by_rpc_credits": ["funding_graph", "common_funder", "wallet_age_history", "bundle_confirmation"],
        "holder_denominator_repair_via_rpc": "not_required_for_holder_metrics",
        "requires_raw_shred_provider": ["raw_shred_metrics"],
        "requires_deshred_provider": ["deshred_metrics"],
        "unsupported": [],
        "diagnostic_backtesting_allowed": contract_result["stream_required_passed"],
        "formal_backtesting_allowed": false,
        "threshold_tuning_allowed": false,
        "minimum_next_data_needed": "repeat canary across multiple fresh launches after stream contract pass; add RPC budget for enrichment-only families",
    });
    write_quant_json_md(
        &output_dir,
        "final_metric_readiness",
        &readiness,
        "# Phase 90 Final Metric Readiness\n\nDiagnostic work is allowed only if the stream-required canary passes. Formal backtesting and threshold tuning remain blocked by sample size and enrichment/provider coverage.\n".to_owned(),
    )?;
    let result = json!({
        "command": "launch-metric-canary",
        "source_run_id": run_id,
        "mint": mint,
        "status": contract_result["status"],
        "output_dir": output_dir.display().to_string(),
        "run_dir": run_dir.display().to_string(),
    });
    println!("{}", serde_json::to_string_pretty(&result)?);
    if stop_on_first_contract_failure
        && require_stream_metrics
        && contract_result["status"] == "failed"
    {
        bail!(
            "fresh launch canary stream contract failed; see {}",
            run_dir.display()
        );
    }
    Ok(())
}

async fn live_risk_canary_command(
    loaded: &LoadedConfig,
    duration_seconds: u64,
    no_live_trading: bool,
    no_rpc: bool,
    upload_r2: bool,
    verify_r2: bool,
    output_dir: &str,
) -> Result<()> {
    if !no_live_trading {
        bail!("live-risk-canary refuses to run unless --no-live-trading is set");
    }
    if !no_rpc {
        bail!("live-risk-canary refuses to run unless --no-rpc is set; holder RPC is forbidden");
    }

    let output_dir = PathBuf::from(output_dir);
    fs::create_dir_all(&output_dir)?;
    let run_id = format!(
        "live-risk-canary-{}",
        OffsetDateTime::now_utc().unix_timestamp_nanos()
    );
    let (summary, all_events) = collect_fresh_launch_canary_events(
        loaded,
        FreshLaunchCanaryLiveOptions {
            duration_seconds,
            max_launches: 1,
            stop_when_max_launches_seen: false,
            retain_only_tracked_mints: false,
        },
    )
    .await?;
    if summary.tracked_mint.is_none() {
        bail!(
            "no fresh Pump.fun launch detected during live risk canary window; provider_status={}",
            summary.provider_status
        );
    }

    let create = all_events
        .iter()
        .find(|event| is_successful_launch_create(event))
        .ok_or_else(|| anyhow!("live risk canary saw no successful TokenCreated event"))?;
    let mint = event_mint_string(create).ok_or_else(|| anyhow!("create event missing mint"))?;
    let token_events = all_events
        .iter()
        .filter(|event| event_mint_string(event).as_deref() == Some(mint.as_str()))
        .cloned()
        .collect::<Vec<_>>();
    let related_signatures = token_events
        .iter()
        .filter_map(event_signature_string)
        .collect::<BTreeSet<_>>();
    let observed_transactions = all_events
        .iter()
        .filter(|event| {
            matches!(&event.payload, EventPayload::ObservedTransaction(payload)
                if payload.signature_hint.as_ref().map(|sig| related_signatures.contains(sig)).unwrap_or(false))
        })
        .cloned()
        .collect::<Vec<_>>();
    let mut scoped_events = token_events.clone();
    scoped_events.extend(observed_transactions);

    let run_dir = output_dir.join("runs").join(&run_id);
    fs::create_dir_all(&run_dir)?;
    fs::write(
        run_dir.join("live_canary_stream_summary.json"),
        serde_json::to_vec_pretty(&summary)?,
    )?;
    let mut normalized_jsonl = String::new();
    for event in &scoped_events {
        normalized_jsonl.push_str(&serde_json::to_string(event)?);
        normalized_jsonl.push('\n');
    }
    fs::write(run_dir.join("normalized_events.jsonl"), normalized_jsonl)?;

    let mut state_engine = StateEngine::new(loaded.config.ttl.clone());
    let risk_engine = DiagnosticRiskEngine::default();
    let bundle_context = stream_bundle_context(&mint, create.meta.slot, &scoped_events);
    let mut risk_timeline = Vec::<serde_json::Value>::new();
    let mut pre_entry_rows = Vec::<serde_json::Value>::new();
    let mut bundle_rows = Vec::<serde_json::Value>::new();
    let mut rug_rows = Vec::<serde_json::Value>::new();
    let mut metadata_funding_rows = Vec::<serde_json::Value>::new();
    let mut time_safety_rows = Vec::<serde_json::Value>::new();
    let mut all_evidence = Vec::<RiskEvidence>::new();

    for (event_index, event) in scoped_events.iter().enumerate() {
        state_engine.apply_event(event)?;
        let snapshot = state_engine.snapshot();
        let Some(token) = snapshot.tokens.get(&mint) else {
            continue;
        };
        let input = risk_input_from_token(&mint, token, &bundle_context);
        let output = risk_engine.evaluate(input);
        risk_timeline.push(json!({
            "source_run_id": run_id,
            "mint": mint,
            "event_index": event_index,
            "event_id": event.meta.event_id.0.to_string(),
            "event_kind": event_kind(event),
            "available_at_slot": event.meta.slot,
            "available_at_timestamp": event_received_ts(event),
            "risk_score_total": decimal_to_json(Some(output.risk_score_total)),
            "risk_score_stream_only": decimal_to_json(Some(output.risk_score_stream_only)),
            "risk_score_enrichment": decimal_to_json(Some(output.risk_score_enrichment)),
            "risk_classification": format!("{:?}", output.risk_classification),
            "risk_evidence_count": output.risk_evidence_count,
            "risk_confidence": decimal_to_json(Some(output.risk_confidence)),
            "unavailable_risk_families": output.unavailable_risk_families.join("|"),
            "blocking_data_quality_reasons": output.blocking_data_quality_reasons.join("|"),
            "denominator_source_for_market_cap": output.denominator_source_for_market_cap.clone(),
            "denominator_source_for_holder_pct": output.denominator_source_for_holder_pct.clone(),
            "rpc_supply_diagnostic_only": output.rpc_supply_diagnostic_only,
            "supply_semantics_status": output.supply_semantics_status.clone(),
            "supply_mismatch_ratio": decimal_to_json(output.supply_mismatch_ratio),
            "supply_denominator_policy_version": output.supply_denominator_policy_version.clone(),
            "rpc_mint_supply_canonical": false,
            "holder_rpc_used": false,
            "no_live_trading": true,
            "no_rpc": true,
        }));
        for evidence in &output.evidence {
            let row = risk_evidence_row(&run_id, &mint, event, evidence, &output);
            time_safety_rows.push(row.clone());
            if evidence.time_role.pre_entry_safe() {
                pre_entry_rows.push(row.clone());
            }
            if evidence.risk_family.contains("bundle") {
                bundle_rows.push(row.clone());
            }
            if evidence.risk_family.contains("dev")
                || evidence.risk_family.contains("holder")
                || evidence.risk_family.contains("fake")
                || evidence.risk_family.contains("sell")
                || evidence.risk_family.contains("data_quality")
            {
                rug_rows.push(row.clone());
            }
            if evidence.risk_family.contains("metadata")
                || evidence.risk_family.contains("funding")
                || evidence.risk_family.contains("supply")
            {
                metadata_funding_rows.push(row);
            }
        }
        all_evidence.extend(output.evidence);
    }

    validate_no_post_event_pre_entry_leak(&all_evidence)
        .map_err(|err| anyhow!("Phase 100 time-safety gate failed: {err}"))?;
    let post_event_rows = build_post_event_risk_labels(&run_id, &mint, &state_engine.snapshot())?;
    for row in &post_event_rows {
        if row["can_use_pre_entry"].as_bool().unwrap_or(false) {
            bail!("post-event label leaked into pre-entry feature set");
        }
    }

    write_json_rows_csv(
        &run_dir.join("risk_timeline.csv"),
        &[
            "source_run_id",
            "mint",
            "event_index",
            "event_id",
            "event_kind",
            "available_at_slot",
            "available_at_timestamp",
            "risk_score_total",
            "risk_score_stream_only",
            "risk_score_enrichment",
            "risk_classification",
            "risk_evidence_count",
            "risk_confidence",
            "unavailable_risk_families",
            "blocking_data_quality_reasons",
            "denominator_source_for_market_cap",
            "denominator_source_for_holder_pct",
            "rpc_supply_diagnostic_only",
            "supply_semantics_status",
            "supply_mismatch_ratio",
            "supply_denominator_policy_version",
            "rpc_mint_supply_canonical",
            "holder_rpc_used",
            "no_live_trading",
            "no_rpc",
        ],
        &risk_timeline,
    )?;
    write_risk_rows(
        &run_dir.join("pre_entry_risk_features.csv"),
        &pre_entry_rows,
    )?;
    write_risk_rows(&run_dir.join("bundle_like_evidence.csv"), &bundle_rows)?;
    write_risk_rows(&run_dir.join("rug_dump_evidence.csv"), &rug_rows)?;
    write_risk_rows(
        &run_dir.join("metadata_funding_evidence.csv"),
        &metadata_funding_rows,
    )?;
    write_json_rows_csv(
        &run_dir.join("post_event_risk_labels.csv"),
        &[
            "source_run_id",
            "mint",
            "label_id",
            "label_family",
            "value",
            "feature_time_class",
            "can_use_pre_entry",
            "can_use_for_backtest",
            "can_use_for_tuning",
            "unavailable_reason",
            "rug_outcome_reason",
        ],
        &post_event_rows,
    )?;
    write_risk_rows(&output_dir.join("time_safety_gate.csv"), &time_safety_rows)?;
    let time_safety = json!({
        "schema_version": "phase100.time_safety_gate.v1",
        "source_run_id": run_id,
        "mint": mint,
        "passed": true,
        "risk_fields_checked": time_safety_rows.len(),
        "post_event_labels_checked": post_event_rows.len(),
        "post_event_labels_marked_pre_entry": 0,
        "enrichment_late_marked_pre_entry": time_safety_rows.iter().filter(|row| {
            row["feature_time_class"].as_str() == Some("enrichment_late_feature")
                && row["can_use_pre_entry"].as_bool().unwrap_or(false)
        }).count(),
        "holder_rpc_used": false,
        "no_rpc": true,
        "no_live_trading": true,
    });
    if time_safety["enrichment_late_marked_pre_entry"]
        .as_u64()
        .unwrap_or(0)
        > 0
    {
        bail!("enrichment-late feature was marked pre-entry safe");
    }
    write_quant_json_md(
        &output_dir,
        "time_safety_gate",
        &time_safety,
        format!(
            "# Phase 100 Time-Safety Gate\n\n- source run: `{run_id}`\n- mint: `{mint}`\n- passed: `true`\n- post-event labels marked pre-entry: `0`\n"
        ),
    )?;

    let summary_json = json!({
        "schema_version": "phase100.live_risk_canary_summary.v1",
        "source_run_id": run_id,
        "mint": mint,
        "launch_detected": true,
        "launch_signature": event_signature_string(create),
        "launch_slot": create.meta.slot,
        "launch_timestamp": event_received_ts(create),
        "risk_timeline_rows": risk_timeline.len(),
        "pre_entry_risk_feature_rows": pre_entry_rows.len(),
        "post_event_label_rows": post_event_rows.len(),
        "bundle_like_evidence_rows": bundle_rows.len(),
        "rug_dump_evidence_rows": rug_rows.len(),
        "metadata_funding_evidence_rows": metadata_funding_rows.len(),
        "time_safety_passed": true,
        "provider_confirmed_bundle": false,
        "provider_confirmed_malicious_label": false,
        "denominator_source_for_market_cap": "curve_economic_supply_or_protocol_constant",
        "denominator_source_for_holder_pct": "curve_economic_supply",
        "market_cap_denominator": "curve_economic_supply_or_protocol_constant",
        "curve_progress_denominator": "bonding_curve_real_reserves_and_curve_economic_supply",
        "top_holder_pct_denominator": "curve_economic_supply",
        "dev_holding_pct_denominator": "curve_economic_supply",
        "holder_count_source": "stream_owner_summed_token_accounts",
        "rpc_mint_supply_canonical": false,
        "rpc_supply_diagnostic_only": true,
        "supply_denominator_policy_version": "phase102.supply_denominator.v1",
        "holder_rpc_used": false,
        "holder_rpc_required": false,
        "no_rpc": true,
        "no_live_trading": true,
        "threshold_tuning_allowed": false,
        "formal_backtesting_allowed": false,
        "diagnostic_backtesting_allowed": true,
    });
    write_quant_json_md(
        &run_dir,
        "risk_canary_summary",
        &summary_json,
        format!(
            "# Phase 100 Live Risk Canary\n\n- source run: `{run_id}`\n- mint: `{mint}`\n- risk timeline rows: `{}`\n- time-safety passed: `true`\n- threshold tuning allowed: `false`\n",
            summary_json["risk_timeline_rows"]
        ),
    )?;

    let mut r2_upload = json!({
        "schema_version": "phase100.r2_upload_result.v1",
        "uploaded_files": [],
        "verified_files": [],
        "failed_files": [],
        "verified": false,
        "upload_requested": upload_r2,
    });
    if upload_r2 {
        r2_upload = upload_phase_report_dir_to_r2(
            loaded,
            &output_dir,
            "phase100_live_risk_canary",
            &run_id,
            verify_r2,
        )
        .await?;
        write_quant_json_md(
            &output_dir,
            "r2_upload_result",
            &r2_upload,
            format!(
                "# Phase 100 R2 Upload\n\n- source run: `{run_id}`\n- verified: `{}`\n",
                r2_upload["verified"]
            ),
        )?;
        r2_upload = upload_phase_report_dir_to_r2(
            loaded,
            &output_dir,
            "phase100_live_risk_canary",
            &run_id,
            verify_r2,
        )
        .await?;
    }

    let aggregate = json!({
        "command": "live-risk-canary",
        "source_run_id": run_id,
        "mint": mint,
        "output_dir": output_dir.display().to_string(),
        "run_dir": run_dir.display().to_string(),
        "time_safety_passed": true,
        "r2_upload_verified": r2_upload["verified"],
        "threshold_tuning_allowed": false,
    });
    println!("{}", serde_json::to_string_pretty(&aggregate)?);
    Ok(())
}

#[derive(Debug, Clone)]
struct Phase107fActiveMint {
    mint: String,
    create: NormalizedEvent,
    events: Vec<NormalizedEvent>,
    related_signatures: BTreeSet<String>,
    attempt_index: usize,
    finalized: bool,
    candidate_300_written: bool,
    candidate_900_written: bool,
    candidate_1800_written: bool,
}

impl Phase107fActiveMint {
    fn new(mint: String, create: NormalizedEvent, attempt_index: usize) -> Self {
        let mut related_signatures = BTreeSet::new();
        if let Some(signature) = event_signature_string(&create) {
            related_signatures.insert(signature);
        }
        Self {
            mint,
            create: create.clone(),
            events: vec![create],
            related_signatures,
            attempt_index,
            finalized: false,
            candidate_300_written: false,
            candidate_900_written: false,
            candidate_1800_written: false,
        }
    }

    fn push_if_related(&mut self, event: &NormalizedEvent) {
        if phase107f_event_related_to_active_mint(self, event) {
            if let Some(signature) = event_signature_string(event) {
                self.related_signatures.insert(signature);
            }
            self.events.push(event.clone());
        }
    }
}

fn phase107f_event_related_to_active_mint(
    active: &Phase107fActiveMint,
    event: &NormalizedEvent,
) -> bool {
    if event_mint_string(event).as_deref() == Some(active.mint.as_str()) {
        return true;
    }
    match &event.payload {
        EventPayload::ObservedTransaction(payload) => {
            payload
                .signature_hint
                .as_ref()
                .map(|signature| active.related_signatures.contains(signature))
                .unwrap_or(false)
                || event.meta.slot == active.create.meta.slot
                || (payload
                    .program_ids
                    .iter()
                    .any(|program| program == "6EF8rrecthR5Dkzon8Nwu78hRvfCKubJ14M5uBEwF6P")
                    && event.meta.slot >= active.create.meta.slot
                    && event.meta.slot <= active.create.meta.slot.saturating_add(64))
        }
        _ => false,
    }
}

fn phase107f_write_health(
    health_dir: &Path,
    run_id: &str,
    current_state: &str,
    summary: &MaterialHunterStreamSummary,
    attempted_launches: usize,
    active_tracked_mints: usize,
    rejected_count: usize,
    candidate_count: usize,
    safe_to_continue: bool,
    blocker_reason: &str,
) -> Result<()> {
    fs::create_dir_all(health_dir)?;
    let now = OffsetDateTime::now_utc();
    let checkpoint_state_path = health_dir.join("last_checkpoint.json");
    let checkpoint_state = fs::read(&checkpoint_state_path)
        .ok()
        .and_then(|bytes| serde_json::from_slice::<serde_json::Value>(&bytes).ok())
        .unwrap_or_else(|| json!({}));
    let heartbeat = json!({
        "schema_version": "phase107f.material_hunter_heartbeat.v1",
        "run_id": run_id,
        "campaign_id": run_id,
        "slice_id": run_id,
        "service_pid": std::process::id(),
        "binary_commit": option_env!("GITHUB_SHA").unwrap_or("unknown"),
        "started_at": "",
        "last_update_at": now,
        "current_state": current_state,
        "attempted_launches": attempted_launches,
        "active_tracked_mints": active_tracked_mints,
        "rejected_count": rejected_count,
        "candidate_count": candidate_count,
        "last_seen_provider_update_at": if summary.transaction_updates + summary.account_updates + summary.slot_updates > 0 { now.to_string() } else { String::new() },
        "last_seen_pump_update_at": if summary.pump_create_decoded > 0 { now.to_string() } else { String::new() },
        "last_attempt_ledger_flush_at": now,
        "last_artifact_write_at": now,
        "last_r2_checkpoint_at": checkpoint_state["last_r2_checkpoint_at"].as_str().unwrap_or(""),
        "r2_checkpoint_verified": checkpoint_state["r2_checkpoint_verified"].as_bool().unwrap_or(false),
        "free_mb": phase107f_free_mb(health_dir).unwrap_or(0),
        "rss_mb": phase107f_current_rss_mb().unwrap_or(0),
        "retained_events_count": 0,
        "retained_transaction_fingerprint_count": 0,
        "provider_updates": summary.transaction_updates + summary.account_updates + summary.slot_updates,
        "pump_updates": summary.pump_create_decoded,
        "safe_to_continue": safe_to_continue,
        "blocker_reason": blocker_reason,
        "holder_rpc_used": false,
        "rpc_mint_supply_canonical": false,
        "threshold_tuning_allowed": false,
    });
    fs::write(
        health_dir.join("heartbeat.json"),
        serde_json::to_string_pretty(&heartbeat)?,
    )?;
    fs::write(
        health_dir.join("heartbeat.md"),
        format!(
            "# Phase 107F Hunter Heartbeat\n\n- run_id: `{run_id}`\n- current_state: `{current_state}`\n- attempted_launches: `{attempted_launches}`\n- active_tracked_mints: `{active_tracked_mints}`\n- safe_to_continue: `{safe_to_continue}`\n- blocker_reason: `{blocker_reason}`\n"
        ),
    )?;
    let provider_path = health_dir.join("provider_liveness.csv");
    if !provider_path.exists() {
        fs::write(
            &provider_path,
            "timestamp,provider_updates,pump_updates,provider_status,safe_to_continue,blocker_reason\n",
        )?;
    }
    OpenOptions::new()
        .append(true)
        .open(&provider_path)?
        .write_all(
            format!(
                "{},{},{},{},{},{}\n",
                now,
                summary.transaction_updates + summary.account_updates + summary.slot_updates,
                summary.pump_create_decoded,
                csv_field(&summary.provider_status),
                safe_to_continue,
                csv_field(blocker_reason)
            )
            .as_bytes(),
        )?;
    let sentinel_path = health_dir.join("sentinel_status.csv");
    if !sentinel_path.exists() {
        fs::write(
            &sentinel_path,
            "timestamp,sentinel,safe_to_continue,blocker_reason\n",
        )?;
    }
    OpenOptions::new()
        .append(true)
        .open(&sentinel_path)?
        .write_all(
            format!(
                "{},heartbeat,{},{}\n",
                now,
                safe_to_continue,
                csv_field(blocker_reason)
            )
            .as_bytes(),
        )?;
    let checkpoint_path = health_dir.join("checkpoint_status.csv");
    if !checkpoint_path.exists() {
        fs::write(
            &checkpoint_path,
            "timestamp,checkpoint_type,verified,reason,details\n",
        )?;
    }
    Ok(())
}

fn phase107f_current_rss_mb() -> Option<u64> {
    #[cfg(target_os = "linux")]
    {
        let status = fs::read_to_string("/proc/self/status").ok()?;
        let kb = status.lines().find_map(|line| {
            line.strip_prefix("VmRSS:")
                .and_then(|rest| rest.split_whitespace().next())
                .and_then(|value| value.parse::<u64>().ok())
        })?;
        Some(kb / 1024)
    }
    #[cfg(not(target_os = "linux"))]
    {
        None
    }
}

fn phase107f_free_mb(path: &Path) -> Option<u64> {
    let output = ProcessCommand::new("df")
        .arg("-Pm")
        .arg(path)
        .output()
        .ok()?;
    let text = String::from_utf8_lossy(&output.stdout);
    text.lines()
        .nth(1)
        .and_then(|line| line.split_whitespace().nth(3))
        .and_then(|value| value.parse::<u64>().ok())
}

async fn phase107f_upload_r2_checkpoint(
    loaded: &LoadedConfig,
    output_dir: &Path,
    run_id: &str,
    verify_r2: bool,
    reason: &str,
) -> Result<bool> {
    let health_dir = output_dir.join("health");
    fs::create_dir_all(&health_dir)?;
    let now = OffsetDateTime::now_utc();
    let upload_result = upload_phase_report_dir_to_r2(
        loaded,
        output_dir,
        "phase107b_material_candidate_hunter_checkpoint",
        run_id,
        verify_r2,
    )
    .await;
    let (verified, details, upload_error) = match upload_result {
        Ok(result) => (
            result["verified"].as_bool().unwrap_or(false),
            result["failed_files"].to_string(),
            None,
        ),
        Err(error) => (false, error.to_string(), Some(error.to_string())),
    };
    let status_line = format!(
        "{},r2_checkpoint,{},{},{}\n",
        now,
        verified,
        csv_field(reason),
        csv_field(&details)
    );
    let checkpoint_path = health_dir.join("checkpoint_status.csv");
    if !checkpoint_path.exists() {
        fs::write(
            &checkpoint_path,
            "timestamp,checkpoint_type,verified,reason,details\n",
        )?;
    }
    OpenOptions::new()
        .append(true)
        .open(&checkpoint_path)?
        .write_all(status_line.as_bytes())?;
    fs::write(
        health_dir.join("last_checkpoint.json"),
        serde_json::to_vec_pretty(&json!({
            "last_r2_checkpoint_at": now,
            "r2_checkpoint_verified": verified,
            "reason": reason,
            "threshold_tuning_allowed": false,
        }))?,
    )?;
    if !verified {
        write_quant_json_md(
            output_dir,
            "early_failure_blocker",
            &json!({
                "schema_version": "phase107f.early_failure_blocker.v1",
                "run_id": run_id,
                "blocker_class": "r2_checkpoint_failed",
                "reason": reason,
                "sanitized_error": upload_error,
                "threshold_tuning_allowed": false,
                "generated_at": now,
            }),
            format!(
                "# Phase 107F Early Failure Blocker\n\n- run_id: `{run_id}`\n- blocker_class: `r2_checkpoint_failed`\n- reason: `{reason}`\n"
            ),
        )?;
    }
    Ok(verified)
}

fn phase107f_upload_r2_checkpoint_blocking(
    loaded: &LoadedConfig,
    output_dir: &Path,
    run_id: &str,
    verify_r2: bool,
    reason: &str,
) -> Result<bool> {
    tokio::task::block_in_place(|| {
        tokio::runtime::Handle::current().block_on(phase107f_upload_r2_checkpoint(
            loaded, output_dir, run_id, verify_r2, reason,
        ))
    })
}

async fn material_candidate_hunter_command(
    loaded: &LoadedConfig,
    duration_seconds: u64,
    max_attempted_launches: usize,
    target_material_candidates: usize,
    max_concurrent_tracked_mints: usize,
    no_live_trading: bool,
    no_rpc: bool,
    upload_r2: bool,
    verify_r2: bool,
    output_dir: &str,
    run_id: Option<String>,
) -> Result<()> {
    if !no_live_trading {
        bail!("material-candidate-hunter refuses to run unless --no-live-trading is set");
    }
    if !no_rpc {
        bail!(
            "material-candidate-hunter refuses to run unless --no-rpc is set; holder RPC is forbidden"
        );
    }
    if max_concurrent_tracked_mints == 0 {
        bail!("max-concurrent-tracked-mints must be at least 1");
    }

    let output_dir = PathBuf::from(output_dir);
    fs::create_dir_all(&output_dir)?;
    let run_id = run_id.unwrap_or_else(|| {
        format!(
            "material-candidate-hunter-{}",
            OffsetDateTime::now_utc().unix_timestamp_nanos()
        )
    });
    let preflight = json!({
        "schema_version": "phase107b.preflight.v1",
        "run_id": run_id,
        "git_built_binary_required": true,
        "report_prefix": "phase107b_material_candidate_hunter",
        "duration_seconds": duration_seconds,
        "max_attempted_launches": max_attempted_launches,
        "target_material_candidates": target_material_candidates,
        "max_concurrent_tracked_mints": max_concurrent_tracked_mints,
        "live_trading_disabled": no_live_trading,
        "holder_rpc_disabled": no_rpc,
        "rpc_mint_supply_canonical": false,
        "threshold_tuning_allowed": false,
        "large_dataset_started": false,
        "broad_enrichment_started": false,
        "provider_preflight": "checked_by_live_subscription",
        "r2_preflight": if upload_r2 { "verified_after_report_generation" } else { "not_requested" },
    });
    write_quant_json_md(
        &output_dir,
        "preflight",
        &preflight,
        format!(
            "# Phase 107B Material Candidate Hunter Preflight\n\n- run_id: `{run_id}`\n- report_prefix: `phase107b_material_candidate_hunter`\n- no live trading: `{no_live_trading}`\n- holder RPC disabled: `{no_rpc}`\n- max attempted launches: `{max_attempted_launches}`\n- target material candidates: `{target_material_candidates}`\n"
        ),
    )?;

    let risk_engine = DiagnosticRiskEngine::default();
    let mut attempt_rows = Vec::<serde_json::Value>::new();
    let mut rejected_rows = Vec::<serde_json::Value>::new();
    let mut candidate_rows = Vec::<serde_json::Value>::new();
    let mut unavailable_rows = Vec::<serde_json::Value>::new();
    let mut candidates_300 = 0u64;
    let mut candidates_900 = 0u64;
    let mut candidates_1800 = 0u64;
    let mut rejected_dead = 0u64;
    let mut rejected_inconclusive = 0u64;
    let mut provider_confirmed_bundle_count = 0u64;
    let mut active_mints = BTreeMap::<String, Phase107fActiveMint>::new();
    let mut finalized_mints = BTreeSet::<String>::new();
    let health_dir = output_dir.join("health");
    fs::create_dir_all(&health_dir)?;
    phase107b_write_incremental_checkpoint(
        &output_dir,
        &run_id,
        &attempt_rows,
        &rejected_rows,
        &candidate_rows,
        &unavailable_rows,
    )?;
    phase107f_write_health(
        &health_dir,
        &run_id,
        "startup",
        &MaterialHunterStreamSummary::default(),
        attempt_rows.len(),
        active_mints.len(),
        rejected_rows.len(),
        candidate_rows.len(),
        true,
        "",
    )?;
    let interrupted = Arc::new(AtomicBool::new(false));
    {
        let interrupted = interrupted.clone();
        tokio::spawn(async move {
            let _ = tokio::signal::ctrl_c().await;
            interrupted.store(true, Ordering::SeqCst);
        });
    }
    #[cfg(unix)]
    {
        let interrupted = interrupted.clone();
        tokio::spawn(async move {
            if let Ok(mut signal) =
                tokio::signal::unix::signal(tokio::signal::unix::SignalKind::terminate())
            {
                signal.recv().await;
                interrupted.store(true, Ordering::SeqCst);
            }
        });
    }
    let last_r2_checkpoint_at = Arc::new(std::sync::Mutex::new(Instant::now()));
    if upload_r2 {
        let verified =
            phase107f_upload_r2_checkpoint(loaded, &output_dir, &run_id, verify_r2, "startup")
                .await?;
        if !verified {
            let interrupted_summary = json!({
                "schema_version": "phase107f.hunter_summary_interrupted.v1",
                "run_id": run_id,
                "interruption_reason": "r2_checkpoint_failed_startup",
                "last_attempt_index": 0,
                "last_tracked_mint": "",
                "attempted_launches": 0,
                "rejected_count": 0,
                "candidate_count": 0,
                "partial_outputs_r2_verified": false,
                "counted_phase107b_result": false,
                "off_vps_candidate_replay_allowed": false,
                "threshold_tuning_allowed": false,
                "generated_at": OffsetDateTime::now_utc(),
            });
            write_quant_json_md(
                &output_dir,
                "hunter_summary_interrupted",
                &interrupted_summary,
                format!(
                    "# Phase 107F Hunter Interrupted\n\n- run_id: `{run_id}`\n- interruption_reason: `r2_checkpoint_failed_startup`\n- counted_phase107b_result: `false`\n"
                ),
            )?;
            write_quant_json_md(
                &output_dir,
                "countability_decision",
                &interrupted_summary,
                format!(
                    "# Phase 107B Countability Decision\n\n- counted_phase107b_result: `false`\n- interruption_reason: `r2_checkpoint_failed_startup`\n- threshold_tuning_allowed: `false`\n"
                ),
            )?;
            bail!("material-candidate-hunter startup R2 checkpoint failed");
        }
    }

    let progress_counts = Arc::new(std::sync::Mutex::new((0usize, 0usize, 0usize, 0usize)));
    let interrupted_for_stream = interrupted.clone();
    let progress_counts_for_events = progress_counts.clone();
    let progress_counts_for_progress = progress_counts.clone();
    let health_dir_for_progress = health_dir.clone();
    let run_id_for_progress = run_id.clone();
    let output_dir_for_progress = output_dir.clone();
    let interrupted_for_progress = interrupted.clone();
    let last_r2_checkpoint_for_events = last_r2_checkpoint_at.clone();
    let last_r2_checkpoint_for_progress = last_r2_checkpoint_at.clone();
    let stream_summary = run_material_hunter_stream_with_progress(
        loaded,
        runtime::MaterialHunterStreamOptions { duration_seconds },
        |event, summary| {
            if interrupted_for_stream.load(Ordering::SeqCst) {
                return Ok(MaterialHunterStreamAction::Stop);
            }
            if let Ok(mut counts) = progress_counts_for_events.lock() {
                *counts = (
                    attempt_rows.len(),
                    active_mints.len(),
                    rejected_rows.len(),
                    candidate_rows.len(),
                );
            }
            phase107f_write_health(
                &health_dir,
                &run_id,
                "streaming",
                summary,
                attempt_rows.len(),
                active_mints.len(),
                rejected_rows.len(),
                candidate_rows.len(),
                true,
                "",
            )?;

            if is_successful_launch_create(&event)
                && attempt_rows.len() < max_attempted_launches.max(1)
                && !event_mint_string(&event)
                    .map(|mint| finalized_mints.contains(&mint) || active_mints.contains_key(&mint))
                    .unwrap_or(false)
            {
                if active_mints.len() < max_concurrent_tracked_mints {
                    let mint = event_mint_string(&event)
                        .ok_or_else(|| anyhow!("create event missing mint"))?;
                    let attempt_index = attempt_rows.len() + 1;
                    active_mints.insert(
                        mint.clone(),
                        Phase107fActiveMint::new(mint.clone(), event.clone(), attempt_index),
                    );
                    attempt_rows.push(json!({
                        "attempt_index": attempt_index,
                        "mint": mint,
                        "run_id": run_id,
                        "launch_timestamp": event_received_ts(&event),
                        "tracked_until_seconds": 0,
                        "final_state": "tracking_early",
                        "rejection_or_promotion_reason": "live_attempt_discovered",
                        "early_warning_families": "",
                        "rug_like_outcome_by_300s": false,
                        "survived_300s": false,
                        "survived_900s": false,
                        "survived_1800s": false,
                        "holder_rpc_used": false,
                        "rpc_mint_supply_canonical": false,
                        "r2_verified": false,
                        "local_artifact_size_bytes": phase107b_dir_size_bytes(&output_dir).unwrap_or(0),
                        "promoted_to_candidate_dataset": false,
                        "tombstone_written": false,
                    }));
                    phase107b_write_incremental_checkpoint(
                        &output_dir,
                        &run_id,
                        &attempt_rows,
                        &rejected_rows,
                        &candidate_rows,
                        &unavailable_rows,
                    )?;
                }
            }

            for active in active_mints.values_mut() {
                active.push_if_related(&event);
            }

            let mut finalized_now = Vec::<String>::new();
            for (mint, active) in active_mints.iter_mut() {
                if active.finalized || active.events.is_empty() {
                    continue;
                }
                let observed_horizon_seconds = active
                    .events
                    .iter()
                    .map(|event| {
                        (event.meta.received_at_wall_time - active.create.meta.received_at_wall_time)
                            .whole_seconds()
                            .max(0) as u64
                    })
                    .max()
                    .unwrap_or(0);
                if observed_horizon_seconds < 15 {
                    continue;
                }
                let analysis = phase107b_analyze_token(
                    loaded,
                    &risk_engine,
                    &run_id,
                    mint,
                    &active.create,
                    &active.events,
                    observed_horizon_seconds,
                    event.meta.received_at_wall_time,
                )?;
                let decision = phase107b_decide_token(
                    &analysis.post_event_rows,
                    &analysis.early_rule_rows,
                    analysis.observed_horizon_seconds,
                );
                let final_candidate_horizon = duration_seconds.min(1800).max(300);
                let should_finalize = decision.final_state == "early_rejected_dead"
                    || (decision.promoted && observed_horizon_seconds >= final_candidate_horizon)
                    || (observed_horizon_seconds >= 300
                        && decision.final_state.starts_with("early_rejected"));
                if !should_finalize && !decision.promoted {
                    continue;
                }
                if decision.provider_confirmed_bundle {
                    provider_confirmed_bundle_count = provider_confirmed_bundle_count.saturating_add(1);
                }
                if decision.final_state.starts_with("early_rejected") {
                    if decision.final_state == "early_rejected_dead" {
                        rejected_dead = rejected_dead.saturating_add(1);
                    } else {
                        rejected_inconclusive = rejected_inconclusive.saturating_add(1);
                    }
                    rejected_rows.push(json!({
                        "mint": mint,
                        "run_id": run_id,
                        "final_state": decision.final_state,
                        "rejection_class": decision.reason,
                        "stop_tracking_at_seconds": decision.tracked_until_seconds,
                        "early_warning_families": decision.early_warning_families.join("|"),
                        "holder_rpc_used": false,
                        "threshold_tuning_allowed": false,
                    }));
                    phase107b_write_rejected_token(
                        &output_dir,
                        &run_id,
                        mint,
                        &active.create,
                        &decision,
                        &analysis,
                    )?;
                } else if decision.promoted {
                    let mut wrote_candidate_checkpoint = false;
                    if decision.survived_300 && !active.candidate_300_written {
                        candidates_300 = candidates_300.saturating_add(1);
                        active.candidate_300_written = true;
                        wrote_candidate_checkpoint = true;
                    }
                    if decision.survived_900 && !active.candidate_900_written {
                        candidates_900 = candidates_900.saturating_add(1);
                        active.candidate_900_written = true;
                        wrote_candidate_checkpoint = true;
                    }
                    if decision.survived_1800 && !active.candidate_1800_written {
                        candidates_1800 = candidates_1800.saturating_add(1);
                        active.candidate_1800_written = true;
                        wrote_candidate_checkpoint = true;
                    }
                    let candidate_row = json!({
                        "mint": mint,
                        "run_id": run_id,
                        "final_state": if should_finalize { decision.final_state.clone() } else { format!("{}_checkpoint", decision.final_state) },
                        "promotion_reason": decision.reason,
                        "survived_300s": decision.survived_300,
                        "survived_900s": decision.survived_900,
                        "survived_1800s": decision.survived_1800,
                        "risk_timeline_rows": analysis.risk_timeline_rows.len(),
                        "pre_entry_risk_feature_rows": analysis.pre_entry_rows.len(),
                        "post_event_label_rows": analysis.post_event_rows.len(),
                        "holder_rpc_used": false,
                        "rpc_mint_supply_canonical": false,
                    });
                    if let Some(existing) = candidate_rows
                        .iter_mut()
                        .find(|row| row["mint"].as_str() == Some(mint.as_str()))
                    {
                        *existing = candidate_row;
                    } else {
                        candidate_rows.push(candidate_row);
                    }
                    if wrote_candidate_checkpoint || should_finalize {
                        phase107b_write_candidate_token(
                            &output_dir,
                            &run_id,
                            mint,
                            &active.create,
                            &decision,
                            &analysis,
                        )?;
                    }
                }
                for reason in &analysis.unavailable_reasons {
                    unavailable_rows.push(json!({
                        "mint": mint,
                        "run_id": run_id,
                        "unavailable_reason": reason,
                    }));
                }
                if let Some(row) = attempt_rows
                    .iter_mut()
                    .find(|row| row["attempt_index"].as_u64() == Some(active.attempt_index as u64))
                {
                    if let Some(map) = row.as_object_mut() {
                        map.insert("tracked_until_seconds".to_owned(), json!(decision.tracked_until_seconds));
                        map.insert("final_state".to_owned(), json!(decision.final_state));
                        map.insert("rejection_or_promotion_reason".to_owned(), json!(decision.reason));
                        map.insert(
                            "early_warning_families".to_owned(),
                            json!(decision.early_warning_families.join("|")),
                        );
                        map.insert("rug_like_outcome_by_300s".to_owned(), json!(decision.rug_like_by_300));
                        map.insert("survived_300s".to_owned(), json!(decision.survived_300));
                        map.insert("survived_900s".to_owned(), json!(decision.survived_900));
                        map.insert("survived_1800s".to_owned(), json!(decision.survived_1800));
                        map.insert(
                            "local_artifact_size_bytes".to_owned(),
                            json!(phase107b_dir_size_bytes(&output_dir).unwrap_or(0)),
                        );
                        map.insert("promoted_to_candidate_dataset".to_owned(), json!(decision.promoted && should_finalize));
                        map.insert("tombstone_written".to_owned(), json!(!decision.promoted && should_finalize));
                    }
                }
                if should_finalize {
                    active.finalized = true;
                    finalized_now.push(mint.clone());
                }
            }
            for mint in finalized_now {
                active_mints.remove(&mint);
                finalized_mints.insert(mint);
            }
            phase107b_write_incremental_checkpoint(
                &output_dir,
                &run_id,
                &attempt_rows,
                &rejected_rows,
                &candidate_rows,
                &unavailable_rows,
            )?;
            if upload_r2 {
                let due = last_r2_checkpoint_for_events
                    .lock()
                    .map(|last| last.elapsed() >= std::time::Duration::from_secs(300))
                    .unwrap_or(true);
                if due {
                    let verified = phase107f_upload_r2_checkpoint_blocking(
                        loaded,
                        &output_dir,
                        &run_id,
                        verify_r2,
                        "event_checkpoint",
                    )?;
                    if let Ok(mut last) = last_r2_checkpoint_for_events.lock() {
                        *last = Instant::now();
                    }
                    if !verified {
                        interrupted_for_stream.store(true, Ordering::SeqCst);
                        return Ok(MaterialHunterStreamAction::Stop);
                    }
                }
            }

            let candidate_total = if duration_seconds >= 1800 {
                candidates_1800
            } else if duration_seconds >= 900 {
                candidates_900
            } else {
                candidates_300
            } as usize;
            if candidate_total >= target_material_candidates
                || (attempt_rows.len() >= max_attempted_launches.max(1) && active_mints.is_empty())
            {
                return Ok(MaterialHunterStreamAction::Stop);
            }
            Ok(MaterialHunterStreamAction::Continue)
        },
        |summary| {
            let (attempted, active, rejected, candidates) = progress_counts_for_progress
                .lock()
                .map(|counts| *counts)
                .unwrap_or_default();
            let interrupted_now = interrupted_for_progress.load(Ordering::SeqCst);
            phase107f_write_health(
                &health_dir_for_progress,
                &run_id_for_progress,
                if interrupted_now { "interrupt_requested" } else { "provider_progress" },
                summary,
                attempted,
                active,
                rejected,
                candidates,
                !interrupted_now,
                if interrupted_now { "signal_interrupted" } else { "" },
            )?;
            if upload_r2 {
                let due = last_r2_checkpoint_for_progress
                    .lock()
                    .map(|last| last.elapsed() >= std::time::Duration::from_secs(300))
                    .unwrap_or(true);
                if due {
                    let verified = phase107f_upload_r2_checkpoint_blocking(
                        loaded,
                        &output_dir_for_progress,
                        &run_id_for_progress,
                        verify_r2,
                        "progress_checkpoint",
                    )?;
                    if let Ok(mut last) = last_r2_checkpoint_for_progress.lock() {
                        *last = Instant::now();
                    }
                    if !verified {
                        interrupted_for_progress.store(true, Ordering::SeqCst);
                        return Ok(MaterialHunterStreamAction::Stop);
                    }
                }
            }
            if interrupted_now {
                return Ok(MaterialHunterStreamAction::Stop);
            }
            Ok(MaterialHunterStreamAction::Continue)
        },
    )
    .await?;
    let interrupted_run = interrupted.load(Ordering::SeqCst);

    if !interrupted_run
        && stream_summary.transaction_updates
            + stream_summary.account_updates
            + stream_summary.slot_updates
            == 0
    {
        phase107f_write_health(
            &health_dir,
            &run_id,
            "provider_zero_updates",
            &stream_summary,
            attempt_rows.len(),
            active_mints.len(),
            rejected_rows.len(),
            candidate_rows.len(),
            false,
            "provider_zero_updates",
        )?;
        bail!(
            "material-candidate-hunter provider stream emitted zero updates; provider_status={}",
            stream_summary.provider_status
        );
    } else if !interrupted_run
        && stream_summary.transaction_updates
            + stream_summary.account_updates
            + stream_summary.slot_updates
            > 0
        && stream_summary.pump_create_decoded == 0
    {
        phase107f_write_health(
            &health_dir,
            &run_id,
            "no_launches_seen_but_stream_alive",
            &stream_summary,
            attempt_rows.len(),
            active_mints.len(),
            rejected_rows.len(),
            candidate_rows.len(),
            true,
            "no_launches_seen_but_stream_alive",
        )?;
    }

    for (_mint, active) in active_mints.iter() {
        let observed_horizon_seconds = active
            .events
            .iter()
            .map(|event| {
                (event.meta.received_at_wall_time - active.create.meta.received_at_wall_time)
                    .whole_seconds()
                    .max(0) as u64
            })
            .max()
            .unwrap_or(0);
        let analysis = phase107b_analyze_token(
            loaded,
            &risk_engine,
            &run_id,
            &active.mint,
            &active.create,
            &active.events,
            observed_horizon_seconds,
            OffsetDateTime::now_utc(),
        )?;
        let decision = Phase107bDecision {
            final_state: if interrupted_run {
                "terminal_inconclusive".to_owned()
            } else {
                "terminal_inconclusive".to_owned()
            },
            reason: if interrupted_run {
                "signal_interrupted_active_mint_finalized_inconclusive".to_owned()
            } else {
                "stream_slice_completed_before_terminal_gate".to_owned()
            },
            tracked_until_seconds: observed_horizon_seconds,
            early_warning_families: analysis
                .early_rule_rows
                .iter()
                .filter(|row| row["rule_fired"].as_bool().unwrap_or(false))
                .filter_map(|row| row["rule_id"].as_str().map(str::to_owned))
                .collect(),
            rug_like_by_300: false,
            survived_300: false,
            survived_900: false,
            survived_1800: false,
            promoted: false,
            provider_confirmed_bundle: false,
        };
        rejected_inconclusive = rejected_inconclusive.saturating_add(1);
        phase107b_write_rejected_token(
            &output_dir,
            &run_id,
            &active.mint,
            &active.create,
            &decision,
            &analysis,
        )?;
        rejected_rows.push(json!({
            "mint": active.mint,
            "run_id": run_id,
            "final_state": decision.final_state,
            "rejection_class": decision.reason,
            "stop_tracking_at_seconds": decision.tracked_until_seconds,
            "early_warning_families": decision.early_warning_families.join("|"),
            "holder_rpc_used": false,
            "threshold_tuning_allowed": false,
        }));
    }
    phase107b_write_incremental_checkpoint(
        &output_dir,
        &run_id,
        &attempt_rows,
        &rejected_rows,
        &candidate_rows,
        &unavailable_rows,
    )?;
    if interrupted_run {
        let interrupted_summary = json!({
            "schema_version": "phase107f.hunter_summary_interrupted.v1",
            "run_id": run_id,
            "interruption_reason": "signal_interrupted",
            "last_attempt_index": attempt_rows.len(),
            "last_tracked_mint": attempt_rows.last().and_then(|row| row["mint"].as_str()).unwrap_or(""),
            "attempted_launches": attempt_rows.len(),
            "rejected_count": rejected_rows.len(),
            "candidate_count": candidate_rows.len(),
            "partial_outputs_r2_verified": false,
            "counted_phase107b_result": false,
            "off_vps_candidate_replay_allowed": false,
            "threshold_tuning_allowed": false,
            "generated_at": OffsetDateTime::now_utc(),
        });
        write_quant_json_md(
            &output_dir,
            "hunter_summary_interrupted",
            &interrupted_summary,
            format!(
                "# Phase 107F Hunter Interrupted\n\n- run_id: `{run_id}`\n- attempted launches: `{}`\n- counted_phase107b_result: `false`\n",
                attempt_rows.len()
            ),
        )?;
    }

    write_json_rows_csv(
        &output_dir.join("attempt_ledger.csv"),
        &[
            "attempt_index",
            "mint",
            "run_id",
            "launch_timestamp",
            "tracked_until_seconds",
            "final_state",
            "rejection_or_promotion_reason",
            "early_warning_families",
            "rug_like_outcome_by_300s",
            "survived_300s",
            "survived_900s",
            "survived_1800s",
            "holder_rpc_used",
            "rpc_mint_supply_canonical",
            "r2_verified",
            "local_artifact_size_bytes",
            "promoted_to_candidate_dataset",
            "tombstone_written",
        ],
        &attempt_rows,
    )?;
    write_json_rows_csv(
        &output_dir.join("rejected_summary.csv"),
        &[
            "mint",
            "run_id",
            "final_state",
            "rejection_class",
            "stop_tracking_at_seconds",
            "early_warning_families",
            "holder_rpc_used",
            "threshold_tuning_allowed",
        ],
        &rejected_rows,
    )?;
    write_json_rows_csv(
        &output_dir.join("candidate_summary.csv"),
        &[
            "mint",
            "run_id",
            "final_state",
            "promotion_reason",
            "survived_300s",
            "survived_900s",
            "survived_1800s",
            "risk_timeline_rows",
            "pre_entry_risk_feature_rows",
            "post_event_label_rows",
            "holder_rpc_used",
            "rpc_mint_supply_canonical",
        ],
        &candidate_rows,
    )?;
    write_json_rows_csv(
        &output_dir.join("unavailable_reason_summary.csv"),
        &["mint", "run_id", "unavailable_reason"],
        &unavailable_rows,
    )?;

    let attempted_launches = attempt_rows.len() as u64;
    let hunter_summary = json!({
        "schema_version": "phase107b.hunter_summary.v1",
        "run_id": run_id,
        "attempted_launches": attempted_launches,
        "rejected_dead_count": rejected_dead,
        "rejected_inconclusive_count": rejected_inconclusive,
        "rejected_before_60s_count": rejected_rows.iter().filter(|row| row["stop_tracking_at_seconds"].as_u64().unwrap_or(0) <= 60).count(),
        "rejected_before_300s_count": rejected_rows.iter().filter(|row| row["stop_tracking_at_seconds"].as_u64().unwrap_or(0) <= 300).count(),
        "candidates_300s_count": candidates_300,
        "candidates_900s_count": candidates_900,
        "candidates_1800s_count": candidates_1800,
        "material_candidates_found": candidate_rows.len(),
        "target_material_candidates": target_material_candidates,
        "code_path_failures": 0,
        "missing_evidence_became_zero": false,
        "holder_rpc_used": false,
        "rpc_mint_supply_canonical": false,
        "provider_confirmed_bundle_count": provider_confirmed_bundle_count,
        "binary_malicious_labels_emitted": false,
        "threshold_tuning_allowed": false,
        "formal_backtesting_allowed": false,
        "interrupted_run": interrupted_run,
        "ready_for_off_vps_candidate_replay": !interrupted_run && !candidate_rows.is_empty(),
        "ready_for_large_strategy_dataset": false,
    });
    write_quant_json_md(
        &output_dir,
        "hunter_summary",
        &hunter_summary,
        format!(
            "# Phase 107B Material Candidate Hunter\n\n- run_id: `{run_id}`\n- attempted launches: `{attempted_launches}`\n- rejected/dead: `{rejected_dead}`\n- material candidates found: `{}`\n- holder RPC used: `false`\n- threshold tuning allowed: `false`\n",
            candidate_rows.len()
        ),
    )?;

    let policy = phase107b_dataset_separation_policy();
    write_quant_json_md(
        &output_dir,
        "dataset_separation_policy",
        &policy,
        "# Material Candidate Dataset Policy\n\nRejected/dead tokens are retained as compact tombstones only; promoted candidates receive richer artifacts. This phase does not tune or train.\n".to_owned(),
    )?;

    let manifest = json!({
        "schema_version": "phase107b.material_candidate_hunter_manifest.v1",
        "phase": "phase107b_replacement_after_retention_fix",
        "binary_commit": option_env!("GITHUB_SHA").unwrap_or("unknown"),
        "housekeeping_passed_before_hunter": true,
        "attempted_launches": attempted_launches,
        "rejected_dead_count": rejected_dead,
        "rejected_inconclusive_count": rejected_inconclusive,
        "candidates_300s_count": candidates_300,
        "candidates_900s_count": candidates_900,
        "candidates_1800s_count": candidates_1800,
        "holder_rpc_used": false,
        "rpc_mint_supply_canonical": false,
        "provider_confirmed_bundle_count": provider_confirmed_bundle_count,
        "binary_malicious_labels_emitted": false,
        "process_exit_code": if interrupted_run { 130 } else { 0 },
        "killed_by_oom_or_signal": interrupted_run,
        "resource_telemetry_available": output_dir.join("resource_telemetry.csv").exists(),
        "threshold_tuning_allowed": false,
        "ready_for_off_vps_candidate_replay": !interrupted_run && !candidate_rows.is_empty(),
        "generated_at": OffsetDateTime::now_utc(),
    });
    write_quant_json_md(
        &output_dir,
        "manifest",
        &manifest,
        "# Phase 107B Manifest\n\n- phase: `phase107b`\n- threshold_tuning_allowed: `false`\n"
            .to_owned(),
    )?;

    let mut r2_upload = json!({
        "schema_version": "phase107b.r2_upload_result.v1",
        "uploaded_files": [],
        "verified_files": [],
        "failed_files": [],
        "verified": false,
        "upload_requested": upload_r2,
    });
    let mut stable_manifest_upload = json!({
        "schema_version": "phase107b.stable_manifest_upload.v1",
        "key": "pump-launch-quant/research/material_candidate_hunter/manifest.json",
        "uploaded": false,
        "verified": false,
        "threshold_tuning_allowed": false,
    });
    if upload_r2 {
        r2_upload = upload_phase_report_dir_to_r2(
            loaded,
            &output_dir,
            "phase107b_material_candidate_hunter",
            &run_id,
            verify_r2,
        )
        .await?;
        write_quant_json_md(
            &output_dir,
            "r2_upload_result",
            &r2_upload,
            format!(
                "# Phase 107B R2 Upload\n\n- run_id: `{run_id}`\n- verified: `{}`\n- threshold_tuning_allowed: `false`\n",
                r2_upload["verified"]
            ),
        )?;
        stable_manifest_upload =
            phase107b_upload_stable_manifest(loaded, &output_dir, verify_r2).await?;
        write_quant_json_md(
            &output_dir,
            "stable_manifest_upload",
            &stable_manifest_upload,
            "# Phase 107B Stable Manifest Upload\n\n- key: `pump-launch-quant/research/material_candidate_hunter/manifest.json`\n- threshold_tuning_allowed: `false`\n".to_owned(),
        )?;
        if r2_upload["verified"].as_bool().unwrap_or(false) {
            for row in &mut attempt_rows {
                if let Some(map) = row.as_object_mut() {
                    map.insert("r2_verified".to_owned(), json!(true));
                }
            }
            write_json_rows_csv(
                &output_dir.join("attempt_ledger.csv"),
                &[
                    "attempt_index",
                    "mint",
                    "run_id",
                    "launch_timestamp",
                    "tracked_until_seconds",
                    "final_state",
                    "rejection_or_promotion_reason",
                    "early_warning_families",
                    "rug_like_outcome_by_300s",
                    "survived_300s",
                    "survived_900s",
                    "survived_1800s",
                    "holder_rpc_used",
                    "rpc_mint_supply_canonical",
                    "r2_verified",
                    "local_artifact_size_bytes",
                    "promoted_to_candidate_dataset",
                    "tombstone_written",
                ],
                &attempt_rows,
            )?;
        }
        let final_artifacts_exist = phase107b_required_final_artifacts_exist(&output_dir);
        let attempt_ledger_row_count_matches =
            phase107b_csv_data_row_count(&output_dir.join("attempt_ledger.csv"))
                .map(|rows| rows == attempted_launches as usize)
                .unwrap_or(false);
        let rejected_summary_reconciles =
            phase107b_csv_data_row_count(&output_dir.join("rejected_summary.csv"))
                .map(|rows| rows == rejected_rows.len())
                .unwrap_or(false);
        let candidate_summary_reconciles =
            phase107b_csv_data_row_count(&output_dir.join("candidate_summary.csv"))
                .map(|rows| rows == candidate_rows.len())
                .unwrap_or(false);
        let rejected_tombstones_exist = rejected_rows.iter().all(|row| {
            row["mint"]
                .as_str()
                .map(|mint| {
                    output_dir
                        .join("rejected")
                        .join(mint)
                        .join("dead_token_tombstone.json")
                        .exists()
                })
                .unwrap_or(false)
        });
        let candidate_artifacts_exist = candidate_rows.iter().all(|row| {
            row["mint"]
                .as_str()
                .map(|mint| {
                    let dir = output_dir.join("candidates").join(mint);
                    [
                        "token_summary.json",
                        "risk_timeline.csv",
                        "early_feature_timeline.csv",
                        "pre_entry_risk_features.csv",
                        "post_event_risk_labels.csv",
                        "bundle_like_evidence.csv",
                        "rug_dump_evidence.csv",
                    ]
                    .iter()
                    .all(|relative| dir.join(relative).exists())
                })
                .unwrap_or(false)
        });
        let no_dead_token_promoted = attempt_rows.iter().all(|row| {
            let final_state = row["final_state"].as_str().unwrap_or("");
            let promoted = row["promoted_to_candidate_dataset"]
                .as_bool()
                .unwrap_or(false);
            !(final_state.starts_with("early_rejected") && promoted)
        });
        let latest_checkpoint_verified =
            fs::read(output_dir.join("health").join("last_checkpoint.json"))
                .ok()
                .and_then(|bytes| serde_json::from_slice::<serde_json::Value>(&bytes).ok())
                .and_then(|value| value["r2_checkpoint_verified"].as_bool())
                .unwrap_or(false);
        let hard_invariants_passed = no_live_trading
            && no_rpc
            && manifest["rpc_mint_supply_canonical"].as_bool() == Some(false)
            && manifest["binary_malicious_labels_emitted"].as_bool() == Some(false)
            && attempt_ledger_row_count_matches
            && rejected_summary_reconciles
            && candidate_summary_reconciles
            && rejected_tombstones_exist
            && candidate_artifacts_exist
            && no_dead_token_promoted;
        let counted_phase107b_result = r2_upload["verified"].as_bool().unwrap_or(false)
            && final_artifacts_exist
            && hard_invariants_passed
            && latest_checkpoint_verified
            && attempted_launches > 0
            && !interrupted_run;
        let countability = json!({
            "schema_version": "phase107b.countability_decision.v1",
            "phase": "phase107b_replacement_after_retention_fix",
            "counted_phase107b_result": counted_phase107b_result,
            "hunter_exited_normally": !interrupted_run,
            "interrupted_run": interrupted_run,
            "process_exit_code": if interrupted_run { 130 } else { 0 },
            "final_artifacts_exist": final_artifacts_exist,
            "attempt_ledger_row_count_matches": attempt_ledger_row_count_matches,
            "attempted_launches_nonzero": attempted_launches > 0,
            "rejected_summary_reconciles": rejected_summary_reconciles,
            "candidate_summary_reconciles": candidate_summary_reconciles,
            "rejected_tombstones_exist": rejected_tombstones_exist,
            "candidate_artifacts_exist": candidate_artifacts_exist,
            "no_dead_token_promoted": no_dead_token_promoted,
            "latest_r2_checkpoint_verified": latest_checkpoint_verified,
            "r2_verified": r2_upload["verified"].as_bool().unwrap_or(false),
            "resource_telemetry_has_critical_failure": false,
            "hard_invariants_passed": hard_invariants_passed,
            "partial_outputs_audit_only": !counted_phase107b_result,
            "candidate_mints": candidate_rows.iter().filter_map(|row| row["mint"].as_str().map(ToOwned::to_owned)).collect::<Vec<_>>(),
            "off_vps_candidate_replay_allowed": counted_phase107b_result && !candidate_rows.is_empty(),
            "formal_backtesting_allowed": false,
            "threshold_tuning_allowed": false,
            "generated_at": OffsetDateTime::now_utc(),
        });
        write_quant_json_md(
            &output_dir,
            "countability_decision",
            &countability,
            format!(
                "# Phase 107B Countability Decision\n\n- counted_phase107b_result: `{}`\n- hunter_exited_normally: `true`\n- R2 verified: `{}`\n- candidates: `{}`\n- threshold_tuning_allowed: `false`\n",
                countability["counted_phase107b_result"],
                countability["r2_verified"],
                candidate_rows.len()
            ),
        )?;
        r2_upload = upload_phase_report_dir_to_r2(
            loaded,
            &output_dir,
            "phase107b_material_candidate_hunter",
            &run_id,
            verify_r2,
        )
        .await?;
    }

    let aggregate = json!({
        "command": "material-candidate-hunter",
        "run_id": run_id,
        "output_dir": output_dir.display().to_string(),
        "attempted_launches": attempted_launches,
        "material_candidates_found": candidate_rows.len(),
        "r2_upload_verified": r2_upload["verified"],
        "stable_manifest_verified": stable_manifest_upload["verified"],
        "threshold_tuning_allowed": false,
    });
    println!("{}", serde_json::to_string_pretty(&aggregate)?);
    Ok(())
}

#[derive(Debug, Clone)]
struct Phase107bTokenAnalysis {
    observed_horizon_seconds: u64,
    risk_timeline_rows: Vec<serde_json::Value>,
    pre_entry_rows: Vec<serde_json::Value>,
    post_event_rows: Vec<serde_json::Value>,
    early_rule_rows: Vec<serde_json::Value>,
    source_field_rows: Vec<serde_json::Value>,
    stream_metric_rows: Vec<serde_json::Value>,
    holder_invariant_rows: Vec<serde_json::Value>,
    curve_invariant_rows: Vec<serde_json::Value>,
    bundle_rows: Vec<serde_json::Value>,
    rug_rows: Vec<serde_json::Value>,
    metadata_funding_rows: Vec<serde_json::Value>,
    unavailable_reasons: Vec<String>,
}

#[derive(Debug, Clone)]
struct Phase107bDecision {
    final_state: String,
    reason: String,
    tracked_until_seconds: u64,
    early_warning_families: Vec<String>,
    rug_like_by_300: bool,
    survived_300: bool,
    survived_900: bool,
    survived_1800: bool,
    promoted: bool,
    provider_confirmed_bundle: bool,
}

fn phase107b_write_incremental_checkpoint(
    output_dir: &Path,
    run_id: &str,
    attempt_rows: &[serde_json::Value],
    rejected_rows: &[serde_json::Value],
    candidate_rows: &[serde_json::Value],
    unavailable_rows: &[serde_json::Value],
) -> Result<()> {
    write_json_rows_csv(
        &output_dir.join("attempt_ledger.csv"),
        &[
            "attempt_index",
            "mint",
            "run_id",
            "launch_timestamp",
            "tracked_until_seconds",
            "final_state",
            "rejection_or_promotion_reason",
            "early_warning_families",
            "rug_like_outcome_by_300s",
            "survived_300s",
            "survived_900s",
            "survived_1800s",
            "holder_rpc_used",
            "rpc_mint_supply_canonical",
            "r2_verified",
            "local_artifact_size_bytes",
            "promoted_to_candidate_dataset",
            "tombstone_written",
        ],
        attempt_rows,
    )?;
    write_json_rows_csv(
        &output_dir.join("rejected_summary_partial.csv"),
        &[
            "mint",
            "run_id",
            "final_state",
            "rejection_class",
            "stop_tracking_at_seconds",
            "early_warning_families",
            "holder_rpc_used",
            "threshold_tuning_allowed",
        ],
        rejected_rows,
    )?;
    write_json_rows_csv(
        &output_dir.join("candidate_summary_partial.csv"),
        &[
            "mint",
            "run_id",
            "final_state",
            "promotion_reason",
            "survived_300s",
            "survived_900s",
            "survived_1800s",
            "risk_timeline_rows",
            "pre_entry_risk_feature_rows",
            "post_event_label_rows",
            "holder_rpc_used",
            "rpc_mint_supply_canonical",
        ],
        candidate_rows,
    )?;
    write_json_rows_csv(
        &output_dir.join("unavailable_reason_summary_partial.csv"),
        &["mint", "run_id", "unavailable_reason"],
        unavailable_rows,
    )?;
    let partial = json!({
        "schema_version": "phase107e.countability_decision_partial.v1",
        "run_id": run_id,
        "attempts_written": attempt_rows.len(),
        "candidate_count": candidate_rows.len(),
        "rejected_count": rejected_rows.len(),
        "counted_phase107b_result": false,
        "partial_outputs_audit_only": true,
        "off_vps_candidate_replay_allowed": false,
        "threshold_tuning_allowed": false,
        "updated_at": OffsetDateTime::now_utc(),
    });
    fs::write(
        output_dir.join("countability_decision_partial.json"),
        serde_json::to_vec_pretty(&partial)?,
    )?;
    write_report(
        &output_dir.join("progress_heartbeat.md"),
        &format!(
            "# Phase 107E Hunter Progress\n\n- run_id: `{run_id}`\n- attempts_written: `{}`\n- candidates: `{}`\n- rejected: `{}`\n- counted_phase107b_result: `false`\n",
            attempt_rows.len(),
            candidate_rows.len(),
            rejected_rows.len()
        ),
    )?;
    fs::write(
        output_dir.join("progress_heartbeat.json"),
        serde_json::to_vec_pretty(&json!({
            "schema_version": "phase107e.progress_heartbeat.v1",
            "run_id": run_id,
            "attempts_written": attempt_rows.len(),
            "candidate_count": candidate_rows.len(),
            "rejected_count": rejected_rows.len(),
            "holder_rpc_used": false,
            "rpc_mint_supply_canonical": false,
            "threshold_tuning_allowed": false,
            "updated_at": OffsetDateTime::now_utc(),
        }))?,
    )?;
    fs::write(
        output_dir.join("progress_manifest.json"),
        serde_json::to_vec_pretty(&json!({
            "schema_version": "phase107f.progress_manifest.v1",
            "run_id": run_id,
            "attempt_ledger_exists": output_dir.join("attempt_ledger.csv").exists(),
            "attempts_written": attempt_rows.len(),
            "candidate_count": candidate_rows.len(),
            "rejected_count": rejected_rows.len(),
            "countability_decision_partial_exists": output_dir.join("countability_decision_partial.json").exists(),
            "holder_rpc_used": false,
            "rpc_mint_supply_canonical": false,
            "binary_malicious_labels_emitted": false,
            "threshold_tuning_allowed": false,
            "updated_at": OffsetDateTime::now_utc(),
        }))?,
    )?;
    Ok(())
}

fn phase107b_scoped_events_for_mint(
    mint: &str,
    create: &NormalizedEvent,
    events: &[NormalizedEvent],
) -> Vec<NormalizedEvent> {
    let related_signatures = events
        .iter()
        .filter(|event| event_mint_string(event).as_deref() == Some(mint))
        .filter_map(event_signature_string)
        .collect::<BTreeSet<_>>();
    let mut scoped = events
        .iter()
        .filter(|event| {
            event_mint_string(event).as_deref() == Some(mint)
                || matches!(&event.payload, EventPayload::ObservedTransaction(payload)
                    if payload.signature_hint.as_ref().map(|sig| related_signatures.contains(sig)).unwrap_or(false)
                        || event.meta.slot == create.meta.slot)
        })
        .cloned()
        .collect::<Vec<_>>();
    scoped.sort_by_key(|event| {
        (
            event.meta.received_at_wall_time,
            event.meta.slot,
            event.meta.event_id.0,
        )
    });
    scoped
}

fn phase107b_analyze_token(
    loaded: &LoadedConfig,
    risk_engine: &DiagnosticRiskEngine,
    run_id: &str,
    mint: &str,
    create: &NormalizedEvent,
    scoped_events: &[NormalizedEvent],
    duration_seconds: u64,
    collection_end_at: OffsetDateTime,
) -> Result<Phase107bTokenAnalysis> {
    let launch_at = create.meta.received_at_wall_time;
    let windows = [15u64, 30, 60, 120, 180, 300, 900, 1800];
    let mut risk_timeline_rows = Vec::new();
    let mut pre_entry_rows = Vec::new();
    let mut early_rule_rows = Vec::new();
    let mut bundle_rows = Vec::new();
    let mut rug_rows = Vec::new();
    let mut metadata_funding_rows = Vec::new();
    let mut all_evidence = Vec::<RiskEvidence>::new();
    let mut final_state_engine = StateEngine::new(loaded.config.ttl.clone());
    for event in scoped_events {
        final_state_engine.apply_event(event)?;
    }
    let final_snapshot = final_state_engine.snapshot();
    let post_event_rows = build_post_event_risk_labels(run_id, mint, &final_snapshot)?;
    let scoped_horizon_seconds = scoped_events
        .iter()
        .map(|event| {
            (event.meta.received_at_wall_time - launch_at)
                .whole_seconds()
                .max(0) as u64
        })
        .max()
        .unwrap_or(0);
    let collection_horizon_seconds = (collection_end_at - launch_at).whole_seconds().max(0) as u64;
    let observed_horizon_seconds = scoped_horizon_seconds
        .max(collection_horizon_seconds)
        .min(duration_seconds);

    for window in windows {
        if window > duration_seconds && duration_seconds < 300 {
            continue;
        }
        let cutoff = launch_at + time::Duration::seconds(window as i64);
        let window_events = scoped_events
            .iter()
            .filter(|event| event.meta.received_at_wall_time <= cutoff)
            .cloned()
            .collect::<Vec<_>>();
        let mut state_engine = StateEngine::new(loaded.config.ttl.clone());
        for event in &window_events {
            state_engine.apply_event(event)?;
        }
        let snapshot = state_engine.snapshot();
        let Some(token) = snapshot.tokens.get(mint) else {
            early_rule_rows.push(json!({
                "source_run_id": run_id,
                "mint": mint,
                "window_seconds": window,
                "rule_id": "token_state_unavailable",
                "rule_fired": false,
                "unavailable_reason": "token_state_unavailable_at_window",
                "can_use_pre_entry": true,
            }));
            continue;
        };
        let bundle_context = stream_bundle_context(mint, create.meta.slot, &window_events);
        let input = risk_input_from_token(mint, token, &bundle_context);
        let output = risk_engine.evaluate(input);
        risk_timeline_rows.push(json!({
            "source_run_id": run_id,
            "mint": mint,
            "window_seconds": window,
            "available_at_slot": window_events.last().map(|event| event.meta.slot).unwrap_or(create.meta.slot),
            "available_at_timestamp": cutoff.to_string(),
            "risk_score_total": decimal_to_json(Some(output.risk_score_total)),
            "risk_classification": format!("{:?}", output.risk_classification),
            "risk_evidence_count": output.risk_evidence_count,
            "denominator_source_for_market_cap": output.denominator_source_for_market_cap.clone(),
            "denominator_source_for_holder_pct": output.denominator_source_for_holder_pct.clone(),
            "rpc_supply_diagnostic_only": output.rpc_supply_diagnostic_only,
            "supply_denominator_policy_version": output.supply_denominator_policy_version.clone(),
            "holder_rpc_used": false,
            "rpc_mint_supply_canonical": false,
        }));
        for evidence in &output.evidence {
            let row = json!({
                "source_run_id": run_id,
                "mint": mint,
                "risk_id": evidence.risk_id,
                "risk_family": evidence.risk_family,
                "source": format!("{:?}", evidence.source),
                "feature_time_class": risk_time_role_label(evidence.time_role),
                "available_at_slot": window_events.last().map(|event| event.meta.slot).unwrap_or(create.meta.slot),
                "available_at_timestamp": cutoff.to_string(),
                "can_use_pre_entry": evidence.time_role.pre_entry_safe(),
                "can_use_for_backtest": evidence.score.is_some(),
                "can_use_for_tuning": false,
                "score": decimal_to_json(evidence.score),
                "confidence": decimal_to_json(Some(evidence.confidence)),
                "unavailable_reason": evidence.unavailable_reason.clone().unwrap_or_default(),
                "evidence": evidence.evidence.join("|"),
                "denominator_source_for_market_cap": output.denominator_source_for_market_cap.clone(),
                "denominator_source_for_holder_pct": output.denominator_source_for_holder_pct.clone(),
                "rpc_supply_diagnostic_only": output.rpc_supply_diagnostic_only,
                "supply_semantics_status": output.supply_semantics_status.clone(),
                "supply_mismatch_ratio": decimal_to_json(output.supply_mismatch_ratio),
                "supply_denominator_policy_version": output.supply_denominator_policy_version.clone(),
                "rpc_mint_supply_canonical": false,
                "provider_confirmed_bundle": false,
                "holder_rpc_used": false,
            });
            if evidence.time_role.pre_entry_safe() {
                pre_entry_rows.push(row.clone());
            }
            if evidence.risk_family.contains("bundle") {
                bundle_rows.push(row.clone());
            }
            if evidence.risk_family.contains("dev")
                || evidence.risk_family.contains("holder")
                || evidence.risk_family.contains("fake")
                || evidence.risk_family.contains("sell")
                || evidence.risk_family.contains("data_quality")
            {
                rug_rows.push(row.clone());
            }
            if evidence.risk_family.contains("metadata")
                || evidence.risk_family.contains("funding")
                || evidence.risk_family.contains("supply")
            {
                metadata_funding_rows.push(row.clone());
            }
        }
        all_evidence.extend(output.evidence);

        let window_labels = build_post_event_risk_labels(run_id, mint, &snapshot)?;
        early_rule_rows.extend(phase107b_rule_rows_from_window(
            run_id,
            mint,
            window,
            token,
            &bundle_context,
            &window_labels,
        ));
    }
    validate_no_post_event_pre_entry_leak(&all_evidence)
        .map_err(|err| anyhow!("Phase 107B time-safety gate failed: {err}"))?;
    for row in &post_event_rows {
        if row["can_use_pre_entry"].as_bool().unwrap_or(false) {
            bail!("post-event label leaked into Phase 107B pre-entry feature set");
        }
    }

    let source_field_rows = vec![json!({
        "source_run_id": run_id,
        "mint": mint,
        "holder_count_source": "stream_owner_summed_token_accounts",
        "top_holder_source": "stream_owner_summed_token_accounts",
        "dev_holding_source": "stream_owner_summed_token_accounts",
        "holder_rpc_used": false,
        "holder_rpc_required": false,
        "rpc_mint_supply_canonical": false,
        "supply_denominator_policy_version": "phase102.supply_denominator.v1",
    })];
    let stream_metric_rows = vec![json!({
        "source_run_id": run_id,
        "mint": mint,
        "stream_metrics_computed": true,
        "holder_rpc_used": false,
        "no_live_orders": true,
        "threshold_tuning_allowed": false,
    })];
    let holder_invariant_rows = vec![json!({
        "source_run_id": run_id,
        "mint": mint,
        "holder_invariant_status": "stream_owner_summed_checked",
        "holder_rpc_used": false,
    })];
    let curve_invariant_rows = vec![json!({
        "source_run_id": run_id,
        "mint": mint,
        "curve_progress_denominator": "bonding_curve_real_reserves_and_curve_economic_supply",
        "rpc_mint_supply_canonical": false,
    })];
    let unavailable_reasons = early_rule_rows
        .iter()
        .filter_map(|row| row["unavailable_reason"].as_str())
        .filter(|value| !value.is_empty())
        .map(str::to_owned)
        .collect::<BTreeSet<_>>()
        .into_iter()
        .collect::<Vec<_>>();
    Ok(Phase107bTokenAnalysis {
        observed_horizon_seconds,
        risk_timeline_rows,
        pre_entry_rows,
        post_event_rows,
        early_rule_rows,
        source_field_rows,
        stream_metric_rows,
        holder_invariant_rows,
        curve_invariant_rows,
        bundle_rows,
        rug_rows,
        metadata_funding_rows,
        unavailable_reasons,
    })
}

fn phase107b_rule_rows_from_window(
    run_id: &str,
    mint: &str,
    window: u64,
    token: &state::TokenState,
    bundle: &StreamBundleContext,
    labels: &[serde_json::Value],
) -> Vec<serde_json::Value> {
    let buy_count = token.trade_stats.buy_count;
    let sell_count = token.trade_stats.sell_count;
    let holder_churn = token.holder_state.holder_churn_rate;
    let holder_collapse = holder_churn >= Decimal::new(50, 2);
    let no_buy_followthrough = buy_count <= 1 && sell_count > 0;
    let volume_evaporated = phase107b_label_bool(labels, "volume_evaporated").unwrap_or(false);
    let rapid_collapse_80 = phase107b_label_bool(labels, "rapid_collapse_80pct").unwrap_or(false);
    let rapid_collapse_95 = phase107b_label_bool(labels, "rapid_collapse_95pct").unwrap_or(false);
    let top_holder_or_dev_dumped =
        phase107b_label_bool(labels, "top_holder_or_dev_dumped").unwrap_or(false);
    let liquidity_exit_proxy =
        phase107b_label_bool(labels, "liquidity_exit_proxy").unwrap_or(false);
    let bundle_with_concentration =
        bundle.same_slot_tx_count > 0 && token.holder_state.nonzero_holder_count <= 3;
    [
        (
            "no_buy_followthrough_by_30s",
            window >= 30 && no_buy_followthrough,
        ),
        (
            "no_buy_followthrough_by_60s",
            window >= 60 && no_buy_followthrough,
        ),
        (
            "volume_evaporated_by_60s",
            window >= 60 && volume_evaporated,
        ),
        ("holder_collapse_by_60s", window >= 60 && holder_collapse),
        (
            "top_holder_or_dev_dump_before_180s",
            window >= 180 && top_holder_or_dev_dumped,
        ),
        (
            "same_slot_bundle_like_plus_holder_concentration",
            window >= 15 && bundle_with_concentration,
        ),
        (
            "liquidity_exit_proxy_before_300s",
            window >= 300 && liquidity_exit_proxy,
        ),
        ("rapid_collapse_80pct", rapid_collapse_80),
        ("rapid_collapse_95pct", rapid_collapse_95),
    ]
    .into_iter()
    .map(|(rule_id, fired)| {
        json!({
            "source_run_id": run_id,
            "mint": mint,
            "window_seconds": window,
            "rule_id": rule_id,
            "rule_fired": fired,
            "buy_count": buy_count,
            "sell_count": sell_count,
            "holder_count": token.holder_state.nonzero_holder_count,
            "holder_churn_rate": decimal_to_json(Some(holder_churn)),
            "same_slot_tx_count": bundle.same_slot_tx_count,
            "stream_bundle_like_only": rule_id == "same_slot_bundle_like_plus_holder_concentration",
            "unavailable_reason": "",
            "can_use_pre_entry": true,
            "threshold_tuning_allowed": false,
        })
    })
    .collect()
}

fn phase107b_decide_token(
    labels: &[serde_json::Value],
    early_rule_rows: &[serde_json::Value],
    duration_seconds: u64,
) -> Phase107bDecision {
    let mut early_warning_families = early_rule_rows
        .iter()
        .filter(|row| row["rule_fired"].as_bool().unwrap_or(false))
        .filter_map(|row| row["rule_id"].as_str())
        .filter(|rule| *rule != "same_slot_bundle_like_plus_holder_concentration")
        .map(str::to_owned)
        .collect::<BTreeSet<_>>()
        .into_iter()
        .collect::<Vec<_>>();
    let bundle_only_fired = early_rule_rows.iter().any(|row| {
        row["rule_id"].as_str() == Some("same_slot_bundle_like_plus_holder_concentration")
            && row["rule_fired"].as_bool().unwrap_or(false)
    });
    let rug_like = phase107b_label_bool(labels, "rug_like_outcome").unwrap_or(false);
    let dead_60 = phase107b_label_bool(labels, "dead_within_60s").unwrap_or(false);
    let dead_180 = phase107b_label_bool(labels, "dead_within_180s").unwrap_or(false);
    let dead_300 = phase107b_label_bool(labels, "dead_within_300s").unwrap_or(false);
    let collapse_80 = phase107b_label_bool(labels, "rapid_collapse_80pct").unwrap_or(false);
    let collapse_95 = phase107b_label_bool(labels, "rapid_collapse_95pct").unwrap_or(false);
    let no_buy = phase107b_label_bool(labels, "no_buy_followthrough").unwrap_or(false);
    let volume_evaporated = phase107b_label_bool(labels, "volume_evaporated").unwrap_or(false);
    let holder_collapse = phase107b_label_bool(labels, "holder_collapse").unwrap_or(false);
    let dump = phase107b_label_bool(labels, "top_holder_or_dev_dumped").unwrap_or(false);
    let liquidity_exit = phase107b_label_bool(labels, "liquidity_exit_proxy").unwrap_or(false);
    let rug_like_by_300 = dead_60
        || dead_180
        || dead_300
        || collapse_80
        || collapse_95
        || no_buy
        || volume_evaporated
        || holder_collapse
        || dump
        || liquidity_exit
        || rug_like;
    if rug_like_by_300 {
        let reason = if dead_60 || collapse_95 {
            "rug_like_by_60s"
        } else if volume_evaporated {
            "volume_evaporated"
        } else if no_buy {
            "no_buy_followthrough"
        } else if holder_collapse {
            "holder_collapse"
        } else if dump {
            "top_holder_or_dev_dumped"
        } else if liquidity_exit {
            "liquidity_exit_proxy"
        } else {
            "rug_like_by_300s"
        };
        if early_warning_families.is_empty() && bundle_only_fired {
            early_warning_families
                .push("bundle_like_stream_signal_recorded_not_auto_rejected".to_owned());
        }
        return Phase107bDecision {
            final_state: "early_rejected_dead".to_owned(),
            reason: reason.to_owned(),
            tracked_until_seconds: if dead_60 || collapse_95 || volume_evaporated || no_buy {
                60
            } else if dump {
                180
            } else {
                300
            },
            early_warning_families,
            rug_like_by_300: true,
            survived_300: false,
            survived_900: false,
            survived_1800: false,
            promoted: false,
            provider_confirmed_bundle: false,
        };
    }
    let outcome_label_available = labels.iter().any(|row| {
        row["label_id"].as_str() == Some("rug_like_outcome")
            && row["unavailable_reason"].as_str().unwrap_or("").is_empty()
    });
    if !outcome_label_available {
        return Phase107bDecision {
            final_state: "early_rejected_unavailable_required_data".to_owned(),
            reason: "inconclusive_missing_required_data".to_owned(),
            tracked_until_seconds: duration_seconds.min(300),
            early_warning_families,
            rug_like_by_300: false,
            survived_300: false,
            survived_900: false,
            survived_1800: false,
            promoted: false,
            provider_confirmed_bundle: false,
        };
    }
    if duration_seconds < 300 {
        return Phase107bDecision {
            final_state: "terminal_inconclusive".to_owned(),
            reason: "insufficient_observed_horizon_for_300s_promotion".to_owned(),
            tracked_until_seconds: duration_seconds,
            early_warning_families,
            rug_like_by_300: false,
            survived_300: false,
            survived_900: false,
            survived_1800: false,
            promoted: false,
            provider_confirmed_bundle: false,
        };
    }
    Phase107bDecision {
        final_state: if duration_seconds >= 1800 {
            "material_candidate_1800s".to_owned()
        } else if duration_seconds >= 900 {
            "material_candidate_900s".to_owned()
        } else {
            "survived_300s_candidate".to_owned()
        },
        reason: "survived_early_death_gates".to_owned(),
        tracked_until_seconds: duration_seconds.min(1800).max(300),
        early_warning_families,
        rug_like_by_300: false,
        survived_300: true,
        survived_900: duration_seconds >= 900,
        survived_1800: duration_seconds >= 1800,
        promoted: true,
        provider_confirmed_bundle: false,
    }
}

fn phase107b_label_bool(labels: &[serde_json::Value], label_id: &str) -> Option<bool> {
    labels
        .iter()
        .find(|row| row["label_id"].as_str() == Some(label_id))
        .and_then(|row| row["value"].as_bool())
}

fn phase107b_write_rejected_token(
    output_dir: &Path,
    run_id: &str,
    mint: &str,
    create: &NormalizedEvent,
    decision: &Phase107bDecision,
    analysis: &Phase107bTokenAnalysis,
) -> Result<()> {
    let dir = output_dir.join("rejected").join(mint);
    fs::create_dir_all(&dir)?;
    write_json_rows_csv(
        &dir.join("early_rule_snapshot.csv"),
        &[
            "source_run_id",
            "mint",
            "window_seconds",
            "rule_id",
            "rule_fired",
            "buy_count",
            "sell_count",
            "holder_count",
            "holder_churn_rate",
            "same_slot_tx_count",
            "stream_bundle_like_only",
            "unavailable_reason",
            "can_use_pre_entry",
            "threshold_tuning_allowed",
        ],
        &analysis.early_rule_rows,
    )?;
    write_json_rows_csv(
        &dir.join("rejection_evidence.csv"),
        &[
            "source_run_id",
            "mint",
            "risk_id",
            "risk_family",
            "source",
            "feature_time_class",
            "available_at_slot",
            "available_at_timestamp",
            "can_use_pre_entry",
            "can_use_for_backtest",
            "can_use_for_tuning",
            "score",
            "confidence",
            "unavailable_reason",
            "evidence",
            "denominator_source_for_market_cap",
            "denominator_source_for_holder_pct",
            "rpc_supply_diagnostic_only",
            "supply_semantics_status",
            "supply_mismatch_ratio",
            "supply_denominator_policy_version",
            "rpc_mint_supply_canonical",
            "provider_confirmed_bundle",
            "holder_rpc_used",
        ],
        &analysis.rug_rows,
    )?;
    let tombstone = json!({
        "schema_version": "phase107b.dead_token_tombstone.v1",
        "mint": mint,
        "run_id": run_id,
        "launch_timestamp": event_received_ts(create),
        "launch_slot": create.meta.slot,
        "launch_signature": event_signature_string(create),
        "stop_tracking_at_seconds": decision.tracked_until_seconds,
        "rejection_class": decision.reason,
        "final_state": decision.final_state,
        "early_warning_families": decision.early_warning_families,
        "unavailable_reasons": analysis.unavailable_reasons,
        "r2_verification_status": "uploaded_in_phase_report_if_requested",
        "no_live_orders": true,
        "holder_rpc_used": false,
        "rpc_mint_supply_canonical": false,
        "threshold_tuning_allowed": false,
    });
    write_quant_json_md(
        &dir,
        "dead_token_tombstone",
        &tombstone,
        format!(
            "# Dead Token Tombstone\n\n- mint: `{mint}`\n- stop_tracking_at_seconds: `{}`\n- rejection_class: `{}`\n- holder_rpc_used: `false`\n",
            decision.tracked_until_seconds, decision.reason
        ),
    )
}

