fn write_run_summary_csv(
    path: &Path,
    loaded: &LoadedConfig,
    run_id: &str,
    metadata: Option<&StoredRecord<storage::RunMetadata>>,
    events: &[StoredRecord<NormalizedEvent>],
    decisions: &[StoredRecord<common::TradeDecisionEvent>],
    fills: &[StoredRecord<FillEvent>],
    replay_equivalence_status: Option<bool>,
) -> Result<()> {
    let mut file = create_csv_file(path)?;
    let source_summary =
        source_specific_early_intent_summary(loaded, run_id, metadata, events, fills)?;
    let stream_only_summary = stream_only_run_summary(loaded, run_id, metadata)?;
    let deshred_enabled = metadata
        .map(|record| {
            record.record.notes.iter().any(|note| {
                note == "with_deshred=true"
                    || note == "mode=real_geyser+deshred"
                    || note == "mock_deshred=true"
            })
        })
        .unwrap_or(false)
        || source_summary.deshred_connected
        || source_summary.deshred_tentative_sells_total > 0;
    writeln!(
        file,
        "run_id,run_kind,run_role,source_run_id,calibration_snapshot_hash,post_run_calibration_hash,contains_tentative_sell_events,contains_shred_exit_defense_events,tentative_sell_count,emergency_exit_count,saved_loss_total,opportunity_cost_total,false_positive_count,decode_mismatch_count,reorg_count,not_seen_count,deshred_enabled,deshred_supported,deshred_connected,deshred_provider_status,deshred_events_received,deshred_tentative_sell_count,deshred_false_positive_count,deshred_saved_loss_total,early_intent_sources_active,raw_shred_supported,raw_shred_connected,mock_early_intent_active,source_dedup_count,stream_only_enabled,rpc_network_calls_total,rpc_credits_used_total,rpc_denials_total,stream_only_passed,market_data_rpc_calls_allowed,holder_rpc_calls_allowed,metadata_fetch_allowed,confirmation_rpc_allowed,blockhash_rpc_allowed,replay_equivalence_status"
    )?;
    let source_run_id = metadata
        .and_then(|record| record.record.source_run_id.clone())
        .unwrap_or_else(|| run_id.to_owned());
    let row = vec![
        csv_field(run_id),
        csv_field(
            &metadata
                .map(|record| json_enum_label(&record.record.run_kind))
                .unwrap_or_else(|| "unknown".to_owned()),
        ),
        csv_field(
            &metadata
                .map(|record| json_enum_label(&record.record.run_role))
                .unwrap_or_else(|| "unknown".to_owned()),
        ),
        csv_field(&source_run_id),
        csv_field(
            metadata
                .and_then(|record| record.record.calibration_snapshot_hash.as_deref())
                .unwrap_or(""),
        ),
        csv_field(
            metadata
                .and_then(|record| record.record.post_run_calibration_hash.as_deref())
                .unwrap_or(""),
        ),
        metadata
            .map(|record| record.record.contains_tentative_sell_events)
            .unwrap_or(false)
            .to_string(),
        metadata
            .map(|record| record.record.contains_shred_exit_defense_events)
            .unwrap_or(false)
            .to_string(),
        metadata
            .map(|record| record.record.tentative_sell_count)
            .unwrap_or_else(|| {
                events
                    .iter()
                    .filter(|record| {
                        matches!(
                            record.record.payload,
                            EventPayload::TentativeSellIntentDetected(_)
                        )
                    })
                    .count() as u64
            })
            .to_string(),
        metadata
            .map(|record| record.record.emergency_exit_count)
            .unwrap_or_else(|| {
                decisions
                    .iter()
                    .filter(|record| {
                        matches!(record.record.decision, common::TradeDecision::EmergencyExit)
                    })
                    .count() as u64
            })
            .to_string(),
        metadata
            .map(|record| record.record.saved_loss_total)
            .unwrap_or(Decimal::ZERO)
            .to_string(),
        metadata
            .map(|record| record.record.opportunity_cost_total)
            .unwrap_or(Decimal::ZERO)
            .to_string(),
        metadata
            .map(|record| record.record.false_positive_count)
            .unwrap_or_default()
            .to_string(),
        metadata
            .map(|record| record.record.decode_mismatch_count)
            .unwrap_or_default()
            .to_string(),
        metadata
            .map(|record| record.record.reorg_count)
            .unwrap_or_default()
            .to_string(),
        metadata
            .map(|record| record.record.not_seen_count)
            .unwrap_or_default()
            .to_string(),
        deshred_enabled.to_string(),
        source_summary.deshred_supported.to_string(),
        source_summary.deshred_connected.to_string(),
        csv_field(&source_summary.deshred_provider_status),
        source_summary.deshred_events_received.to_string(),
        source_summary.deshred_tentative_sells_total.to_string(),
        source_summary.deshred_false_positive_total.to_string(),
        source_summary.deshred_saved_loss_quote_total.to_string(),
        csv_field(&source_summary.early_intent_sources_active.join("|")),
        source_summary.raw_shred_supported.to_string(),
        source_summary.raw_shred_connected.to_string(),
        source_summary.mock_early_intent_active.to_string(),
        source_summary.source_dedup_count.to_string(),
        stream_only_summary.stream_only_enabled.to_string(),
        stream_only_summary.rpc_network_calls_total.to_string(),
        stream_only_summary.rpc_credits_used_total.to_string(),
        stream_only_summary.rpc_denials_total.to_string(),
        stream_only_summary.stream_only_passed.to_string(),
        stream_only_summary
            .market_data_rpc_calls_allowed
            .to_string(),
        stream_only_summary.holder_rpc_calls_allowed.to_string(),
        stream_only_summary.metadata_fetch_allowed.to_string(),
        stream_only_summary.confirmation_rpc_allowed.to_string(),
        stream_only_summary.blockhash_rpc_allowed.to_string(),
        csv_field(
            &replay_equivalence_status
                .map(|value| value.to_string())
                .unwrap_or_default(),
        ),
    ];
    writeln!(file, "{}", row.join(","))?;
    Ok(())
}

fn write_data_gaps_csv(
    path: &Path,
    run_id: &str,
    metadata: Option<&StoredRecord<storage::RunMetadata>>,
    events: &[StoredRecord<NormalizedEvent>],
) -> Result<()> {
    let mut file = create_csv_file(path)?;
    writeln!(
        file,
        "run_id,run_kind,run_role,source_run_id,runtime_sequence_number,event_id,scope,affected_mint,start_slot,end_slot,severity,recovered,reason_codes"
    )?;
    let run_kind = metadata
        .map(|record| json_enum_label(&record.record.run_kind))
        .unwrap_or_else(|| "unknown".to_owned());
    let run_role = metadata
        .map(|record| json_enum_label(&record.record.run_role))
        .unwrap_or_else(|| "unknown".to_owned());
    let source_run_id = metadata
        .and_then(|record| record.record.source_run_id.clone())
        .unwrap_or_else(|| run_id.to_owned());
    let mut rows = Vec::new();
    for event in events {
        let EventPayload::DataGap(gap) = &event.record.payload else {
            continue;
        };
        let affected = if gap.affected_tokens.is_empty() {
            vec![String::new()]
        } else {
            gap.affected_tokens
                .iter()
                .map(|mint| mint.0.clone())
                .collect()
        };
        for mint in affected {
            rows.push((
                event.runtime_sequence_number.unwrap_or_default(),
                event.record.meta.event_id.0.to_string(),
                if mint.is_empty() {
                    "global".to_owned()
                } else {
                    "token".to_owned()
                },
                mint,
                gap.start_slot,
                gap.end_slot.unwrap_or_default(),
                format!("{:?}", gap.severity).to_lowercase(),
                gap.end_slot.is_some(),
                gap.recovery_action.clone(),
            ));
        }
    }
    rows.sort();
    for row in rows {
        writeln!(
            file,
            "{},{},{},{},{},{},{},{},{},{},{},{},{}",
            csv_field(run_id),
            csv_field(&run_kind),
            csv_field(&run_role),
            csv_field(&source_run_id),
            row.0,
            csv_field(&row.1),
            csv_field(&row.2),
            csv_field(&row.3),
            row.4,
            row.5,
            csv_field(&row.6),
            row.7,
            csv_field(&row.8),
        )?;
    }
    Ok(())
}

fn write_rejection_reasons_csv(
    path: &Path,
    run_id: &str,
    metadata: Option<&StoredRecord<storage::RunMetadata>>,
    decisions: &[StoredRecord<common::TradeDecisionEvent>],
) -> Result<()> {
    let mut file = create_csv_file(path)?;
    writeln!(
        file,
        "run_id,run_kind,run_role,source_run_id,decision_id,mint,strategy,reason_code,threshold,observed_value,feature_name,risk_name"
    )?;
    let run_kind = metadata
        .map(|record| json_enum_label(&record.record.run_kind))
        .unwrap_or_else(|| "unknown".to_owned());
    let run_role = metadata
        .map(|record| json_enum_label(&record.record.run_role))
        .unwrap_or_else(|| "unknown".to_owned());
    let source_run_id = metadata
        .and_then(|record| record.record.source_run_id.clone())
        .unwrap_or_else(|| run_id.to_owned());
    let mut rows = Vec::new();
    for decision in decisions {
        let mut reasons = decision
            .record
            .reason_codes
            .iter()
            .map(|reason| format!("{reason:?}"))
            .collect::<Vec<_>>();
        reasons.sort();
        for reason in reasons {
            rows.push((
                decision.record.decision_id.clone(),
                decision.record.mint.0.clone(),
                decision.record.strategy.clone(),
                reason,
            ));
        }
    }
    rows.sort();
    for row in rows {
        writeln!(
            file,
            "{},{},{},{},{},{},{},{},{},{},{},{}",
            csv_field(run_id),
            csv_field(&run_kind),
            csv_field(&run_role),
            csv_field(&source_run_id),
            csv_field(&row.0),
            csv_field(&row.1),
            csv_field(&row.2),
            csv_field(&row.3),
            "",
            "",
            "",
            "",
        )?;
    }
    Ok(())
}

fn create_csv_file(path: &Path) -> Result<File> {
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent)?;
    }
    Ok(File::create(path)?)
}

fn rpc_ledger_json_path(store: &StorageEngine, run_id: &str) -> PathBuf {
    store.run_report_dir(run_id).join("rpc_ledger.json")
}

fn load_rpc_ledger_entries(store: &StorageEngine, run_id: &str) -> Result<Vec<RpcLedgerEntry>> {
    let path = rpc_ledger_json_path(store, run_id);
    if !path.exists() {
        return Ok(Vec::new());
    }
    Ok(serde_json::from_slice(&fs::read(path)?)?)
}

fn write_rpc_ledger_csv(path: &Path, rows: &[RpcLedgerRow]) -> Result<()> {
    let mut file = create_csv_file(path)?;
    writeln!(
        file,
        "run_id,timestamp,category,method,caller,reason,allowed,denied,network_touched,estimated_credits,actual_credits,stream_only_enabled"
    )?;
    for row in rows {
        writeln!(
            file,
            "{},{},{},{},{},{},{},{},{},{},{},{}",
            csv_field(&row.run_id),
            row.timestamp.unix_timestamp_nanos(),
            csv_field(&row.category),
            csv_field(&row.method),
            csv_field(&row.caller),
            csv_field(&row.reason),
            row.allowed,
            row.denied,
            row.network_touched,
            row.estimated_credits,
            row.actual_credits,
            row.stream_only_enabled,
        )?;
    }
    Ok(())
}

fn csv_field(value: &str) -> String {
    if value.contains(',') || value.contains('"') || value.contains('\n') {
        format!("\"{}\"", value.replace('"', "\"\""))
    } else {
        value.to_owned()
    }
}

fn storage_engine(loaded: &LoadedConfig) -> Result<StorageEngine> {
    let layout = StorageLayout::from_config(&loaded.config.storage)?;
    Ok(StorageEngine::new(layout)
        .with_feature_snapshot_persistence(loaded.config.research_worker.persistence.clone()))
}

fn resolved_config(
    loaded: &LoadedConfig,
    mode: Option<RuntimeMode>,
) -> Result<RuntimeResolvedConfig> {
    if loaded.config.stream_only.enabled {
        loaded.validate_stream_only()?;
    }
    RuntimeResolvedConfig::from_loaded(loaded.clone(), mode)
}

fn render_strategy_summary(summary: &runtime::RuntimeSummary) -> String {
    use std::collections::BTreeMap;

    let mut by_strategy = BTreeMap::<String, Vec<&common::FillEvent>>::new();
    for fill in &summary.fills {
        by_strategy
            .entry(
                fill.strategy
                    .clone()
                    .unwrap_or_else(|| "unknown".to_owned()),
            )
            .or_default()
            .push(fill);
    }
    let mut decisions_by_strategy = BTreeMap::<String, BTreeMap<String, u64>>::new();
    for decision in &summary.decision_events {
        *decisions_by_strategy
            .entry(decision.strategy.clone())
            .or_default()
            .entry(format!("{:?}", decision.decision))
            .or_default() += 1;
    }
    let mut out = format!("# Strategy Summary {}\n\n", summary.run_id);
    out.push_str(&format!(
        "- mode: {:?}\n- source_run_id: {}\n- fills: {}\n- decisions: {}\n\n",
        summary.mode,
        summary
            .source_run_id
            .clone()
            .unwrap_or_else(|| "none".to_owned()),
        summary.fills.len(),
        summary.decision_events.len()
    ));
    for (strategy, decision_counts) in &decisions_by_strategy {
        let fills = by_strategy.remove(strategy).unwrap_or_default();
        let net = fills
            .iter()
            .map(|fill| fill.net_pnl_quote.unwrap_or(Decimal::ZERO))
            .sum::<Decimal>();
        let gross = fills
            .iter()
            .map(|fill| fill.gross_pnl_quote.unwrap_or(Decimal::ZERO))
            .sum::<Decimal>();
        let fee_drag = fills
            .iter()
            .map(|fill| {
                fill.base_fee_quote.unwrap_or(Decimal::ZERO)
                    + fill.priority_fee_quote.unwrap_or(Decimal::ZERO)
                    + fill.tip_quote.unwrap_or(Decimal::ZERO)
                    + fill.failed_tx_cost_quote.unwrap_or(Decimal::ZERO)
            })
            .sum::<Decimal>();
        let slippage_drag = fills
            .iter()
            .map(|fill| fill.slippage_cost_quote.unwrap_or(Decimal::ZERO))
            .sum::<Decimal>();
        let impact_drag = fills
            .iter()
            .map(|fill| fill.curve_impact_cost_quote.unwrap_or(Decimal::ZERO))
            .sum::<Decimal>();
        let wins = fills
            .iter()
            .filter(|fill| fill.net_pnl_quote.unwrap_or(Decimal::ZERO) > Decimal::ZERO)
            .count();
        let avg_hold_ms = if fills.is_empty() {
            0u64
        } else {
            fills
                .iter()
                .map(|fill| fill.hold_time_ms.unwrap_or(0).max(0) as u64)
                .sum::<u64>()
                / fills.len() as u64
        };
        let watch_count = decision_counts
            .get("WatchDeep")
            .copied()
            .unwrap_or_default();
        let enter_count = decision_counts
            .get("EnterPaper")
            .copied()
            .unwrap_or_default();
        let exit_count = decision_counts.get("Exit").copied().unwrap_or_default();
        let hold_count = decision_counts.get("Hold").copied().unwrap_or_default();
        let best_trade = fills.iter().max_by_key(|fill| {
            fill.net_pnl_quote
                .unwrap_or(Decimal::ZERO)
                .round_dp_with_strategy(6, rust_decimal::RoundingStrategy::MidpointAwayFromZero)
                .mantissa()
        });
        let worst_trade = fills.iter().min_by_key(|fill| {
            fill.net_pnl_quote
                .unwrap_or(Decimal::ZERO)
                .round_dp_with_strategy(6, rust_decimal::RoundingStrategy::MidpointAwayFromZero)
                .mantissa()
        });
        out.push_str(&format!(
            "## {strategy}\n\
- decisions_enter: {enter_count}\n\
- decisions_watchdeep: {watch_count}\n\
- decisions_hold: {hold_count}\n\
- decisions_exit: {exit_count}\n\
- fills: {}\n\
- win_rate: {}/{}\n\
- gross_pnl: {}\n\
- net_pnl: {}\n\
- fee_drag: {}\n\
- slippage_drag: {}\n\
- impact_drag: {}\n\
- average_hold_ms: {}\n",
            fills.len(),
            wins,
            fills.len(),
            gross,
            net,
            fee_drag,
            slippage_drag,
            impact_drag,
            avg_hold_ms
        ));
        if let Some(best_trade) = best_trade {
            out.push_str(&format!(
                "- best_trade: mint={} net_pnl={} exit_classification={}\n",
                best_trade.mint.0,
                best_trade.net_pnl_quote.unwrap_or(Decimal::ZERO),
                best_trade
                    .exit_classification
                    .clone()
                    .unwrap_or_else(|| "unknown".to_owned())
            ));
        }
        if let Some(worst_trade) = worst_trade {
            out.push_str(&format!(
                "- worst_trade: mint={} net_pnl={} exit_classification={}\n",
                worst_trade.mint.0,
                worst_trade.net_pnl_quote.unwrap_or(Decimal::ZERO),
                worst_trade
                    .exit_classification
                    .clone()
                    .unwrap_or_else(|| "unknown".to_owned())
            ));
        }
        out.push('\n');
    }
    for (strategy, fills) in by_strategy {
        if fills.is_empty() {
            continue;
        }
        let net = fills
            .iter()
            .map(|fill| fill.net_pnl_quote.unwrap_or(Decimal::ZERO))
            .sum::<Decimal>();
        out.push_str(&format!(
            "## {strategy}\n- fills: {}\n- net_pnl: {}\n\n",
            fills.len(),
            net
        ));
    }
    out
}

async fn ensure_store_seeded(loaded: &LoadedConfig) -> Result<String> {
    let store = storage_engine(loaded)?;
    if let Some(run_id) = store.latest_normalized_event_run_id()? {
        return Ok(run_id);
    }
    let mut loaded_for_run = loaded.clone();
    loaded_for_run.config.environment.run_id = derived_run_id("fixture-suite");
    let resolved = resolved_config(&loaded_for_run, Some(RuntimeMode::Fixture))?;
    let mut supervisor = Supervisor::new(resolved)?;
    let results = supervisor
        .run_fixture_suite(&builtin_fixture_suite())
        .await?;
    if results.is_empty() {
        return Err(anyhow!("fixture suite produced no results"));
    }
    storage_engine(&loaded_for_run)?
        .latest_normalized_event_run_id()?
        .ok_or_else(|| anyhow!("fixture suite did not persist a normalized event run"))
}

fn parse_run_kind(kind: Option<&str>) -> Result<Option<RunKind>> {
    match kind {
        None => Ok(None),
        Some("standard_fixture_suite") => Ok(Some(RunKind::StandardFixtureSuite)),
        Some("shred_exit_fixture_suite") => Ok(Some(RunKind::ShredExitFixtureSuite)),
        Some("fixture_scenario") => Ok(Some(RunKind::FixtureScenario)),
        Some("paper_replay") => Ok(Some(RunKind::PaperReplay)),
        Some("mocked_live_paper") => Ok(Some(RunKind::MockedLivePaper)),
        Some("mocked_live_paper_early_intent") => Ok(Some(RunKind::MockedLivePaperEarlyIntent)),
        Some("mocked_live_paper_deshred") => Ok(Some(RunKind::MockedLivePaperDeshred)),
        Some("real_live_paper") => Ok(Some(RunKind::RealLivePaper)),
        Some("real_live_paper_deshred") => Ok(Some(RunKind::RealLivePaperDeshred)),
        Some("backtest") => Ok(Some(RunKind::Backtest)),
        Some("shred_exit_backtest") => Ok(Some(RunKind::ShredExitBacktest)),
        Some("deshred_smoke") => Ok(Some(RunKind::DeshredSmoke)),
        Some("multisource_early_intent_suite") => Ok(Some(RunKind::MultisourceEarlyIntentSuite)),
        Some("report") => Ok(Some(RunKind::Report)),
        Some("export") => Ok(Some(RunKind::Export)),
        Some("replay_equivalence") => Ok(Some(RunKind::ReplayEquivalence)),
        Some("calibration_update") => Ok(Some(RunKind::CalibrationUpdate)),
        Some("unknown") => Ok(Some(RunKind::Unknown)),
        Some(other) => Err(anyhow!("unknown run kind: {other}")),
    }
}

fn parse_run_role(role: Option<&str>) -> Result<Option<RunRole>> {
    match role {
        None => Ok(None),
        Some("source_run") => Ok(Some(RunRole::SourceRun)),
        Some("derived_run") => Ok(Some(RunRole::DerivedRun)),
        Some("analysis_run") => Ok(Some(RunRole::AnalysisRun)),
        Some("report_run") => Ok(Some(RunRole::ReportRun)),
        Some("export_run") => Ok(Some(RunRole::ExportRun)),
        Some("unknown") => Ok(Some(RunRole::Unknown)),
        Some(other) => Err(anyhow!("unknown run role: {other}")),
    }
}

fn pick_latest_run(
    records: Vec<StoredRecord<storage::RunMetadata>>,
) -> Option<StoredRecord<storage::RunMetadata>> {
    let pick = |records: Vec<StoredRecord<storage::RunMetadata>>| {
        records.into_iter().max_by(|left, right| {
            let left_completed = left
                .record
                .completed_at_wall_time
                .unwrap_or(left.record.created_at_wall_time);
            let right_completed = right
                .record
                .completed_at_wall_time
                .unwrap_or(right.record.created_at_wall_time);
            left_completed
                .cmp(&right_completed)
                .then_with(|| left.record.run_id.cmp(&right.record.run_id))
        })
    };
    if let Some(record) = pick(
        records
            .iter()
            .filter(|record| record.record.status == storage::RunStatus::Completed)
            .cloned()
            .collect(),
    ) {
        return Some(record);
    }
    if let Some(record) = pick(
        records
            .iter()
            .filter(|record| record.record.status != storage::RunStatus::Running)
            .cloned()
            .collect(),
    ) {
        return Some(record);
    }
    pick(records)
}

async fn select_run_id(
    loaded: &LoadedConfig,
    selection: RunSelection<'_>,
    prefer_source_fallback: bool,
) -> Result<String> {
    if let Some(run_id) = selection.run_id {
        return Ok(run_id.to_owned());
    }
    let store = storage_engine(loaded)?;
    let mut runs = store.list_runs()?;
    runs.retain(|record| {
        selection
            .run_kind
            .map(|kind| record.record.run_kind == kind)
            .unwrap_or(true)
            && selection
                .run_role
                .map(|role| record.record.run_role == role)
                .unwrap_or(true)
    });
    let explicit_non_default = selection.latest_any_run
        || selection.latest_source_run
        || selection.latest_paper_run
        || selection.latest_live_paper_run
        || selection.latest_real_live_paper_run
        || selection.latest_mocked_live_run
        || selection.latest_mocked_early_intent_run
        || selection.latest_deshred_run
        || selection.latest_mock_deshred_run
        || selection.latest_real_deshred_run
        || selection.latest_shred_exit_run
        || selection.latest_analysis_run
        || selection.latest_report_run
        || selection.latest_backtest_run
        || selection.latest_shred_exit_backtest_run
        || selection.run_role.is_some()
        || selection.run_kind.is_some();
    if !explicit_non_default && selection.latest_run {
        runs.retain(|record| record.record.run_kind.is_default_latest_candidate());
    }
    if selection.latest_source_run {
        runs.retain(|record| record.record.run_role == RunRole::SourceRun);
    }
    if selection.latest_paper_run {
        runs.retain(|record| record.record.run_kind.is_paper_run());
    }
    if selection.latest_live_paper_run {
        runs.retain(|record| record.record.run_kind.is_live_paper());
    }
    if selection.latest_real_live_paper_run {
        runs.retain(|record| {
            matches!(
                record.record.run_kind,
                RunKind::RealLivePaper | RunKind::RealLivePaperDeshred
            )
        });
    }
    if selection.latest_mocked_live_run {
        runs.retain(|record| record.record.run_kind.is_mocked_live());
    }
    if selection.latest_mocked_early_intent_run {
        runs.retain(|record| record.record.run_kind == RunKind::MockedLivePaperEarlyIntent);
    }
    if selection.latest_deshred_run {
        runs.retain(|record| {
            matches!(
                record.record.run_kind,
                RunKind::MockedLivePaperDeshred | RunKind::RealLivePaperDeshred
            )
        });
    }
    if selection.latest_mock_deshred_run {
        runs.retain(|record| record.record.run_kind == RunKind::MockedLivePaperDeshred);
    }
    if selection.latest_real_deshred_run {
        runs.retain(|record| record.record.run_kind == RunKind::RealLivePaperDeshred);
    }
    if selection.latest_shred_exit_run {
        let shred_suite_runs = runs
            .iter()
            .filter(|record| record.record.run_kind == RunKind::ShredExitFixtureSuite)
            .cloned()
            .collect::<Vec<_>>();
        if let Some(record) = pick_latest_run(shred_suite_runs) {
            return Ok(record.record.run_id);
        }
        runs.retain(|record| record.record.contains_shred_exit_defense_events);
    }
    if selection.latest_analysis_run {
        runs.retain(|record| record.record.run_role == RunRole::AnalysisRun);
    }
    if selection.latest_report_run {
        runs.retain(|record| record.record.run_role == RunRole::ReportRun);
    }
    if selection.latest_backtest_run {
        runs.retain(|record| record.record.run_kind.is_backtest());
    }
    if selection.latest_shred_exit_backtest_run {
        runs.retain(|record| record.record.run_kind == RunKind::ShredExitBacktest);
    }
    if selection.latest_source_run
        || selection.latest_shred_exit_run
        || selection.latest_mocked_early_intent_run
        || selection.latest_deshred_run
        || selection.latest_mock_deshred_run
        || selection.latest_real_deshred_run
    {
        runs.retain(|record| record.record.event_count > 0);
    }
    let selected = pick_latest_run(runs).map(|record| record.record.run_id);
    match selected {
        Some(run_id) => Ok(run_id),
        None if prefer_source_fallback => ensure_store_seeded(loaded).await,
        None => Err(anyhow!("no stored run found")),
    }
}

fn derived_run_id(prefix: &str) -> String {
    format!(
        "{prefix}-{}",
        OffsetDateTime::now_utc().unix_timestamp_nanos()
    )
}

fn latest_metadata_for_run(
    store: &StorageEngine,
    run_id: &str,
) -> Result<Option<StoredRecord<storage::RunMetadata>>> {
    let selected = store
        .read_run_metadata_filtered(Some(run_id), None)?
        .into_iter()
        .max_by(|left, right| {
            let left_root = left.record.scenario_id.is_none();
            let right_root = right.record.scenario_id.is_none();
            left_root
                .cmp(&right_root)
                .then_with(|| {
                    left.record
                        .completed_at_wall_time
                        .cmp(&right.record.completed_at_wall_time)
                })
                .then_with(|| {
                    left.record
                        .created_at_wall_time
                        .cmp(&right.record.created_at_wall_time)
                })
                .then_with(|| left.record.run_id.cmp(&right.record.run_id))
        });
    if let Some(ref record) = selected {
        if record.record.scenario_id.is_none() {
            return Ok(selected);
        }
    }
    Ok(store
        .list_runs()?
        .into_iter()
        .find(|record| record.record.run_id == run_id)
        .or(selected))
}

fn latest_replay_equivalence_status_for_run(
    store: &StorageEngine,
    run_id: &str,
) -> Result<Option<bool>> {
    let path = store.run_report_dir(run_id).join("replay_equivalence.md");
    if !path.exists() {
        return Ok(None);
    }
    let content = fs::read_to_string(path)?;
    Ok(if content.contains("- equivalent: true") {
        Some(true)
    } else if content.contains("- equivalent: false") {
        Some(false)
    } else {
        None
    })
}

fn collect_artifacts_for_run(store: &StorageEngine, run_id: &str) -> Result<Vec<ArtifactMetadata>> {
    let metadata = latest_metadata_for_run(store, run_id)?;
    let source_run_id = metadata
        .as_ref()
        .and_then(|record| record.record.source_run_id.clone())
        .unwrap_or_else(|| run_id.to_owned());
    let config_hash = metadata
        .as_ref()
        .map(|record| record.record.config_hash.clone())
        .unwrap_or_default();
    let idl_hash = metadata
        .as_ref()
        .map(|record| record.record.idl_hash.clone())
        .unwrap_or_default();
    let calibration_snapshot_hash = metadata
        .as_ref()
        .and_then(|record| record.record.calibration_snapshot_hash.clone());
    let mut artifacts = Vec::new();
    let report_dir = store.run_report_dir(run_id);
    if report_dir.exists() {
        let mut entries = fs::read_dir(&report_dir)?
            .filter_map(|entry| entry.ok())
            .filter(|entry| {
                entry
                    .file_type()
                    .map(|kind| kind.is_file())
                    .unwrap_or(false)
            })
            .collect::<Vec<_>>();
        entries.sort_by(|left, right| left.file_name().cmp(&right.file_name()));
        for entry in entries {
            let path = entry.path();
            let bytes = fs::read(&path)?;
            let checksum = format!("{:x}", Sha256::digest(&bytes));
            let created_at_wall_time = entry
                .metadata()
                .ok()
                .and_then(|metadata| metadata.modified().ok())
                .and_then(system_time_to_offset);
            let row_count = match path.extension().and_then(|value| value.to_str()) {
                Some("csv") => {
                    Some(bytes.split(|byte| *byte == b'\n').count().saturating_sub(1) as u64)
                }
                _ => None,
            };
            let artifact_type = artifact_type_for_path(&path);
            artifacts.push(ArtifactMetadata {
                artifact_id: artifact_id_for_path(run_id, &path),
                artifact_type,
                associated_run_id: run_id.to_owned(),
                source_run_id: source_run_id.clone(),
                created_at_wall_time,
                path: path.display().to_string(),
                schema_version: common::SCHEMA_VERSION,
                config_hash: config_hash.clone(),
                idl_hash: idl_hash.clone(),
                calibration_snapshot_hash: calibration_snapshot_hash.clone(),
                row_count,
                checksum,
                notes: Vec::new(),
            });
        }
    }
    if let Some(path) = metadata
        .as_ref()
        .and_then(|record| record.record.calibration_snapshot_path.clone())
        .map(PathBuf::from)
    {
        if path.exists() {
            let bytes = fs::read(&path)?;
            artifacts.push(ArtifactMetadata {
                artifact_id: artifact_id_for_path(run_id, &path),
                artifact_type: ArtifactType::CalibrationSnapshot,
                associated_run_id: run_id.to_owned(),
                source_run_id,
                created_at_wall_time: fs::metadata(&path)
                    .ok()
                    .and_then(|metadata| metadata.modified().ok())
                    .and_then(system_time_to_offset),
                path: path.display().to_string(),
                schema_version: common::SCHEMA_VERSION,
                config_hash,
                idl_hash,
                calibration_snapshot_hash,
                row_count: None,
                checksum: format!("{:x}", Sha256::digest(&bytes)),
                notes: vec!["calibration_snapshot".to_owned()],
            });
        }
    }
    artifacts.sort_by(|left, right| {
        left.path
            .cmp(&right.path)
            .then_with(|| left.artifact_id.cmp(&right.artifact_id))
    });
    Ok(artifacts)
}

fn metadata_note_value<'a>(
    metadata: Option<&'a StoredRecord<storage::RunMetadata>>,
    prefix: &str,
) -> Option<&'a str> {
    metadata.and_then(|record| {
        record
            .record
            .notes
            .iter()
            .find_map(|note| note.strip_prefix(prefix))
    })
}

fn metadata_note_bool(
    metadata: Option<&StoredRecord<storage::RunMetadata>>,
    prefix: &str,
) -> Option<bool> {
    metadata_note_value(metadata, prefix).and_then(|value| match value {
        "true" => Some(true),
        "false" => Some(false),
        _ => None,
    })
}

fn metadata_note_u64(
    metadata: Option<&StoredRecord<storage::RunMetadata>>,
    prefix: &str,
) -> Option<u64> {
    metadata_note_value(metadata, prefix).and_then(|value| value.parse().ok())
}

fn metadata_note_decimal(
    metadata: Option<&StoredRecord<storage::RunMetadata>>,
    prefix: &str,
) -> Option<Decimal> {
    metadata_note_value(metadata, prefix).and_then(|value| value.parse().ok())
}

fn stream_only_run_summary(
    loaded: &LoadedConfig,
    run_id: &str,
    metadata: Option<&StoredRecord<storage::RunMetadata>>,
) -> Result<StreamOnlyRunSummary> {
    let store = storage_engine(loaded)?;
    let ledger = load_rpc_ledger_entries(&store, run_id)?;
    let ledger_path = rpc_ledger_json_path(&store, run_id);
    Ok(StreamOnlyRunSummary {
        stream_only_enabled: metadata_note_bool(metadata, "stream_only_enabled=")
            .unwrap_or(loaded.config.stream_only.enabled),
        stream_only_passed: metadata_note_bool(metadata, "stream_only_passed=")
            .unwrap_or_else(|| loaded.validate_stream_only().is_ok()),
        rpc_network_calls_total: metadata_note_u64(metadata, "rpc_network_calls_total=")
            .unwrap_or_else(|| {
                ledger
                    .iter()
                    .filter(|entry| entry.allowed && entry.network_touched)
                    .count() as u64
            }),
        rpc_credits_used_total: metadata_note_u64(metadata, "rpc_credits_used_total=")
            .unwrap_or_else(|| {
                ledger
                    .iter()
                    .filter(|entry| entry.allowed)
                    .map(|entry| entry.request.estimated_provider_credit_cost)
                    .sum()
            }),
        rpc_denials_total: metadata_note_u64(metadata, "rpc_denials_total=")
            .unwrap_or_else(|| ledger.iter().filter(|entry| entry.denied).count() as u64),
        rpc_ledger_path: ledger_path.display().to_string(),
        market_data_rpc_calls_allowed: metadata_note_bool(
            metadata,
            "market_data_rpc_calls_allowed=",
        )
        .unwrap_or(loaded.config.stream_only.allow_tracking_rpc),
        holder_rpc_calls_allowed: metadata_note_bool(metadata, "holder_rpc_calls_allowed=")
            .unwrap_or(loaded.config.stream_only.allow_holder_rpc),
        metadata_fetch_allowed: metadata_note_bool(metadata, "metadata_fetch_allowed=")
            .unwrap_or(loaded.config.stream_only.allow_metadata_rpc),
        confirmation_rpc_allowed: metadata_note_bool(metadata, "confirmation_rpc_allowed=")
            .unwrap_or(loaded.config.stream_only.allow_confirmation_rpc),
        blockhash_rpc_allowed: metadata_note_bool(metadata, "blockhash_rpc_allowed=")
            .unwrap_or(loaded.config.stream_only.allow_blockhash_rpc),
        send_rpc_allowed: metadata_note_bool(metadata, "send_rpc_allowed=")
            .unwrap_or(loaded.config.stream_only.allow_send_rpc),
    })
}

fn source_specific_early_intent_summary(
    loaded: &LoadedConfig,
    run_id: &str,
    metadata: Option<&StoredRecord<storage::RunMetadata>>,
    events: &[StoredRecord<NormalizedEvent>],
    fills: &[StoredRecord<FillEvent>],
) -> Result<SourceSpecificEarlyIntentSummary> {
    let deshred_capability = runtime::inspect_deshred_capability(loaded, None, None);
    let artifacts = build_shred_exit_artifacts(
        loaded,
        run_id.to_owned(),
        run_id.to_owned(),
        events.to_vec(),
        fills.to_vec(),
    )?;
    let mut source_breakdown = BTreeMap::<String, u64>::new();
    let mut primary_source_summary = BTreeMap::<String, u64>::new();
    let mut duplicate_sources_summary = BTreeMap::<String, u64>::new();
    let mut confirmation_method_breakdown = BTreeMap::<String, u64>::new();
    let mut source_latency_delta_ms = Vec::<i64>::new();
    for row in &artifacts.event_rows {
        *source_breakdown
            .entry(row.early_intent_source.clone())
            .or_default() += 1;
        *primary_source_summary
            .entry(row.primary_source.clone())
            .or_default() += 1;
        if !row.duplicate_sources.is_empty() {
            for duplicate in row
                .duplicate_sources
                .split('|')
                .filter(|value| !value.is_empty())
            {
                *duplicate_sources_summary
                    .entry(duplicate.to_owned())
                    .or_default() += 1;
            }
        }
        if let Some(delta_ms) = row.source_latency_delta_ms {
            source_latency_delta_ms.push(delta_ms);
        }
    }
    for row in &artifacts.reconciliation_rows {
        *confirmation_method_breakdown
            .entry(row.confirmation_method.clone())
            .or_default() += 1;
    }
    let mut early_intent_sources_active =
        if let Some(value) = metadata_note_value(metadata, "early_intent_sources_active=") {
            value
                .split('|')
                .filter(|value| !value.is_empty())
                .map(ToOwned::to_owned)
                .collect::<BTreeSet<_>>()
                .into_iter()
                .collect::<Vec<_>>()
        } else {
            source_breakdown.keys().cloned().collect::<Vec<_>>()
        };
    early_intent_sources_active.sort();
    let deshred_connected =
        metadata_note_bool(metadata, "deshred_connected=").unwrap_or_else(|| {
            events.iter().any(|record| {
                matches!(
                    record.record.meta.source,
                    common::EventSource::DeshredTentative
                )
            })
        });
    let deshred_provider_status = metadata_note_value(metadata, "deshred_provider_status=")
        .map(ToOwned::to_owned)
        .unwrap_or_else(|| {
            if deshred_connected {
                "connected".to_owned()
            } else if metadata
                .map(|record| {
                    record.record.notes.iter().any(|note| {
                        note == "with_deshred=true"
                            || note == "mock_deshred=true"
                            || note == "mode=real_geyser+deshred"
                            || note == "mode=mock_geyser+mock_deshred"
                            || note == "mode=mock_geyser+mock_deshred+mock_early_intent"
                    })
                })
                .unwrap_or(false)
            {
                "unavailable".to_owned()
            } else {
                "not_requested".to_owned()
            }
        });
    let contains_mock_source = source_breakdown.contains_key("mockearlyintent");
    Ok(SourceSpecificEarlyIntentSummary {
        early_intent_sources_active,
        source_breakdown,
        primary_source_summary,
        duplicate_sources_summary,
        confirmation_method_breakdown,
        deshred_connected,
        deshred_supported: metadata_note_bool(metadata, "deshred_supported=")
            .unwrap_or(deshred_capability.can_enable),
        deshred_provider_status,
        deshred_events_received: metadata_note_u64(metadata, "deshred_events_received=")
            .unwrap_or_else(|| {
                events
                    .iter()
                    .filter(|record| {
                        matches!(
                            record.record.meta.source,
                            common::EventSource::DeshredTentative
                        )
                    })
                    .count() as u64
            }),
        deshred_tentative_sells_total: metadata_note_u64(
            metadata,
            "deshred_tentative_sells_total=",
        )
        .unwrap_or_else(|| {
            artifacts
                .event_rows
                .iter()
                .filter(|row| row.early_intent_source == "deshredpreexecution")
                .count() as u64
        }),
        deshred_malicious_warnings_total: metadata_note_u64(
            metadata,
            "deshred_malicious_warnings_total=",
        )
        .unwrap_or_else(|| {
            artifacts
                .event_rows
                .iter()
                .filter(|row| row.early_intent_source == "deshredpreexecution")
                .count() as u64
        }),
        deshred_emergency_exits_armed_total: metadata_note_u64(
            metadata,
            "deshred_emergency_exits_armed_total=",
        )
        .unwrap_or_else(|| {
            artifacts
                .event_rows
                .iter()
                .filter(|row| row.early_intent_source == "deshredpreexecution" && row.exit_armed)
                .count() as u64
        }),
        deshred_emergency_exits_triggered_total: metadata_note_u64(
            metadata,
            "deshred_emergency_exits_triggered_total=",
        )
        .unwrap_or_else(|| {
            artifacts
                .event_rows
                .iter()
                .filter(|row| {
                    row.early_intent_source == "deshredpreexecution" && row.emergency_exit_triggered
                })
                .count() as u64
        }),
        deshred_confirmed_executed_total: metadata_note_u64(
            metadata,
            "deshred_confirmed_executed_total=",
        )
        .unwrap_or_else(|| {
            artifacts
                .reconciliation_rows
                .iter()
                .filter(|row| {
                    row.early_intent_source == "deshredpreexecution"
                        && row.outcome == "confirmedexecuted"
                })
                .count() as u64
        }),
        deshred_false_positive_total: metadata_note_u64(metadata, "deshred_false_positive_total=")
            .unwrap_or_else(|| {
                artifacts
                    .reconciliation_rows
                    .iter()
                    .filter(|row| {
                        row.early_intent_source == "deshredpreexecution" && row.false_positive_flag
                    })
                    .count() as u64
            }),
        deshred_saved_loss_quote_total: metadata_note_decimal(
            metadata,
            "deshred_saved_loss_quote_total=",
        )
        .unwrap_or_else(|| {
            artifacts
                .reconciliation_rows
                .iter()
                .filter(|row| row.early_intent_source == "deshredpreexecution")
                .map(|row| row.saved_loss)
                .sum()
        }),
        deshred_opportunity_cost_quote_total: metadata_note_decimal(
            metadata,
            "deshred_opportunity_cost_quote_total=",
        )
        .unwrap_or_else(|| {
            artifacts
                .reconciliation_rows
                .iter()
                .filter(|row| row.early_intent_source == "deshredpreexecution")
                .map(|row| row.opportunity_cost)
                .sum()
        }),
        raw_shred_supported: cfg!(feature = "production-shred-decoder")
            && loaded.config.early_intent.allow_production_raw_shred,
        raw_shred_connected: metadata_note_bool(metadata, "raw_shred_connected=").unwrap_or_else(
            || {
                events.iter().any(|record| {
                    matches!(
                        record.record.meta.source,
                        common::EventSource::ShredTentative
                    )
                })
            },
        ),
        raw_shred_tentative_sells_total: artifacts
            .event_rows
            .iter()
            .filter(|row| row.early_intent_source == "rawshred")
            .count() as u64,
        mock_early_intent_active: metadata_note_bool(metadata, "mock_early_intent_active=")
            .unwrap_or(contains_mock_source),
        mock_early_intent_tentative_sells_total: artifacts
            .event_rows
            .iter()
            .filter(|row| row.early_intent_source == "mockearlyintent")
            .count() as u64,
        fixture_early_intent_tentative_sells_total: artifacts
            .event_rows
            .iter()
            .filter(|row| row.early_intent_source == "fixturetentative")
            .count() as u64,
        replay_early_intent_tentative_sells_total: artifacts
            .event_rows
            .iter()
            .filter(|row| row.early_intent_source == "replaytentative")
            .count() as u64,
        source_dedup_count: metadata_note_u64(metadata, "source_dedup_count=").unwrap_or_else(
            || {
                artifacts
                    .event_rows
                    .iter()
                    .filter(|row| !row.duplicate_sources.is_empty())
                    .count() as u64
            },
        ),
        source_latency_delta_ms: (!source_latency_delta_ms.is_empty()).then(|| {
            source_latency_delta_ms.iter().sum::<i64>() / source_latency_delta_ms.len() as i64
        }),
    })
}

fn build_shred_exit_report_summary(
    loaded: &LoadedConfig,
    run_id: &str,
    metadata: Option<&StoredRecord<storage::RunMetadata>>,
    events: &[StoredRecord<NormalizedEvent>],
    fills: &[StoredRecord<FillEvent>],
) -> Result<ShredExitReportSummary> {
    let source_specific =
        source_specific_early_intent_summary(loaded, run_id, metadata, events, fills)?;
    let artifacts = build_shred_exit_artifacts(
        loaded,
        run_id.to_owned(),
        run_id.to_owned(),
        events.to_vec(),
        fills.to_vec(),
    )?;
    let avg_latency_edge_ratio = if artifacts.event_rows.is_empty() {
        Decimal::ZERO
    } else {
        artifacts
            .event_rows
            .iter()
            .map(|row| row.latency_edge_ratio)
            .sum::<Decimal>()
            / Decimal::from(artifacts.event_rows.len() as u64)
    };
    let avg_net_benefit_quote = if artifacts.event_rows.is_empty() {
        Decimal::ZERO
    } else {
        artifacts
            .event_rows
            .iter()
            .map(|row| row.emergency_exit_net_benefit)
            .sum::<Decimal>()
            / Decimal::from(artifacts.event_rows.len() as u64)
    };
    Ok(ShredExitReportSummary {
        run_id: run_id.to_owned(),
        total_tentative_sells: metadata
            .map(|record| record.record.tentative_sell_count)
            .unwrap_or(artifacts.event_rows.len() as u64),
        malicious_sell_warnings: artifacts.event_rows.len() as u64,
        emergency_exits_armed: artifacts
            .event_rows
            .iter()
            .filter(|row| row.exit_armed)
            .count() as u64,
        emergency_exits_triggered: artifacts
            .event_rows
            .iter()
            .filter(|row| row.emergency_exit_triggered)
            .count() as u64,
        confirmed_true_positives: artifacts
            .reconciliation_rows
            .iter()
            .filter(|row| row.outcome == "confirmedexecuted")
            .count() as u64,
        confirmed_failed: artifacts
            .reconciliation_rows
            .iter()
            .filter(|row| row.outcome == "confirmedfailed")
            .count() as u64,
        not_seen_within_ttl: metadata
            .map(|record| record.record.not_seen_count)
            .unwrap_or_else(|| {
                artifacts
                    .reconciliation_rows
                    .iter()
                    .filter(|row| row.not_seen_flag)
                    .count() as u64
            }),
        reorged: metadata
            .map(|record| record.record.reorg_count)
            .unwrap_or_else(|| {
                artifacts
                    .reconciliation_rows
                    .iter()
                    .filter(|row| row.reorg_flag)
                    .count() as u64
            }),
        decode_mismatches: metadata
            .map(|record| record.record.decode_mismatch_count)
            .unwrap_or_else(|| {
                artifacts
                    .reconciliation_rows
                    .iter()
                    .filter(|row| row.decode_mismatch_flag)
                    .count() as u64
            }),
        account_effect_confirmed: artifacts
            .reconciliation_rows
            .iter()
            .filter(|row| row.account_effect_seen)
            .count() as u64,
        false_positive_exits: metadata
            .map(|record| record.record.false_positive_count)
            .unwrap_or_else(|| {
                artifacts
                    .reconciliation_rows
                    .iter()
                    .filter(|row| row.false_positive_flag)
                    .count() as u64
            }),
        saved_loss_quote_total: metadata
            .map(|record| record.record.saved_loss_total)
            .unwrap_or_else(|| {
                artifacts
                    .reconciliation_rows
                    .iter()
                    .map(|row| row.saved_loss)
                    .sum()
            }),
        opportunity_cost_quote_total: metadata
            .map(|record| record.record.opportunity_cost_total)
            .unwrap_or_else(|| {
                artifacts
                    .reconciliation_rows
                    .iter()
                    .map(|row| row.opportunity_cost)
                    .sum()
            }),
        average_latency_edge_ratio: avg_latency_edge_ratio,
        average_net_benefit_quote: avg_net_benefit_quote,
        too_late_cases: artifacts
            .event_rows
            .iter()
            .filter(|row| row.latency_edge_ratio < loaded.config.shred_exit.min_latency_edge_ratio)
            .count() as u64,
        absorbed_sell_cases: artifacts
            .event_rows
            .iter()
            .filter(|row| {
                row.absorption_health_score
                    >= loaded.config.shred_exit.absorption_downgrade_threshold
            })
            .count() as u64,
        provider_status: ProviderStatusSummary {
            endpoint_configured: runtime::inspect_deshred_capability(loaded, None, None)
                .endpoint_configured,
            auth_configured: runtime::inspect_deshred_capability(loaded, None, None)
                .auth_configured,
            auth_metadata_key_configured: !loaded
                .config
                .ingest
                .deshred
                .clone()
                .unwrap_or_default()
                .auth_metadata_key
                .trim()
                .is_empty(),
            provider_status: source_specific.deshred_provider_status.clone(),
            provider_name: (!loaded.config.provider.name.trim().is_empty())
                .then(|| loaded.config.provider.name.clone()),
        },
        source_specific,
    })
}

