fn render_research_artifacts_report(artifacts: &[ArtifactMetadata]) -> String {
    let mut out = String::from("# Research Artifacts\n\n");
    if artifacts.is_empty() {
        out.push_str("- artifacts: none\n");
        return out;
    }
    for artifact in artifacts {
        out.push_str(&format!(
            "- type={} path={} checksum={} row_count={}\n",
            json_enum_label(&artifact.artifact_type),
            artifact.path,
            artifact.checksum,
            artifact
                .row_count
                .map(|value| value.to_string())
                .unwrap_or_else(|| "".to_owned())
        ));
    }
    out
}

fn system_time_to_offset(value: std::time::SystemTime) -> Option<OffsetDateTime> {
    let duration = value.duration_since(std::time::UNIX_EPOCH).ok()?;
    OffsetDateTime::from_unix_timestamp_nanos(duration.as_nanos() as i128).ok()
}

fn artifact_type_for_path(path: &Path) -> ArtifactType {
    let name = path
        .file_name()
        .and_then(|value| value.to_str())
        .unwrap_or_default();
    if name == "replay_equivalence_debug.md" {
        ArtifactType::ReplayEquivalenceDebug
    } else if name == "export_schema_verification.md" {
        ArtifactType::Verification
    } else if name.ends_with(".md") {
        ArtifactType::Report
    } else if name.contains("backtest") || name.contains("latency") || name.contains("threshold") {
        ArtifactType::BacktestOutput
    } else if name.ends_with(".csv") || name.contains(".csv.zst") {
        ArtifactType::Export
    } else if name.ends_with(".json") {
        ArtifactType::CalibrationSnapshot
    } else {
        ArtifactType::Unknown
    }
}

fn artifact_id_for_path(run_id: &str, path: &Path) -> String {
    let mut hasher = Sha256::new();
    hasher.update(run_id.as_bytes());
    hasher.update(path.to_string_lossy().as_bytes());
    format!("{:x}", hasher.finalize())
}

fn json_enum_label<T: Serialize>(value: &T) -> String {
    serde_json::to_value(value)
        .ok()
        .and_then(|value| value.as_str().map(ToOwned::to_owned))
        .unwrap_or_else(|| "unknown".to_owned())
}

fn aggregate_rejection_reasons(
    records: &[StoredRecord<common::TradeDecisionEvent>],
) -> Vec<(String, u64)> {
    let mut counts = std::collections::BTreeMap::<String, u64>::new();
    for record in records {
        for reason in &record.record.reason_codes {
            *counts.entry(format!("{reason:?}")).or_default() += 1;
        }
    }
    let mut items = counts.into_iter().collect::<Vec<_>>();
    items.sort_by(|left, right| right.1.cmp(&left.1).then_with(|| left.0.cmp(&right.0)));
    items
}

fn decision_equivalence_key_from_record(
    record: &StoredRecord<common::TradeDecisionEvent>,
) -> String {
    format!(
        "{}|{:?}|{}|{}",
        record.record.mint.0,
        record.record.decision,
        record.record.strategy,
        record.record.no_lookahead_timestamp.unix_timestamp_nanos(),
    )
}

fn decision_equivalence_key(event: &common::TradeDecisionEvent) -> String {
    format!(
        "{}|{:?}|{}|{}",
        event.mint.0,
        event.decision,
        event.strategy,
        event.no_lookahead_timestamp.unix_timestamp_nanos(),
    )
}

fn fill_equivalence_key_from_record(record: &StoredRecord<common::FillEvent>) -> String {
    format!(
        "{}|{:?}|{}|{}",
        record.record.mint.0,
        record.record.side,
        record
            .record
            .strategy
            .clone()
            .unwrap_or_else(|| "unknown".to_owned()),
        record.record.send_time.unix_timestamp_nanos(),
    )
}

fn fill_equivalence_key(event: &common::FillEvent) -> String {
    format!(
        "{}|{:?}|{}|{}",
        event.mint.0,
        event.side,
        event
            .strategy
            .clone()
            .unwrap_or_else(|| "unknown".to_owned()),
        event.send_time.unix_timestamp_nanos(),
    )
}

fn compare_decisions_for_equivalence(
    original: &[&StoredRecord<common::TradeDecisionEvent>],
    replay: &[common::TradeDecisionEvent],
) -> DecisionEquivalenceDiff {
    let mut ordered_original = original.iter().copied().collect::<Vec<_>>();
    ordered_original.sort_by(|left, right| {
        left.runtime_sequence_number
            .cmp(&right.runtime_sequence_number)
            .then_with(|| {
                left.record
                    .no_lookahead_timestamp
                    .cmp(&right.record.no_lookahead_timestamp)
            })
            .then_with(|| left.record.decision_id.cmp(&right.record.decision_id))
    });
    let mut original_map = BTreeMap::<String, Vec<(Decimal, String, String, String)>>::new();
    let mut replay_map = BTreeMap::<String, Vec<(Decimal, String, String, String)>>::new();
    for record in &ordered_original {
        original_map
            .entry(decision_equivalence_key_from_record(record))
            .or_default()
            .push((
                record.record.expected_net_edge_quote,
                record.record.feature_snapshot_hash.clone(),
                stable_decimal_map_key(&record.record.risk_vector),
                stable_reason_codes_key(&record.record.reason_codes),
            ));
    }
    for event in replay {
        replay_map
            .entry(decision_equivalence_key(event))
            .or_default()
            .push((
                event.expected_net_edge_quote,
                event.feature_snapshot_hash.clone(),
                stable_decimal_map_key(&event.risk_vector),
                stable_reason_codes_key(&event.reason_codes),
            ));
    }
    let mut diff = DecisionEquivalenceDiff::default();
    let replay_keys = replay
        .iter()
        .map(decision_equivalence_key)
        .collect::<Vec<_>>();
    let original_keys = ordered_original
        .iter()
        .map(|record| decision_equivalence_key_from_record(record))
        .collect::<Vec<_>>();
    let overlap = original_keys.len().min(replay_keys.len());
    for index in 0..overlap {
        if original_keys[index] != replay_keys[index] {
            diff.missing.push(original_keys[index].clone());
            diff.extra.push(replay_keys[index].clone());
            continue;
        }
        let original_event = &ordered_original[index].record;
        let replay_event = &replay[index];
        let edge_delta =
            (original_event.expected_net_edge_quote - replay_event.expected_net_edge_quote).abs();
        if edge_delta > Decimal::ZERO {
            diff.edge_drift
                .push(format!("{}|edge_delta={edge_delta}", original_keys[index]));
        }
        if original_event.feature_snapshot_hash != replay_event.feature_snapshot_hash {
            diff.feature_hash_drift.push(format!(
                "{}|feature_hash={}=>{}",
                original_keys[index],
                original_event.feature_snapshot_hash,
                replay_event.feature_snapshot_hash
            ));
        }
        let original_risk_key = stable_decimal_map_key(&original_event.risk_vector);
        let replay_risk_key = stable_decimal_map_key(&replay_event.risk_vector);
        if original_risk_key != replay_risk_key {
            diff.risk_hash_drift.push(format!(
                "{}|risk_hash={}=>{}",
                original_keys[index], original_risk_key, replay_risk_key
            ));
        }
        let original_reason_key = stable_reason_codes_key(&original_event.reason_codes);
        let replay_reason_key = stable_reason_codes_key(&replay_event.reason_codes);
        if original_reason_key != replay_reason_key {
            diff.reason_code_drift.push(format!(
                "{}|reason_codes={}=>{}",
                original_keys[index], original_reason_key, replay_reason_key
            ));
        }
    }
    if original_keys.len() > overlap {
        diff.missing.extend(original_keys.into_iter().skip(overlap));
    }
    if replay_keys.len() > overlap {
        diff.extra.extend(replay_keys.into_iter().skip(overlap));
    }
    diff
}

fn compare_fills_for_equivalence(
    original: &[&StoredRecord<common::FillEvent>],
    replay: &[common::FillEvent],
) -> FillEquivalenceDiff {
    let mut ordered_original = original.iter().copied().collect::<Vec<_>>();
    ordered_original.sort_by(|left, right| {
        left.runtime_sequence_number
            .cmp(&right.runtime_sequence_number)
            .then_with(|| left.record.send_time.cmp(&right.record.send_time))
            .then_with(|| {
                left.record
                    .entry_decision_id
                    .cmp(&right.record.entry_decision_id)
            })
            .then_with(|| {
                left.record
                    .exit_decision_id
                    .cmp(&right.record.exit_decision_id)
            })
    });
    let mut original_map = BTreeMap::<String, Vec<(Decimal, Decimal, Decimal, String)>>::new();
    let mut replay_map = BTreeMap::<String, Vec<(Decimal, Decimal, Decimal, String)>>::new();
    for record in &ordered_original {
        original_map
            .entry(fill_equivalence_key_from_record(record))
            .or_default()
            .push((
                record.record.net_pnl_quote.unwrap_or(Decimal::ZERO),
                record
                    .record
                    .realized_loss_saved_quote
                    .unwrap_or(Decimal::ZERO),
                record
                    .record
                    .opportunity_cost_if_false_positive
                    .unwrap_or(Decimal::ZERO),
                record.record.exit_source.clone().unwrap_or_default(),
            ));
    }
    for event in replay {
        replay_map
            .entry(fill_equivalence_key(event))
            .or_default()
            .push((
                event.net_pnl_quote.unwrap_or(Decimal::ZERO),
                event.realized_loss_saved_quote.unwrap_or(Decimal::ZERO),
                event
                    .opportunity_cost_if_false_positive
                    .unwrap_or(Decimal::ZERO),
                event.exit_source.clone().unwrap_or_default(),
            ));
    }
    let mut diff = FillEquivalenceDiff::default();
    let replay_keys = replay.iter().map(fill_equivalence_key).collect::<Vec<_>>();
    let original_keys = ordered_original
        .iter()
        .map(|record| fill_equivalence_key_from_record(record))
        .collect::<Vec<_>>();
    let overlap = original_keys.len().min(replay_keys.len());
    for index in 0..overlap {
        if original_keys[index] != replay_keys[index] {
            diff.missing.push(original_keys[index].clone());
            diff.extra.push(replay_keys[index].clone());
            continue;
        }
        let original_fill = &ordered_original[index].record;
        let replay_fill = &replay[index];
        let pnl_delta = (original_fill.net_pnl_quote.unwrap_or(Decimal::ZERO)
            - replay_fill.net_pnl_quote.unwrap_or(Decimal::ZERO))
        .abs();
        if pnl_delta > Decimal::ZERO {
            diff.net_pnl_drift.push(format!(
                "{}|net_pnl_delta={pnl_delta}",
                original_keys[index]
            ));
        }
        let saved_loss_delta = (original_fill
            .realized_loss_saved_quote
            .unwrap_or(Decimal::ZERO)
            - replay_fill
                .realized_loss_saved_quote
                .unwrap_or(Decimal::ZERO))
        .abs();
        if saved_loss_delta > Decimal::ZERO {
            diff.saved_loss_drift.push(format!(
                "{}|saved_loss_delta={saved_loss_delta}",
                original_keys[index]
            ));
        }
        let opportunity_cost_delta = (original_fill
            .opportunity_cost_if_false_positive
            .unwrap_or(Decimal::ZERO)
            - replay_fill
                .opportunity_cost_if_false_positive
                .unwrap_or(Decimal::ZERO))
        .abs();
        if opportunity_cost_delta > Decimal::ZERO {
            diff.opportunity_cost_drift.push(format!(
                "{}|opportunity_cost_delta={opportunity_cost_delta}",
                original_keys[index]
            ));
        }
        if original_fill.exit_source != replay_fill.exit_source {
            diff.exit_source_drift.push(format!(
                "{}|exit_source={}=>{}",
                original_keys[index],
                original_fill.exit_source.clone().unwrap_or_default(),
                replay_fill.exit_source.clone().unwrap_or_default()
            ));
        }
    }
    if original_keys.len() > overlap {
        diff.missing.extend(original_keys.into_iter().skip(overlap));
    }
    if replay_keys.len() > overlap {
        diff.extra.extend(replay_keys.into_iter().skip(overlap));
    }
    diff
}

fn stable_decimal_map_key(map: &BTreeMap<String, Decimal>) -> String {
    map.iter()
        .map(|(key, value)| format!("{key}={value}"))
        .collect::<Vec<_>>()
        .join("|")
}

fn stable_reason_codes_key(reason_codes: &[common::ReasonCode]) -> String {
    let mut values = reason_codes
        .iter()
        .map(|reason| format!("{reason:?}"))
        .collect::<Vec<_>>();
    values.sort();
    values.join("|")
}

fn prefix_scenario_keys(scenario_id: Option<&str>, keys: Vec<String>) -> Vec<String> {
    let prefix = scenario_id.unwrap_or("_all");
    keys.into_iter()
        .map(|key| format!("{prefix}|{key}"))
        .collect()
}

#[derive(Default)]
struct DecisionEquivalenceDiff {
    missing: Vec<String>,
    extra: Vec<String>,
    edge_drift: Vec<String>,
    feature_hash_drift: Vec<String>,
    risk_hash_drift: Vec<String>,
    reason_code_drift: Vec<String>,
}

#[derive(Default)]
struct FillEquivalenceDiff {
    missing: Vec<String>,
    extra: Vec<String>,
    net_pnl_drift: Vec<String>,
    saved_loss_drift: Vec<String>,
    opportunity_cost_drift: Vec<String>,
    exit_source_drift: Vec<String>,
}

fn latest_run_metadata_record_for_run(
    store: &StorageEngine,
    run_id: &str,
) -> Result<Option<StoredRecord<storage::RunMetadata>>> {
    let records = store.read_run_metadata_filtered(Some(run_id), None)?;
    Ok(records.into_iter().max_by(|left, right| {
        let left_time = left
            .record
            .completed_at_wall_time
            .unwrap_or(left.record.created_at_wall_time);
        let right_time = right
            .record
            .completed_at_wall_time
            .unwrap_or(right.record.created_at_wall_time);
        left_time
            .cmp(&right_time)
            .then_with(|| left.record.run_id.cmp(&right.record.run_id))
    }))
}

fn render_replay_equivalence_debug_section(
    scenario_id: Option<&str>,
    source_events: &[StoredRecord<common::NormalizedEvent>],
    online_events: &[StoredRecord<common::NormalizedEvent>],
    original_decisions: &[&StoredRecord<common::TradeDecisionEvent>],
    original_fills: &[&StoredRecord<common::FillEvent>],
    replay: &runtime::RuntimeSummary,
    metadata: Option<&StoredRecord<storage::RunMetadata>>,
) -> String {
    let online_keys = original_decisions
        .iter()
        .map(|record| decision_equivalence_key_from_record(record))
        .collect::<Vec<_>>();
    let replay_keys = replay
        .decision_events
        .iter()
        .map(decision_equivalence_key)
        .collect::<Vec<_>>();
    let divergence = first_divergence(&online_keys, &replay_keys);
    let previous_event = divergence
        .and_then(|index| index.checked_sub(1))
        .and_then(|index| source_events.get(index))
        .map(|record| {
            format!(
                "{}@slot{}#{}",
                payload_kind_name(&record.record.payload),
                record.record.meta.slot,
                record.record.meta.event_id.0
            )
        })
        .unwrap_or_else(|| "none".to_owned());
    let online_snapshot = build_snapshot_from_events(online_events);
    let online_state = summarize_snapshot(&online_snapshot);
    let replay_state = summarize_snapshot(&replay.snapshot);
    let online_fills = original_fills
        .iter()
        .map(|record| fill_equivalence_key_from_record(record))
        .collect::<Vec<_>>();
    let replay_fills = replay
        .fills
        .iter()
        .map(fill_equivalence_key)
        .collect::<Vec<_>>();
    format!(
        "## Scenario {}\n\n- first_divergence_index: {}\n- event_before_divergence: {}\n- calibration_snapshot_hash: {}\n- online_decision_count: {}\n- replay_decision_count: {}\n- online_fill_count: {}\n- replay_fill_count: {}\n\n### Online Decisions\n{:?}\n\n### Replay Decisions\n{:?}\n\n### Online Fills\n{:?}\n\n### Replay Fills\n{:?}\n\n### Online State Summary\n{}\n\n### Replay State Summary\n{}\n",
        scenario_id.unwrap_or("_all"),
        divergence
            .map(|value| value.to_string())
            .unwrap_or_else(|| "none".to_owned()),
        previous_event,
        metadata
            .and_then(|record| record.record.calibration_snapshot_hash.clone())
            .unwrap_or_else(|| "none".to_owned()),
        online_keys.len(),
        replay_keys.len(),
        online_fills.len(),
        replay_fills.len(),
        online_keys,
        replay_keys,
        online_fills,
        replay_fills,
        online_state,
        replay_state,
    )
}

fn first_divergence(left: &[String], right: &[String]) -> Option<usize> {
    let overlap = left.len().min(right.len());
    for index in 0..overlap {
        if left[index] != right[index] {
            return Some(index);
        }
    }
    (left.len() != right.len()).then_some(overlap)
}

fn build_snapshot_from_events(
    events: &[StoredRecord<common::NormalizedEvent>],
) -> state::StateSnapshot {
    let mut state_engine = StateEngine::new(common::TtlConfig {
        discovered_secs: u64::MAX,
        active_light_secs: u64::MAX,
        active_deep_secs: u64::MAX,
        discarded_summary_secs: u64::MAX,
        research_sample_secs: u64::MAX,
    });
    for record in events {
        let _ = state_engine.apply_event(&record.record);
    }
    state_engine.snapshot()
}

fn summarize_snapshot(snapshot: &state::StateSnapshot) -> String {
    let pending_tentative = snapshot
        .tokens
        .values()
        .map(|token| token.shred_defense.pending_tentative_sells.len())
        .sum::<usize>();
    let triggered = snapshot
        .tokens
        .values()
        .filter(|token| token.shred_defense.shred_emergency_exit_triggered_flag)
        .count();
    let armed = snapshot
        .tokens
        .values()
        .filter(|token| token.shred_defense.shred_exit_armed_flag)
        .count();
    let warnings = snapshot
        .tokens
        .values()
        .filter(|token| token.shred_defense.last_warning_level.is_some())
        .count();
    format!(
        "- tokens: {}\n- positions: {}\n- pending_tentative_sells: {}\n- warnings: {}\n- armed_exits: {}\n- triggered_exits: {}",
        snapshot.tokens.len(),
        snapshot
            .tokens
            .values()
            .filter(|token| token.lifecycle == state::TokenLifecycle::InPosition)
            .count(),
        pending_tentative,
        warnings,
        armed,
        triggered
    )
}

fn payload_kind_name(payload: &common::EventPayload) -> &'static str {
    match payload {
        common::EventPayload::TokenCreated(_) => "token_created",
        common::EventPayload::PumpBuy(_) => "pump_buy",
        common::EventPayload::PumpSell(_) => "pump_sell",
        common::EventPayload::BondingCurveUpdate(_) => "bonding_curve_update",
        common::EventPayload::HolderBalanceUpdate(_) => "holder_balance_update",
        common::EventPayload::WalletFunding(_) => "wallet_funding",
        common::EventPayload::ObservedTransaction(_) => "observed_transaction",
        common::EventPayload::TokenTerminal(_) => "token_terminal",
        common::EventPayload::TradeDecision(_) => "trade_decision",
        common::EventPayload::SimulatedFill(_) => "simulated_fill",
        common::EventPayload::LiveFill(_) => "live_fill",
        common::EventPayload::DataGap(_) => "data_gap",
        common::EventPayload::TentativeSellIntentDetected(_) => "tentative_sell_intent_detected",
        common::EventPayload::TentativeMaliciousSellWarning(_) => {
            "tentative_malicious_sell_warning"
        }
        common::EventPayload::ShredEmergencyExitArmed(_) => "shred_emergency_exit_armed",
        common::EventPayload::ShredEmergencyExitTriggered(_) => "shred_emergency_exit_triggered",
        common::EventPayload::ShredSellIntentResolved(_) => "shred_sell_intent_resolved",
    }
}

async fn rebuild_from_storage_latest(loaded: &LoadedConfig) -> Result<ReplayArtifacts> {
    let run_id = ensure_store_seeded(loaded).await?;
    rebuild_from_storage_for_run(loaded, &run_id)
}

fn rebuild_from_storage_sync(loaded: &LoadedConfig) -> Result<ReplayArtifacts> {
    let store = storage_engine(loaded)?;
    let run_id = store
        .latest_normalized_event_run_id()?
        .ok_or_else(|| anyhow!("no stored normalized events found"))?;
    rebuild_from_storage_for_run(loaded, &run_id)
}

fn rebuild_from_storage_for_run(loaded: &LoadedConfig, run_id: &str) -> Result<ReplayArtifacts> {
    let store = storage_engine(loaded)?;
    let events = store.deterministic_replay_for_run(Some(run_id))?;
    let idl_hash = combined_idl_hash(loaded)?;
    let mut state_engine = StateEngine::new(loaded.config.ttl.clone());
    for record in &events {
        state_engine.apply_event(&record.record)?;
    }
    Ok(ReplayArtifacts {
        snapshot: state_engine.snapshot(),
        events,
        idl_hash,
        run_id: run_id.to_owned(),
    })
}

fn replay_paper_mode(
    loaded: &LoadedConfig,
    artifacts: &ReplayArtifacts,
) -> Result<executor::PaperExecutor> {
    let mut state_engine = StateEngine::new(loaded.config.ttl.clone());
    let feature_engine = FeatureEngine::default();
    let risk_engine = RiskEngine::default();
    let simulator = Simulator::new(FeeModel::default());
    let decision_engine = decision::DecisionEngine::new(
        loaded.config.strategy.clone(),
        loaded.config.edge.clone(),
        loaded.config.execution.clone(),
        simulator.clone(),
    );
    let mut paper = executor::PaperExecutor::new(simulator.clone());

    for record in &artifacts.events {
        state_engine.apply_event(&record.record)?;
        let Some(mint) = record.record.mint().cloned() else {
            continue;
        };
        let snapshot = state_engine.snapshot();
        let Some(token) = snapshot.tokens.get(&mint.0) else {
            continue;
        };
        let observed_at = record
            .no_lookahead_timestamp
            .unwrap_or(record.record.meta.received_at_wall_time);
        let features = feature_engine.compute_snapshot(token, &snapshot, observed_at);
        let risk = risk_engine.evaluate(token, &features, observed_at);
        let decision = decision_engine.evaluate(
            token,
            &features,
            &risk,
            paper.position_context(&mint.0).as_ref(),
            &loaded.hash,
            &loaded.config.environment.strategy_version,
            observed_at,
        );
        let _ = paper.handle_decision(&decision, token, observed_at, false);
    }

    let store = storage_engine(loaded)?;
    for token in artifacts.snapshot.tokens.values() {
        let summary = state::CompactTokenSummary {
            mint: token.mint.0.clone(),
            lifecycle: token.lifecycle,
            latest_price: token.latest_price,
            holder_count: token.holder_state.nonzero_holder_count,
            top1_holder_pct: token.holder_state.top_holder_pct(1),
            creator_sold_pct: token.developer_state.creator_sell_percentage,
            canonical_trade_count: token.trade_stats.buy_count + token.trade_stats.sell_count,
            reason_codes: vec![],
        };
        let record = StoredRecord::new(
            DatasetKind::TokenSummary,
            loaded.hash.clone(),
            artifacts.idl_hash.clone(),
            Some(loaded.config.environment.strategy_version.clone()),
            "state",
            "snapshot",
            token.launch_time,
            summary,
        )
        .with_run_id(artifacts.run_id.clone());
        let _ = store.write_token_summary(&record)?;
    }
    Ok(paper)
}

fn combined_idl_hash(loaded: &LoadedConfig) -> Result<String> {
    let mut combined = String::new();
    for path in &loaded.config.pump.idl_paths {
        let idl = LoadedIdl::load(loaded.resolve_path(path))?;
        combined.push_str(&idl.hash);
    }
    if combined.is_empty() {
        return Ok("no-idl".to_owned());
    }
    Ok(StorageEngine::config_fingerprint(&loaded.hash, &combined))
}

fn validate_pumpfun_idl_command(loaded: &LoadedConfig, output_dir: &str) -> Result<()> {
    let out = Path::new(output_dir);
    fs::create_dir_all(out)?;
    let idl_path = resolve_user_path(loaded, "vendor/pumpfun/idl/pump.json");
    let idl = LoadedIdl::load(&idl_path)
        .with_context(|| format!("load official Pump.fun IDL {}", idl_path.display()))?;
    let expected_program = "6EF8rrecthR5Dkzon8Nwu78hRvfCKubJ14M5uBEwF6P";
    if idl.program_address() != Some(expected_program) {
        bail!(
            "official Pump.fun IDL program address mismatch: expected {expected_program}, got {:?}",
            idl.program_address()
        );
    }

    let instruction_names = idl.instruction_names();
    let required_instructions = [
        "create",
        "buy",
        "sell",
        "create_v2",
        "buy_v2",
        "sell_v2",
        "buy_exact_quote_in_v2",
        "buy_exact_sol_in",
    ];
    let instruction_rows = required_instructions
        .iter()
        .map(|name| {
            let present = instruction_names.iter().any(|candidate| candidate == name);
            json!({
                "instruction": name,
                "present": present,
                "discriminator": idl.instruction_discriminator_hex(name),
                "accounts": idl.instruction_account_names(name).unwrap_or_default(),
            })
        })
        .collect::<Vec<_>>();
    let missing_instructions = instruction_rows
        .iter()
        .filter(|row| !row["present"].as_bool().unwrap_or(false))
        .map(|row| row["instruction"].as_str().unwrap_or_default().to_owned())
        .collect::<Vec<_>>();
    if !missing_instructions.is_empty() {
        bail!(
            "official Pump.fun IDL missing required instructions: {}",
            missing_instructions.join(", ")
        );
    }

    let bonding_fields = idl
        .account_field_names("BondingCurve")
        .ok_or_else(|| anyhow!("official Pump.fun IDL missing BondingCurve account layout"))?;
    let required_bonding_fields = [
        "virtual_token_reserves",
        "real_token_reserves",
        "token_total_supply",
        "complete",
        "creator",
        "quote_mint",
    ];
    let alias_requirements = [
        (
            "virtual_quote_or_sol_reserves",
            &["virtual_quote_reserves", "virtual_sol_reserves"][..],
        ),
        (
            "real_quote_or_sol_reserves",
            &["real_quote_reserves", "real_sol_reserves"][..],
        ),
    ];
    let mut field_rows = Vec::new();
    for field in required_bonding_fields {
        field_rows.push(json!({
            "field": field,
            "present": bonding_fields.iter().any(|candidate| candidate == field),
            "aliases": [field],
        }));
    }
    for (name, aliases) in alias_requirements {
        field_rows.push(json!({
            "field": name,
            "present": aliases.iter().any(|alias| bonding_fields.iter().any(|candidate| candidate == alias)),
            "aliases": aliases,
        }));
    }
    let missing_fields = field_rows
        .iter()
        .filter(|row| !row["present"].as_bool().unwrap_or(false))
        .map(|row| row["field"].as_str().unwrap_or_default().to_owned())
        .collect::<Vec<_>>();
    if !missing_fields.is_empty() {
        bail!(
            "official Pump.fun IDL missing BondingCurve fields: {}",
            missing_fields.join(", ")
        );
    }

    let account_map_rows = [
        "create",
        "create_v2",
        "buy",
        "sell",
        "buy_v2",
        "sell_v2",
        "buy_exact_quote_in_v2",
        "buy_exact_sol_in",
    ]
    .iter()
    .map(|name| {
        let accounts = idl.instruction_account_names(name).unwrap_or_default();
        let indexed = accounts
            .iter()
            .enumerate()
            .map(|(index, account)| {
                json!({
                    "account_name": account,
                    "index": index,
                    "pda_derivable": matches!(account.as_str(), "bonding_curve" | "associated_bonding_curve" | "associated_base_bonding_curve" | "associated_quote_bonding_curve" | "creator_vault" | "associated_creator_vault"),
                })
            })
            .collect::<Vec<_>>();
        json!({
            "instruction_name": name,
            "discriminator": idl.instruction_discriminator_hex(name),
            "accounts": indexed,
            "legacy_associated_bonding_curve_index": accounts.iter().position(|account| account == "associated_bonding_curve"),
            "v2_associated_base_bonding_curve_index": accounts.iter().position(|account| account == "associated_base_bonding_curve"),
            "v2_associated_quote_bonding_curve_index": accounts.iter().position(|account| account == "associated_quote_bonding_curve"),
        })
    })
    .collect::<Vec<_>>();

    let payload = json!({
        "schema_version": "phase94.official_pumpfun_idl_validation.v1",
        "source_path": idl_path,
        "program_address": idl.program_address(),
        "expected_program_address": expected_program,
        "hash": idl.hash,
        "metadata": idl.document.metadata,
        "instructions": instruction_rows,
        "bonding_curve_fields": field_rows,
        "pda_seed_expectations": {
            "bonding_curve": "official_idl_account_map_or_idl_pda_when present",
            "associated_bonding_curve": "official IDL account, else ATA(owner=bonding_curve,mint,token_program)",
            "associated_base_bonding_curve": "official v2 base associated account",
            "associated_quote_bonding_curve": "official v2 quote associated account",
            "creator_vault": "official v2 account when present",
            "associated_creator_vault": "official v2 account when present"
        },
        "valid": true,
    });
    fs::write(
        out.join("idl_validation.json"),
        serde_json::to_vec_pretty(&payload)?,
    )?;
    write_report(
        out.join("idl_validation.md"),
        &format!(
            "# Pump.fun IDL validation\n\n- IDL: `{}`\n- Program: `{}`\n- SHA-256: `{}`\n- Instructions checked: `{}`\n- BondingCurve fields checked: `{}`\n- Result: `passed`\n",
            idl_path.display(),
            expected_program,
            idl.hash,
            required_instructions.join(", "),
            field_rows
                .iter()
                .map(|row| row["field"].as_str().unwrap_or_default())
                .collect::<Vec<_>>()
                .join(", ")
        ),
    )?;
    fs::write(
        out.join("instruction_account_maps.json"),
        serde_json::to_vec_pretty(&json!({
            "schema_version": "phase94.official_pumpfun_instruction_account_maps.v1",
            "source_idl_hash": idl.hash,
            "program_address": expected_program,
            "maps": account_map_rows,
        }))?,
    )?;
    write_report(
        out.join("instruction_account_maps.md"),
        &format!(
            "# Official Pump.fun instruction account maps\n\nGenerated from vendored IDL `{}`.\n\nSupported instructions: `{}`.\n\nLegacy `associated_bonding_curve` and v2 `associated_base_bonding_curve` / `associated_quote_bonding_curve` are now sourced from the official IDL account names before deterministic ATA derivation fallback.\n",
            idl_path.display(),
            required_instructions.join(", ")
        ),
    )?;
    println!(
        "official Pump.fun IDL validation passed: {} ({})",
        idl_path.display(),
        idl.hash
    );
    Ok(())
}

fn now_for_token(token: &state::TokenState) -> OffsetDateTime {
    token
        .trade_stats
        .price_history
        .back()
        .map(|(time, _)| *time)
        .or(token.launch_time)
        .unwrap_or(OffsetDateTime::UNIX_EPOCH)
}

fn resolve_user_path(loaded: &LoadedConfig, path: &str) -> PathBuf {
    let direct = Path::new(path);
    if direct.is_absolute() || direct.exists() {
        return direct.to_path_buf();
    }
    let config_relative = loaded.resolve_path(path);
    if config_relative.exists() {
        return config_relative;
    }
    direct.to_path_buf()
}

