    #[test]
    fn manifest_drift_prevents_completed_verified_status() {
        let mut manifest = test_manifest();
        manifest.manifest_consistency_checked = true;
        manifest.manifest_consistency_passed = false;
        manifest.manifest_drift_detected = true;
        manifest.manifest_drift_artifacts = vec!["segment_manifest.json".to_owned()];

        refresh_manifest_verification_state(&mut manifest);

        assert_eq!(
            manifest.r2_full_verification_status,
            "object_verified_manifest_drift"
        );
        assert_eq!(
            current_manifest_run_status(&manifest),
            "completed_object_verified_manifest_drift"
        );
        assert!(!manifest_verified(&manifest));
    }

    #[test]
    fn manifest_consistency_pass_allows_completed_verified_status() {
        let mut manifest = test_manifest();

        refresh_manifest_verification_state(&mut manifest);

        assert_eq!(manifest.r2_full_verification_status, "verified");
        assert_eq!(current_manifest_run_status(&manifest), "completed_verified");
        assert!(manifest_verified(&manifest));
    }

